// в”Җв”Җ Transporter global + helper anti-spam в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Injeta headers que reduzem chance de cair em spam em todos os envios.
const _globalTransporter = nodemailer.createTransport(SMTP_CONFIG);
async function sendMailHelper(opts) {
    // Gera versГЈo texto puro automaticamente a partir do HTML se nГЈo fornecida
    // Isso reduz significativamente a chance de cair em spam
    let textPlain = opts.text;
    if (!textPlain && opts.html) {
        textPlain = opts.html
            .replace(/<br\s*\/?>/gi, '\n')
            .replace(/<\/p>/gi, '\n\n')
            .replace(/<\/div>/gi, '\n')
            .replace(/<\/h[1-6]>/gi, '\n\n')
            .replace(/<\/li>/gi, '\n')
            .replace(/<[^>]+>/g, '')
            .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ').replace(/&#10;/g, '\n')
            .replace(/[ \t]{2,}/g, ' ')
            .replace(/\n{3,}/g, '\n\n')
            .trim();
    }
    return _globalTransporter.sendMail({
        ...opts,
        from: opts.from || '"America Rental" <americasistema48@gmail.com>',
        replyTo: opts.replyTo || 'americasistema48@gmail.com',
        text: textPlain,
        headers: {
            'X-Mailer': 'America-Rental-ERP/1.0',
            'X-Priority': '3',
            'Precedence': 'bulk',
            'List-Unsubscribe': '<mailto:americasistema48@gmail.com?subject=Cancelar>',
            ...(opts.headers || {})
        }
    });
}

/**
 * UtilitГЎrio: envia e-mail para todos os usuГЎrios configurados para receber um tipo de notificaГ§ГЈo.
 * Usa mГәltiplas estratГ©gias de busca de e-mail para garantir entrega:
 *   1. email_corporativo do colaborador (JOIN por nome)
 *   2. email do colaborador (JOIN por nome)
 *   3. email_corporativo do colaborador (JOIN por username)
 *   4. email do colaborador (JOIN por username)
 *   5. email direto na tabela usuarios
 *   6. username (se parecer um e-mail)
 * @param {string} tipo - tipo da notificaГ§ГЈo (config_notificacoes.tipo)
 * @param {object} mailOpts - { subject, html, attachments? }
 */
async function sendEmailParaNotificados(tipo, mailOpts) {
    try {
        const logoPath = require('path').join(__dirname, '..', 'frontend', 'assets', 'logo-header.png');
        const attachments = mailOpts.attachments || [{ filename: 'logo-header.png', path: logoPath, cid: 'empresa-logo' }];

        db.all(`
            SELECT u.id as uid, u.nome as unome, u.username, u.email as uemail,
                   cn1.email_corporativo as ec_by_nome, cn1.email as ce_by_nome,
                   cn2.email_corporativo as ec_by_username, cn2.email as ce_by_username
            FROM config_notificacoes cn
            JOIN usuarios u ON u.id = cn.usuario_id
            LEFT JOIN colaboradores cn1 ON LOWER(TRIM(cn1.nome_completo)) = LOWER(TRIM(u.nome))
            LEFT JOIN colaboradores cn2 ON LOWER(TRIM(cn2.nome_completo)) = LOWER(TRIM(u.username))
            WHERE cn.tipo = ? AND u.ativo = 1
        `, [tipo], async (err, rows) => {
            if (err) {
                console.error(`[Notif Email] Erro na query tipo="${tipo}":`, err.message);
                return;
            }
            if (!rows || rows.length === 0) {
                console.log(`[Notif Email] Nenhum usuario configurado para tipo="${tipo}"`);
                return;
            }
            const emails = new Set();
            rows.forEach(r => {
                // EstratГ©gia 1: email_corporativo via JOIN por nome
                if (r.ec_by_nome && r.ec_by_nome.includes('@')) { emails.add(r.ec_by_nome.trim()); return; }
                // EstratГ©gia 2: email do colaborador via JOIN por nome
                if (r.ce_by_nome && r.ce_by_nome.includes('@')) { emails.add(r.ce_by_nome.trim()); return; }
                // EstratГ©gia 3: email_corporativo via JOIN por username
                if (r.ec_by_username && r.ec_by_username.includes('@')) { emails.add(r.ec_by_username.trim()); return; }
                // EstratГ©gia 4: email do colaborador via JOIN por username
                if (r.ce_by_username && r.ce_by_username.includes('@')) { emails.add(r.ce_by_username.trim()); return; }
                // EstratГ©gia 5: email direto na tabela usuarios
                if (r.uemail && r.uemail.includes('@')) { emails.add(r.uemail.trim()); return; }
                // EstratГ©gia 6: username parece um e-mail
                if (r.username && r.username.includes('@')) { emails.add(r.username.trim()); return; }
                console.warn(`[Notif Email] Nenhum e-mail encontrado para usuario_id=${r.uid} (username="${r.username}", nome="${r.unome}")`);
            });
            if (emails.size === 0) {
                console.warn(`[Notif Email] Nenhum e-mail resolvido para tipo="${tipo}". Verifique se os colaboradores tГӘm email_corporativo cadastrado.`);
                return;
            }
            try {
                await sendMailHelper({
                    to: [...emails].join(', '),
                    subject: mailOpts.subject,
                    html: mailOpts.html,
                    attachments
                });
                console.log(`[Notif Email] Tipo="${tipo}" enviado para: ${[...emails].join(', ')}`);
            } catch (mailErr) {
                console.error(`[Notif Email] Erro ao enviar email tipo="${tipo}":`, mailErr.message);
            }
        });
    } catch(e) {
        console.error('[sendEmailParaNotificados] Erro:', e.message);
    }
}

