// MIGRATION: Limpar duplicatas de geradores вҖ” executado em sequГӘncia garantida
db.serialize(() => {
db.run(`CREATE TABLE IF NOT EXISTS epi_selfies (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    colaborador_id INTEGER NOT NULL,
    selfie_base64 TEXT NOT NULL,
    registrado_por TEXT,
    timestamp TEXT,
    criado_em DATETIME DEFAULT CURRENT_TIMESTAMP
)`);
    // 1. Renomear ORDEM DE SERVIГҮO NR01 (maiГәsculo) para caixa mista
    db.run("UPDATE geradores SET nome = 'Ordem de Servi\u00e7o NR01' WHERE nome LIKE 'ORDEM%NR01' OR nome LIKE 'ORDEM%NR 01'", (err) => {
        if (err) console.error('Erro ao renomear NR01 maiГәsculo:', err);
        else console.log('MIGRATION: ORDEM NR01 maiГәsculo renomeado (se existia).');
    });
    // 2. Remover duplicatas de NR01 mantendo o mais antigo
    db.run("DELETE FROM geradores WHERE (nome LIKE '%NR01%' OR nome LIKE '%NR 01%') AND id NOT IN (SELECT MIN(id) FROM geradores WHERE nome LIKE '%NR01%' OR nome LIKE '%NR 01%')", (err) => {
        if (err) console.error('Erro ao deduplicar NR01:', err);
        else console.log('MIGRATION: Duplicatas NR01 removidas (se existiam).');
    });
    // 3. Remover AUTORIZAГҮГғO DE DESCONTO EM FOLHA DE PAGAMENTO (maiГәsculo extra)
    //    MantГ©m apenas o de ID menor (AutorizaГ§ГЈo de Desconto em Folha, criado antes)
    db.run("DELETE FROM geradores WHERE nome LIKE 'AUTORI%DESCONTO%PAGAMENTO'", (err) => {
        if (err) console.error('Erro ao remover AUTORIZACAO DESCONTO PAGAMENTO maiГәsculo:', err);
        else console.log('MIGRATION: AUTORIZACAO DESCONTO PAGAMENTO maiГәsculo removido (se existia).');
    });
    // 4. Remover qualquer outro gerador em CAIXA ALTA cujo nome = UPPER(nome) вҖ” exceto os jГЎ tratados
    //    Detecta nomes 100% maiГәsculos contendo mais de 3 palavras
    db.run("DELETE FROM geradores WHERE nome = UPPER(nome) AND LENGTH(nome) > 10 AND nome NOT LIKE 'Ordem%'", (err) => {
        if (err) console.error('Err ao remover geradores all-caps extra:', err);
        else console.log('MIGRATION: Geradores all-caps extras removidos.');
    });
});

