const allowedOrigins = [
  'http://localhost:3000',
  'http://localhost:3001',
  'http://127.0.0.1:3000',
  'http://127.0.0.1:3001',
  'http://127.0.0.1:5500', // VSCode Live Server
  'https://sistema-america.onrender.com'
];

app.use(cors({
  origin: function (origin, callback) {
    if (!origin) return callback(null, true);
    
    // Permite domГӯnios locais, o domГӯnio oficial, domГӯnios do Render e o BASE_URL configurado
    if (
        allowedOrigins.includes(origin) || 
        origin.endsWith('.onrender.com') ||
        (process.env.BASE_URL && origin.startsWith(process.env.BASE_URL))
    ) {
      return callback(null, true);
    }
    
    return callback(new Error('Acesso bloqueado por CORS (SeguranГ§a)'), false);
  }
}));
