// MIGRATION: Limpar equipes antigas (Equipe 07h, etc) para forГ§ar as novas
db.get("SELECT COUNT(*) as c FROM equipes WHERE nome = 'Equipe 07h' OR nome = 'Equipe 09h'", (err, row) => {
    if (!err && row && row.c > 0) {
        db.run("DELETE FROM equipes_membros");
        db.run("DELETE FROM equipes", () => {
            console.log('[MIGRATION] Equipes antigas limpas com sucesso. Frontend irГЎ recriar as novas.');
        });
    } else {
        // Se nГЈo tem antigas, remove duplicadas geradas por concorrГӘncia
        db.run(`
            DELETE FROM equipes_membros
            WHERE equipe_id NOT IN (
                SELECT MIN(id) FROM equipes GROUP BY nome
            )
        `);
        db.run(`
            DELETE FROM equipes
            WHERE id NOT IN (
                SELECT MIN(id) FROM equipes GROUP BY nome
            )
        `, () => {
            console.log('[MIGRATION] Equipes duplicadas removidas (se existiam).');
            db.get("SELECT COUNT(*) as c FROM equipes WHERE nome = 'Ajudantes noturnos 12x36'", (err, row) => {
                if (!err && row && row.c === 0) {
                    db.run("INSERT INTO equipes (nome, descricao, cor, ordem) VALUES ('Ajudantes noturnos 12x36', '', '#14b8a6', 8)");
                }
            });
        });
    }
});

// в”Җв”Җ GET /api/equipes в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.get('/api/equipes', authenticateToken, (req, res) => {
    db.all(`SELECT e.*,
        (SELECT COUNT(*) FROM equipes_membros em WHERE em.equipe_id = e.id) as total_membros
        FROM equipes e WHERE e.ativa = 1 ORDER BY e.ordem ASC, e.id ASC`, [], (err, equipes) => {
        if (err) return res.status(500).json({ error: err.message });

        // Para cada equipe, buscar membros com dados do colaborador
        const promises = equipes.map(eq => new Promise((resolve) => {
            db.all(`SELECT em.*, c.nome_completo, c.cargo, c.foto_base64, c.foto_path, c.status as colab_status, c.cnh_categoria, c.ferias_programadas_inicio, c.ferias_programadas_fim, c.tipo_contrato, c.data_admissao, c.escala_tipo, c.escala_folgas, c.escala_ciclo_inicio, c.horario_entrada, c.horario_saida, c.destaque_equipe
                FROM equipes_membros em
                JOIN colaboradores c ON c.id = em.colaborador_id
                WHERE em.equipe_id = ? AND LOWER(c.status) NOT LIKE '%desligado%' AND LOWER(c.status) NOT LIKE '%iniciado%'
                ORDER BY em.funcao ASC, em.ordem ASC`, [eq.id], (err2, membros) => {
                eq.membros = membros || [];
                resolve(eq);
            });
        }));

        Promise.all(promises).then(result => res.json(result));
    });
});

