const multerUploadMemoria = require('multer')({ storage: require('multer').memoryStorage(), limits: { fieldSize: 100 * 1024 * 1024 } });

app.post('/api/extrair-bo', authenticateToken, multerUploadMemoria.single('arquivo'), async (req, res) => {
    try {
        if (!req.file) throw new Error('BO nao enviado.');
        const { PDFParse } = require('pdf-parse');
        const parser = new PDFParse({ verbosity: 0, data: req.file.buffer });
        const pdfData = await parser.getText();
        const text = pdfData.text || '';
        // Eliminar espacos duplicados para ajudar a regex
        const cleanText = text.replace(/[\r\n]+/g, ' ').replace(/\s+/g, ' ');

        // Boletim No: "FR6269-1/2026" ou "FR 6269-1/2026"
        let boletim = '';
        const matBO = cleanText.match(/([A-Z]{2}\s*\d+[-]\d+\/\d{4})/i)
            || cleanText.match(/Boletim[^\d]*(\d+[-]\d+\/\d{4})/i);
        if (matBO) boletim = matBO[1].replace(/\s/g, '').toUpperCase();

        // Ocorrencia: "13/04/2026 as 13:30" ou "OcorrГӘncia: ComunicaГ§ГЈo: 11/05/2026 Г s 11:30"
        let dataHoraStr = '';
        const matOc = cleanText.match(/Ocorr[eГӘ]ncia.*?(\d{2}\/\d{2}\/\d{4})\s+[aГ ]s?\s+(\d{2}:\d{2})/i)
            || cleanText.match(/Data.*?Ocorr.*?:?\s*(\d{2}\/\d{2}\/\d{4}).*?(\d{2}:\d{2})/i)
            || cleanText.match(/(\d{2}\/\d{2}\/\d{4})\s*.*?(\d{2}:\d{2})/i); // aggressive fallback
        if (matOc) dataHoraStr = matOc[1] + ' Г s ' + matOc[2];

        // Natureza
        let natureza = '';
        // Captura o que vem logo apГіs Naturezas da OcorrГӘncia... atГ© encontrar Dados da OcorrГӘncia ou Crime Consumado
        const matN = cleanText.match(/Naturezas? da Ocorr[eГӘ]ncia\s*(.*?)(?:Dados da|Crime|\d+\s*-)/i);
        if (matN && matN[1].trim().length > 3) {
            natureza = matN[1].trim();
        } else {
            const matN2 = cleanText.match(/(Crime Consumado.*?)(?:Dados da Ocorr[eГӘ]ncia)/i);
            if (matN2) natureza = matN2[1].trim();
        }

        // Marca/Modelo: "Marca/Modelo: IVECO/DAILY 35CS"
        let marcaModelo = '';
        const matMM = cleanText.match(/Marca\/Modelo[^\w]*([A-Z0-9\/\-\s]{3,30}?)(?:Ano\s|Cor\s|Chassi|Placa)/i);
        if (matMM) marcaModelo = matMM[1].trim();

        // Placa: "TLR0H81"
        let placa = '';
        const matPl = cleanText.match(/\b([A-Z]{3}[-\s]*[0-9][A-Z0-9]{3,4})\b/i)
            || cleanText.match(/Placa[^\w]*([A-Z]{3}[-\s]*\d{4,5})/i);
        if (matPl) {
            placa = matPl[1].replace(/[-\s]/g, '').toUpperCase();
            if (placa.length > 7) placa = placa.substring(0, 7); // ForГ§a 7 caracteres
        }

        console.log('[BO] boletim=' + boletim + ' | data=' + dataHoraStr + ' | natureza=' + natureza + ' | placa=' + placa + ' | modelo=' + marcaModelo);
        console.log('[BO-TEXT primeiros 300 chars]', cleanText.substring(0, 300));
        // _debug_text ainda Г© retornado para log no console do frontend (nГЈo mais em alert)
        res.json({ sucesso: true, boletim, data_hora: dataHoraStr, natureza, placa, marca_modelo: marcaModelo, _debug_text: text.substring(0, 2000) });
    } catch (e) {
        console.error('[EXTRAIR-BO] Erro:', e.message);
        res.status(500).json({ error: e.message });
    }
});



app.delete('/api/colaboradores/:id/sinistros/:sinistroId', authenticateToken, (req, res) => {
    const { id, sinistroId } = req.params;

    // Nao deixamos excluir se ja estiver assinado, por seguranca da assinatura digital, a menos que a senha de exclusao seja fornecida
    const senha = req.headers['x-delete-password'];
    db.get('SELECT status FROM sinistros WHERE id = ? AND colaborador_id = ?', [sinistroId, id], (err, row) => {
        if (err || !row) return res.status(404).json({ error: 'Sinistro nao encontrado' });
        
        if ((row.status === 'assinado' || row.status === 'assinado_testemunhas') && senha !== 'EXL2499!') {
            return res.status(403).json({ error: 'Nao eh possivel excluir um sinistro ja assinado sem a senha de exclusao correta.' });
        }

        db.run('DELETE FROM sinistros WHERE id = ? AND colaborador_id = ?', [sinistroId, id], function (err2) {
            if (err2) return res.status(500).json({ error: err2.message });
            res.json({ sucesso: true });
        });
    });
});

app.post('/api/colaboradores/:id/sinistros', authenticateToken, multerUploadMemoria.single('arquivo'), async (req, res) => {
    try {
        const { id } = req.params;
        const body = req.body;

        const colab = await new Promise((resolve, reject) => {
            db.get('SELECT * FROM colaboradores WHERE id = ?', [id], (err, row) => err ? reject(err) : resolve(row));
        });
        if (!colab) return res.status(404).json({ error: 'Colaborador nao encontrado.' });

        const nomeFormatado = (colab.nome_completo || colab.nome || 'COLAB')
            .toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
            .replace(/\s+/g, '_').replace(/[^A-Z0-9_]/g, '');

        let dataFormatada = (body.data_hora || '').split(' ')[0].replace(/\D/g, '');
        if (!dataFormatada) dataFormatada = String(new Date().getDate()).padStart(2, '0') + String(new Date().getMonth() + 1).padStart(2, '0') + new Date().getFullYear();

        // Pasta padrao C:\...\THAIS_RICCI\SINISTROS\Datadoocorrido\
        const pastaDataStr = (body.data_hora || '').split(' ')[0].replace(/\//g, '-');
        const pastaRoot = process.env.ONEDRIVE_BASE_PATH || 'RH/1.Colaboradores/Sistema';
        let targetDir = pastaRoot + '/' + nomeFormatado + '/SINISTROS/' + (pastaDataStr || dataFormatada);

        // Garantir unique numero se ja existir a mesma data - fazemos isso procurando o count
        const qtdNoDia = await new Promise(r => db.get("SELECT count(*) as c FROM sinistros WHERE colaborador_id=? AND data_hora LIKE ?", [id, (body.data_hora || '').split(' ')[0] + '%'], (e, row) => r(row ? row.c : 0)));
        if (qtdNoDia > 0) {
            targetDir += '_' + (qtdNoDia + 1);
        }

        const stmt = `INSERT INTO sinistros (colaborador_id, numero_boletim, data_hora, natureza, placa, veiculo,
            desconto, parcelas, valor_parcela, valor_total, tipo_sinistro, boletim_path, processo_iniciado, usuario_abertura) 
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)`;

        // Nome padrГЈo do doc: Sinistro_Datadoocorrido_Nome_do_Colaborador.pdf
        const pnome = 'BO_Sinistro_' + (pastaDataStr || dataFormatada).replace(/-/g, '') + '_' + nomeFormatado + '.pdf';
        const docOnedrivePath = targetDir + '/' + pnome;
        const usuarioAbertura = req.user ? (req.user.nome || req.user.username) : 'Sistema';

        db.run(stmt, [id, body.numero_boletim, body.data_hora, body.natureza, body.placa, body.veiculo,
            body.desconto, body.parcelas || null, body.valor_parcela, body.valor_total || null, body.tipo_sinistro, docOnedrivePath, 0, usuarioAbertura],
            async function (err) {
                if (err) return res.status(500).json({ error: err.message });
                const sinId = this.lastID;

                // Sync OneDrive 
                if (req.file && typeof onedrive !== 'undefined') {
                    try {
                        try {
                            const { censorBOPdfBuffer } = require('./censorPDF.js');
                            const censored = await censorBOPdfBuffer(req.file.buffer);
                            if (censored) req.file.buffer = Buffer.from(censored);
                        } catch (e) {
                            console.error('[CENSOR] Falha ao censurar BO em memГіria:', e.message);
                        }

                        await onedrive.ensurePath(pastaRoot + '/' + nomeFormatado);
                        await onedrive.ensurePath(pastaRoot + '/' + nomeFormatado + '/SINISTROS');
                        const finalDir = targetDir.substring(targetDir.lastIndexOf('/SINISTROS/') + 11);
                        await onedrive.ensurePath(pastaRoot + '/' + nomeFormatado + '/SINISTROS/' + finalDir);

                        await onedrive.uploadToOneDrive(targetDir, pnome, req.file.buffer);

                        // Upload de orГ§amentos se houver
                        if (body.orcamentos_base64) {
                            const orcs = JSON.parse(body.orcamentos_base64);
                            let paths = [];
                            for (let i = 0; i < orcs.length; i++) {
                                // Detectar extensao real a partir do data URL (image/jpeg, image/png, etc.)
                                const dataUrl = orcs[i];
                                const mimeMatch = dataUrl.match(/^data:([^;]+);/);
                                const mime = mimeMatch ? mimeMatch[1] : 'image/jpeg';
                                const extMap = { 'image/jpeg': 'jpg', 'image/jpg': 'jpg', 'image/png': 'png', 'image/webp': 'webp', 'application/pdf': 'pdf' };
                                const ext = extMap[mime] || 'jpg';
                                const orcBuf = Buffer.from(dataUrl.split(',')[1], 'base64');
                                const orcNome = 'Orcamento_' + (i + 1) + '.' + ext;
                                await onedrive.uploadToOneDrive(targetDir, orcNome, orcBuf);
                                paths.push(targetDir + '/' + orcNome);
                            }
                            db.run('UPDATE sinistros SET orcamentos_paths = ? WHERE id = ?', [JSON.stringify(paths), sinId]);
                        }
                    } catch (e) { console.error('Erro OneDrive:', e); }
                }

                // Notificar usuarios configurados e enviar e-mail
                db.all("SELECT usuario_id FROM config_notificacoes WHERE tipo = 'novo_sinistro'", [], (errC, rowsC) => {
                    if (!errC && rowsC && rowsC.length > 0) {
                        const msg = `Novo sinistro registrado para ${colab.nome_completo || 'Colaborador'}`;
                        const dadosStr = JSON.stringify({ sinistro_id: sinId, colaborador_id: id });
                        
                        const idsArr = rowsC.map(c => c.usuario_id);
                        rowsC.forEach(c => {
                            db.run("INSERT INTO notificacoes_usuarios (usuario_id, tipo, mensagem, dados) VALUES (?, ?, ?, ?)", [c.usuario_id, 'novo_sinistro', msg, dadosStr]);
                        });

                        const placeholders = idsArr.map(() => '?').join(',');
                        db.all(`SELECT id, username, nome, email as u_email FROM usuarios WHERE id IN (${placeholders})`, idsArr, async (errE, userRows) => {
                            if (!errE && userRows && userRows.length > 0) {
                                db.all(`SELECT nome_completo, cpf, email_corporativo, email FROM colaboradores WHERE email_corporativo IS NOT NULL OR email IS NOT NULL`, [], async (errCol, allColabs) => {
                                    const norm = (s) => s ? s.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().trim() : '';
                                    const emails = new Set();
                                    const colabsArr = allColabs || [];

                                    for (const u of userRows) {
                                        const uNome = norm(u.nome);
                                        const uUser = norm(u.username);
                                        
                                        let c = colabsArr.find(col => norm(col.nome_completo) === uNome || norm(col.cpf) === uUser);
                                        if (!c) {
                                            c = colabsArr.find(col => {
                                                const cNome = norm(col.nome_completo);
                                                return cNome && uNome && (cNome.includes(uNome) || uNome.includes(cNome));
                                            });
                                        }

                                        if (c && c.email_corporativo) emails.add(c.email_corporativo.trim());
                                        else if (c && c.email) emails.add(c.email.trim());
                                        else if (u.u_email) emails.add(u.u_email.trim());
                                    }

                                    const emailsArr = [...emails].filter(e => e !== '');

                                    if (emailsArr.length > 0) {
                                        const logoPath = require('path').join(__dirname, '..', 'frontend', 'assets', 'logo-header.png');
                                        const html = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;border:1px solid #eee;">
                                            <div style="background:linear-gradient(135deg,#1e293b,#334155);padding:20px;text-align:center;">
                                                <img src="cid:logo-sinistro" style="max-height:60px;" alt="AmГ©rica Rental">
                                            </div>
                                            <div style="padding:24px;">
                                                <h2 style="color:#059669;margin-top:0;">вҡ пёҸ Novo Sinistro Registrado</h2>
                                                <p>OlГЎ!</p>
                                                <p>Um novo boletim de ocorrГӘncia de sinistro foi registrado para o colaborador <strong>${colab.nome_completo || 'Colaborador'}</strong>.</p>
                                                <div style="background:#f0fdf4;border-left:4px solid #059669;border-radius:8px;padding:16px;margin:16px 0;">
                                                    <p style="margin:4px 0;"><strong>Boletim:</strong> ${body.numero_boletim || 'N/A'}</p>
                                                    <p style="margin:4px 0;"><strong>Data da OcorrГӘncia:</strong> ${body.data_hora || 'N/A'}</p>
                                                    <p style="margin:4px 0;"><strong>VeГӯculo:</strong> ${body.veiculo || 'N/A'}</p>
                                                    <p style="margin:4px 0;"><strong>Placa:</strong> ${body.placa || 'N/A'}</p>
                                                </div>
                                                <p style="color:#64748b;font-size:0.9em;">Acesse o sistema no prontuГЎrio do colaborador para mais detalhes e visualizaГ§ГЈo dos anexos.</p>
                                                <p style="margin-top:24px;color:#94a3b8;font-size:0.85em;">Atenciosamente,<br>Sistema AmГ©rica Rental</p>
                                            </div>
                                        </div>`;
                                        
                                        for (const eAddr of emailsArr) {
                                            try {
                                                await sendMailHelper({
                                                    from: `"LogГӯstica AmГ©rica Rental" <${SMTP_CONFIG.auth.user}>`,
                                                    to: eAddr,
                                                    subject: `[Sinistro] Novo registro para ${colab.nome_completo || 'Colaborador'}`,
                                                    html,
                                                    attachments: [{ filename: 'logo.png', path: logoPath, cid: 'logo-sinistro' }]
                                                });
                                                console.log(`E-mail de novo sinistro enviado para ${eAddr}`);
                                            } catch(mailErr) {
                                                console.error('Erro ao enviar e-mail de novo sinistro:', mailErr.message);
                                            }
                                        }
                                    }
                                });
                            }
                        });
                    }
                });

                res.json({ sucesso: true, id: sinId, targetDir });
            });

    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// PATCH: Editar sinistro (somente se status = 'pendente' вҖ” sem assinaturas)
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.patch('/api/colaboradores/:id/sinistros/:sinistroId', authenticateToken, multerUploadMemoria.none(), async (req, res) => {
    try {
        const { id: colabId, sinistroId } = req.params;
        const body = req.body;

        // Buscar o sinistro atual
        const sinistro = await new Promise((resolve, reject) => {
            db.get('SELECT * FROM sinistros WHERE id = ? AND colaborador_id = ?', [sinistroId, colabId], (err, row) => {
                if (err) reject(err); else resolve(row);
            });
        });

        if (!sinistro) return res.status(404).json({ error: 'Sinistro nГЈo encontrado.' });
        if (sinistro.status !== 'pendente') {
            return res.status(403).json({ error: 'EdiГ§ГЈo nГЈo permitida: sinistro jГЎ possui assinaturas.' });
        }

        // Atualizar campos bГЎsicos
        await new Promise((resolve, reject) => {
            db.run(
                `UPDATE sinistros SET
                    numero_boletim = COALESCE(?, numero_boletim),
                    data_hora      = COALESCE(?, data_hora),
                    natureza       = COALESCE(?, natureza),
                    veiculo        = COALESCE(?, veiculo),
                    placa          = COALESCE(?, placa)
                WHERE id = ?`,
                [
                    body.numero_boletim || null,
                    body.data_hora      || null,
                    body.natureza       || null,
                    body.veiculo        || null,
                    body.placa          || null,
                    sinistroId
                ],
                err => { if (err) reject(err); else resolve(); }
            );
        });

        // Novos orГ§amentos (acrescentar Г  lista existente)
        if (body.orcamentos_base64) {
            try {
                const novosOrcs = JSON.parse(body.orcamentos_base64);
                const existentes = sinistro.orcamentos_paths ? JSON.parse(sinistro.orcamentos_paths) : [];
                const targetDir = sinistro.boletim_path
                    ? sinistro.boletim_path.substring(0, sinistro.boletim_path.lastIndexOf('/'))
                    : `Sinistros/Colaborador_${colabId}`;

                const caminhos = [...existentes];
                for (let i = 0; i < novosOrcs.length; i++) {
                    const dataUrl = novosOrcs[i];
                    const mimeMatch = dataUrl.match(/^data:([^;]+);/);
                    const mime = mimeMatch ? mimeMatch[1] : 'image/jpeg';
                    const extMap = { 'image/jpeg': 'jpg', 'image/jpg': 'jpg', 'image/png': 'png' };
                    const ext = extMap[mime] || 'jpg';
                    const orcBuf = Buffer.from(dataUrl.split(',')[1], 'base64');
                    const orcNome = 'Orcamento_' + (existentes.length + i + 1) + '.' + ext;
                    await onedrive.uploadToOneDrive(targetDir, orcNome, orcBuf);
                    caminhos.push(targetDir + '/' + orcNome);
                }
                await new Promise((resolve, reject) => {
                    db.run('UPDATE sinistros SET orcamentos_paths = ? WHERE id = ?', [JSON.stringify(caminhos), sinistroId], err => {
                        if (err) reject(err); else resolve();
                    });
                });
            } catch (e) { console.error('[PATCH sinistro] erro orГ§amentos:', e); }
        }

        res.json({ sucesso: true });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});



// Upload multer de media com limite maior
const multerMediaStorage = multer.diskStorage({
    destination: (req, file, cb) => {
        const tmpDir = require('os').tmpdir();
        cb(null, tmpDir);
    },
    filename: (req, file, cb) => {
        cb(null, 'r2_midia_' + Date.now() + '_' + file.originalname.replace(/[^a-zA-Z0-9.]/g, '_'));
    }
});
const uploadMediaFile = multer({ storage: multerMediaStorage, limits: { fileSize: 500 * 1024 * 1024 } }); // 500MB

app.post('/api/sinistros/:id/midia', authenticateToken, uploadMediaFile.single('file'), async (req, res) => {
    try {
        const sinId = req.params.id;
        if (!req.file) return res.status(400).json({ error: 'Nenhum arquivo enviado.' });
        if (!r2 || !r2.isReady()) return res.status(500).json({ error: 'R2 Storage nГЈo configurado.' });

        const sinistro = await new Promise((resolve, reject) => {
            db.get('SELECT * FROM sinistros WHERE id = ?', [sinId], (err, row) => err ? reject(err) : resolve(row));
        });
        if (!sinistro) return res.status(404).json({ error: 'Sinistro nГЈo encontrado.' });

        const fileExt = req.file.originalname.split('.').pop();
        const r2Key = `sinistros/${sinId}/${Date.now()}_${Math.random().toString(36).substring(7)}.${fileExt}`;
        const contentType = req.file.mimetype;

        const publicUrl = await r2.uploadToR2(r2Key, req.file.path, contentType);

        let midias = [];
        try {
            if (sinistro.midias_paths) midias = JSON.parse(sinistro.midias_paths);
        } catch (e) { }

        midias.push({
            url: publicUrl,
            nome: req.file.originalname,
            tipo: contentType,
            data: new Date().toISOString()
        });

        db.run('UPDATE sinistros SET midias_paths = ? WHERE id = ?', [JSON.stringify(midias), sinId], (err) => {
            require('fs').unlink(req.file.path, () => { });
            if (err) return res.status(500).json({ error: err.message });
            res.json({ sucesso: true, url: publicUrl });
        });
    } catch (e) {
        if (req.file && req.file.path) require('fs').unlink(req.file.path, () => { });
        res.status(500).json({ error: e.message });
    }
});

// DELETE: Remove uma mГӯdia especГӯfica do sinistro pelo Гӯndice (sГі se status=pendente)
app.delete('/api/sinistros/:id/midia/:idx', authenticateToken, async (req, res) => {
    try {
        const { id: sinId, idx } = req.params;
        const index = parseInt(idx);

        const sinistro = await new Promise((resolve, reject) => {
            db.get('SELECT * FROM sinistros WHERE id = ?', [sinId], (err, row) => err ? reject(err) : resolve(row));
        });
        if (!sinistro) return res.status(404).json({ error: 'Sinistro nГЈo encontrado.' });
        if (sinistro.status !== 'pendente') {
            return res.status(403).json({ error: 'RemoГ§ГЈo nГЈo permitida: sinistro jГЎ possui assinaturas.' });
        }

        let midias = [];
        try { midias = JSON.parse(sinistro.midias_paths || '[]'); } catch (e) { }

        if (index < 0 || index >= midias.length) {
            return res.status(400).json({ error: 'ГҚndice de mГӯdia invГЎlido.' });
        }

        // Remove do array
        midias.splice(index, 1);

        await new Promise((resolve, reject) => {
            db.run('UPDATE sinistros SET midias_paths = ? WHERE id = ?', [JSON.stringify(midias), sinId],
                err => err ? reject(err) : resolve());
        });

        res.json({ sucesso: true, total: midias.length });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});



app.post('/api/colaboradores/:id/sinistros/:sinistroId/gerar-documento', authenticateToken, async (req, res) => {
    try {
        const { id, sinistroId } = req.params;
        const colab = await new Promise((resolve) => db.get('SELECT * FROM colaboradores WHERE id = ?', [id], (e, r) => resolve(r)));
        const sin = await new Promise((resolve) => db.get('SELECT * FROM sinistros WHERE id = ?', [sinistroId], (e, r) => resolve(r)));
        if (!sin || !colab) throw new Error('NГЈo encontrado.');

        // Busca todos os geradores de Sinistro e acha o mais proximo ao tipo_sinistro
        const normalize = s => (s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9 ]/g, '').replace(/\s+/g, ' ').trim();
        const tipoNorm = normalize(sin.tipo_sinistro);
        const todosGeradores = await new Promise((resolve) => db.all("SELECT * FROM geradores WHERE nome LIKE '%Sinistro%' OR nome LIKE '%sinistro%'", [], (e, r) => resolve(r || [])));
        console.log('[Sinistro] tipo_sinistro:', JSON.stringify(sin.tipo_sinistro), '| geradores disponiveis:', todosGeradores.map(g => g.nome));
        let gerador = todosGeradores.find(g => normalize(g.nome).includes(tipoNorm))
            || todosGeradores.find(g => tipoNorm.split(' ').filter(w => w.length > 3).every(w => normalize(g.nome).includes(w)))
            || todosGeradores[0] // fallback: pega o primeiro gerador de sinistro disponГӯvel
            || null;
        console.log('[Sinistro] gerador escolhido:', gerador ? gerador.nome : 'NENHUM');

        let template = '';
        if (!gerador) {
            template = "<h2 style='text-align:center;'>TERMO DE RESPONSABILIDADE - SINISTRO</h2>"
                + "<p><strong>Colaborador:</strong> {NOME_COMPLETO}</p>"
                + "<p><strong>Tipo de Sinistro:</strong> " + sin.tipo_sinistro + "</p>"
                + "<p><strong>BO:</strong> " + sin.numero_boletim + " - " + sin.data_hora + "</p>"
                + "<p><strong>Placa/VeГӯculo:</strong> " + sin.placa + " / " + sin.veiculo + "</p>"
                + "<p><strong>CondiГ§Гөes de Desconto:</strong> " + sin.parcelas + "x de " + (sin.valor_parcela || '0,00') + "</p>"
                + "<br/><br/><br/>";
        } else {
            template = gerador.conteudo;
        }

        // ===== SUBSTITUICOES AVANCADAS SINISTRO =====
        let htmlFinal = template;
        const colabNome = (colab.nome_completo || colab.nome || '').toUpperCase();

        const admissao = colab.data_admissao ? new Date(colab.data_admissao + 'T12:00:00').toLocaleDateString('pt-BR') : '';
        const salario = colab.salario ? `R$ ${parseFloat(colab.salario).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` : '---';
        const tituloBox = gerador ? gerador.nome.toUpperCase() : 'TERMO DE RESPONSABILIDADE - SINISTRO';

        let needsLogo = !htmlFinal.includes('logo-header.png');
        let needsBox = !htmlFinal.includes('DADOS COLABORADOR:');

        if (needsLogo || needsBox) {
            let injectedHTML = '';

            // 1. Logo sem margin/padding lateral para colar nas bordas do papel
            if (needsLogo) {
                const logoUrl = req.protocol + '://' + req.get('host') + '/assets/logo-header.png';
                injectedHTML += `<div style="margin:0;padding:0;line-height:0;"><img src="${logoUrl}" style="width:100%;display:block;margin:0;padding:0;"></div>`;
            }

            // InГӯcio do container com padding para o resto do documento
            injectedHTML += `<div style="padding: 20px 60px 40px 60px;">`;

            // 2. Quadro de DADOS COLABORADOR
            if (needsBox) {
                injectedHTML += `
                <div style="border: 1px solid #000; padding: 0.4rem 0.75rem; margin-top: 0.5rem; line-height: 1.3; font-size: 0.75rem;">
                    <p style="margin-bottom: 0.2rem; font-size: 0.8rem;"><b>DADOS COLABORADOR:</b></p>
                    <div style="display: flex; gap: 2rem;">
                        <span>NOME: <b>${colabNome}</b></span>
                        <span>CPF: <b>${colab.cpf || ''}</b></span>
                    </div>
                    <p>ENDEREГҮO: ${colab.endereco || '---'}</p>
                    <p>CARGO: ${colab.cargo || '---'}</p>
                    <div style="display: flex; gap: 2rem;">
                        <span>CELULAR: ${colab.telefone || '---'}</span>
                        <span>E-MAIL: ${colab.email || '---'}</span>
                    </div>
                </div>
                `;
            }

            // 3. O template original (com conteГәdo do gerador) formatado
            injectedHTML += `
                <div style="margin-top: 0.6rem; text-align: justify; font-size: 0.82rem; line-height: 1.45;">
                    <style>
                        p { margin: 0.1rem 0; page-break-inside: avoid; }
                        li { margin: 0.08rem 0; page-break-inside: avoid; }
                        br { line-height: 0.3; }
                    </style>
                    ${htmlFinal}
                </div>
            `;

            // Fim do container com padding
            injectedHTML += `</div>`;

            htmlFinal = injectedHTML;
        }

        // SubstituiГ§Гөes via placeholders {{}} ou {} (gerador padrГЈo)
        htmlFinal = htmlFinal.replace(/\{NOME_COMPLETO\}|\{NOME_COLABORADOR\}|\{COLABORADOR\}|\{\{NOME_COMPLETO\}\}|\{\{COLABORADOR\}\}/gi, colabNome);
        htmlFinal = htmlFinal.replace(/\{CPF\}|\{\{CPF\}\}/gi, colab.cpf || '');
        htmlFinal = htmlFinal.replace(/\{RG\}|\{\{RG\}\}/gi, colab.rg || '');
        htmlFinal = htmlFinal.replace(/\{CARGO\}|\{FUNCAO\}|\{\{CARGO\}\}|\{\{FUNCAO\}\}/gi, colab.cargo || colab.funcao || '');
        htmlFinal = htmlFinal.replace(/\{SINISTRO_BO\}|\{BO_NUMERO\}|\{NUMERO_BO\}/gi, sin.numero_boletim || '');
        htmlFinal = htmlFinal.replace(/\{SINISTRO_DATA\}|\{DATA_BO\}|\{DATA_OCORRENCIA\}/gi, sin.data_hora || '');
        htmlFinal = htmlFinal.replace(/\{SINISTRO_NATUREZA\}|\{NATUREZA\}/gi, sin.natureza || '');
        htmlFinal = htmlFinal.replace(/\{SINISTRO_PLACA\}|\{PLACA\}/gi, sin.placa || '');
        htmlFinal = htmlFinal.replace(/\{SINISTRO_VEICULO\}|\{VEICULO\}|\{MARCA_MODELO\}/gi, sin.veiculo || '');
        const isIsento = (sin.valor_total === '0,00' || sin.valor_total === '0' || sin.valor_total === 0);
        const condicoesTexto = isIsento ? 'ISENTO DE COBRANГҮA' : `${sin.parcelas || 1}x de ${sin.valor_parcela || ''}`;
        
        htmlFinal = htmlFinal.replace(/\{SINISTRO_PARCELAS\}|\{QTDE_PARCELAS\}/gi, String(sin.parcelas || 1));
        htmlFinal = htmlFinal.replace(/\{SINISTRO_VALOR_PARCELA\}|\{VALOR_PARCELA\}/gi, sin.valor_parcela || '');
        htmlFinal = htmlFinal.replace(/\{VALOR_TOTAL\}|\{VALOR_DANO\}/gi, sin.valor_total || sin.valor_parcela || '');
        htmlFinal = htmlFinal.replace(/\{SINISTRO_TIPO\}|\{TIPO_SINISTRO\}/gi, sin.tipo_sinistro || '');
        htmlFinal = htmlFinal.replace(/\{SINISTRO_CONDICOES\}|\{DESCRICAO_DESCONTO\}/gi, condicoesTexto);
        // SubstituiГ§Гөes com chaves duplas (padrГЈo {{CAMPO}})
        const dataAtualFmt = new Date().toLocaleDateString('pt-BR');
        htmlFinal = htmlFinal.replace(/\{\{DATA_ATUAL\}\}/gi, dataAtualFmt);
        htmlFinal = htmlFinal.replace(/\{\{DATA_OCORRENCIA\}\}/gi, sin.data_hora || '');
        htmlFinal = htmlFinal.replace(/\{\{BO_NUMERO\}\}|\{\{NUMERO_BO\}\}/gi, sin.numero_boletim || '');
        htmlFinal = htmlFinal.replace(/\{\{SINISTRO_TIPO\}\}|\{\{TIPO_SINISTRO\}\}/gi, sin.tipo_sinistro || '');
        htmlFinal = htmlFinal.replace(/\{\{PLACA\}\}/gi, sin.placa || '');
        htmlFinal = htmlFinal.replace(/\{\{VEICULO\}\}|\{\{MARCA_MODELO\}\}/gi, sin.veiculo || '');
        htmlFinal = htmlFinal.replace(/\{\{VALOR_PARCELA\}\}/gi, sin.valor_parcela || '');
        htmlFinal = htmlFinal.replace(/\{\{QTDE_PARCELAS\}\}/gi, String(sin.parcelas || 1));

        // ===== SUBSTITUIГҮГғO INTELIGENTE DE CAMPOS BLANK NO HTML =====
        // Separa data e hora da string "DD/MM/YYYY Г s HH:MM"
        const dataHoraStr = sin.data_hora || '';
        const parteData = dataHoraStr.split(' ')[0] || '';   // DD/MM/YYYY
        const parteHora = dataHoraStr.includes('Г s') ? dataHoraStr.split('Г s')[1]?.trim() : (dataHoraStr.split(' ')[1] || '');

        // Remove "(se houver)" se existir
        htmlFinal = htmlFinal.replace(/\s*\(se\s+houver\)/gi, '');

        // 1. Data e hora da ocorrГӘncia
        // Remove "//"
        htmlFinal = htmlFinal.replace(/(Data[^:]*ocorr[^:]*:[\s\S]{0,80}?)\/\//gi, '$1');
        // Primeiro blank -> Data
        let dataSubstCount = 0;
        htmlFinal = htmlFinal.replace(
            /(Data[^:]*ocorr[^:]*:[\s\S]{0,80}?)_{2,}/i,
            (match, p1) => {
                dataSubstCount++;
                return `${p1}<strong>${parteData}</strong>`;
            }
        );
        // Segundo blank -> Hora
        if (dataSubstCount > 0) {
            htmlFinal = htmlFinal.replace(
                /(Data[^:]*ocorr[^:]*:[\s\S]{0,80}?<strong>[\s\S]{0,40}?<\/strong>[\s\S]{0,80}?)_{2,}/i,
                `$1<strong>${parteHora}</strong>`
            );
        }

        // 2. Natureza da ocorrГӘncia (filtrando "Crime Consumado")
        let orgNatureza = sin.natureza || '';
        let naturezaFormatada = orgNatureza.replace(/Crime Consumado\s*-?\s*/gi, '').trim();
        htmlFinal = htmlFinal.replace(
            /(Natureza[^:]*:[\s\S]{0,80}?)_{3,}/gi,
            `$1<strong>${naturezaFormatada}</strong>`
        );

        // 3. Boletim de OcorrГӘncia
        htmlFinal = htmlFinal.replace(
            /(Boletim[^:]*:[\s\S]{0,80}?)_{3,}/gi,
            `$1<strong>${sin.numero_boletim || ''}</strong>`
        );

        // 4. Marca / Modelo
        htmlFinal = htmlFinal.replace(
            /(Marca[^:]*:[\s\S]{0,80}?)_{3,}/gi,
            `$1<strong>${sin.veiculo || ''}</strong>`
        );

        // 5. Placa
        htmlFinal = htmlFinal.replace(
            /(Placa[^:]*:[\s\S]{0,80}?)_{3,}/gi,
            `$1<strong>${sin.placa || ''}</strong>`
        );

        // 6. Valor
        const valorTotal = sin.valor_total
            || (sin.valor_parcela && sin.parcelas ? (parseFloat((sin.valor_parcela || '0').replace(',', '.')) * (sin.parcelas || 1)).toFixed(2).replace('.', ',') : sin.valor_parcela)
            || '';

        // PadrГЈo: Valor total do dano
        htmlFinal = htmlFinal.replace(
            /(Valor\s+total[^:]*:[\s\S]{0,80}?R\$[\s\S]{0,50}?)_{3,}/gi,
            `$1 <strong>${valorTotal}</strong>`
        );
        htmlFinal = htmlFinal.replace(
            /(Valor\s+total[^:]*:[\s\S]{0,80}?)_{3,}/gi,
            `$1 R$ <strong>${valorTotal}</strong>`
        );
        // PadrГЈo: Valor do dano
        htmlFinal = htmlFinal.replace(
            /(Valor\s+do\s+dano[^:]*:[\s\S]{0,80}?R\$[\s\S]{0,50}?)_{3,}/gi,
            `$1 <strong>${valorTotal}</strong>`
        );
        htmlFinal = htmlFinal.replace(
            /(Valor\s+do\s+dano[^:]*:[\s\S]{0,80}?)_{3,}/gi,
            `$1 R$ <strong>${valorTotal}</strong>`
        );

        // Substitui parcelamento (   ) 1x ... usando X
        const nParc = parseInt(sin.parcelas) || 1;
        htmlFinal = htmlFinal.replace(
            /(\([\s\xA0&nbsp;]*\)(?:[\s\xA0&nbsp;]|<[^>]+>)*1x)/gi,
            (nParc === 1 ? '(<strong>X</strong>) 1x' : '(   ) 1x')
        );
        htmlFinal = htmlFinal.replace(
            /(\([\s\xA0&nbsp;]*\)(?:[\s\xA0&nbsp;]|<[^>]+>)*2x)/gi,
            (nParc === 2 ? '(<strong>X</strong>) 2x' : '(   ) 2x')
        );
        htmlFinal = htmlFinal.replace(
            /(\([\s\xA0&nbsp;]*\)(?:[\s\xA0&nbsp;]|<[^>]+>)*3x)/gi,
            (nParc === 3 ? '(<strong>X</strong>) 3x' : '(   ) 3x')
        );

        // ===== AJUSTES PARA SINISTRO ISENTO DE COBRANГҮA =====
        if (isIsento) {
            // 1. Remove linhas que exibam "Valor total do dano: R$ 0,00"
            htmlFinal = htmlFinal.replace(
                /<(p|div|tr|td|li|span|strong)[^>]*>[\s\S]{0,150}?Valor\s+(?:total\s+)?(?:do\s+)?dano[\s\S]{0,150}?<\/\1>/gi,
                ''
            );
            htmlFinal = htmlFinal.replace(
                /Valor\s+(?:total\s+)?(?:do\s+)?dano[\s\S]{0,100}?(?:R\$)?[\s\S]{0,50}?0[,.]?00/gi,
                ''
            );

            // 2. Altera CLГҒUSULA PRIMEIRA вҖ“ DO OBJETO (texto 1.1)
            htmlFinal = htmlFinal.replace(
                /1\.1\.\s*O\s+presente\s+termo\s+tem\s+por\s+objeto\s+formalizar\s+a\s+autoriza[Г§c][ГЈa]o\s+de\s+desconto\s+em\s+folha[\s\S]{0,400}?danos\s+ao\s+ve[Гӯi]culo\s+da\s+pr[Гіo]pria\s+empresa\s+e\/ou\s+a\s+terceiros\./gi,
                '1.1. O presente termo tem por objeto formalizar a ci\u00eancia do colaborador sobre o sinistro aberto.'
            );

            // 3. Remove a CLГҒUSULA TERCEIRA atual inteira atГ© o inГӯcio da prГіxima clГЎusula (para limpar a de COBRANГҮA)
            htmlFinal = htmlFinal.replace(
                /CL[ГҒA]USULA\s+TERCEIRA\s*[вҖ“\-]\s*DO\s+VALOR\s+DO\s+DANO[\s\S]{0,800}?(?=CL[ГҒA]USULA\s+QUARTA|CL[ГҒA]USULA\s+4|<p[^>]*>\s*4\.1\.)/gi,
                ''
            );

            // 4. Substitui a CLГҒUSULA QUARTA inteira pelo novo bloco da ClГЎusula Terceira (Isento)
            htmlFinal = htmlFinal.replace(
                /CL[ГҒA]USULA\s+QUARTA\s*[вҖ“\-]\s*DA\s+AUTORIZA[ГҮC][ГғA]O\s+DE\s+DESCONTO[\s\S]{0,800}?(?=CL[ГҒA]USULA\s+QUINTA|CL[ГҒA]USULA\s+5|<\/p>[\s\S]{0,50}<p[^>]*>[\s\S]{0,10}CL[ГҒA]USULA)/gi,
                'CL\u00c1USULA TERCEIRA \u2013 DO VALOR DO DANO\n<br/>3.1. Colaborador fica <strong>ISENTO DE COBRAN\u00c7A</strong> para o dano relatado no BO.'
            );

            // Fallback: se nГЈo encontrou a clГЎusula quarta por tГӯtulo, procura pelo texto 4.1 e limpa tudo de desconto
            if (htmlFinal.includes('4.1.') && htmlFinal.includes('artigo 462')) {
                htmlFinal = htmlFinal.replace(
                    /4\.1\.\s*O\s+colaborador\s+autoriza[\s\S]{0,500}?artigo\s+462[\s\S]{0,100}?CLT\./gi,
                    'CL\u00c1USULA TERCEIRA \u2013 DO VALOR DO DANO<br/>3.1. Colaborador fica <strong>ISENTO DE COBRAN\u00c7A</strong> para o dano relatado no BO.'
                );
            }

            // 5. Renomear o tГӯtulo do termo (agora o usuГЎrio pediu apenas "TERMO DE CIГҠNCIA DE SINISTRO")
            htmlFinal = htmlFinal.replace(
                /TERMO\s+DE\s+AUTORIZA[ГҮC][ГғA]O\s+DE\s+DESCONTO\s+EM\s+FOLHA/gi,
                'TERMO DE CI\u00caNCIA DE SINISTRO'
            );
        } else {
            // ===== AJUSTES PARA SINISTRO COM COBRANГҮA =====

            // 1. Remove a clГЎusula 3.2 (fica acordado o desconto a tГӯtulo de ressarcimento)
            htmlFinal = htmlFinal.replace(
                /3\.2\.\s*Fica\s+acordado\s+entre\s+as\s+partes\s+o\s+desconto\s+a\s+t[Гӯi]tulo\s+de\s+ressarcimento\s+dos\s+preju[Гӯi]zos\s+decorrentes\s+do\s+sinistro\./gi,
                ''
            );

            // 2. Altera clГЎusula 4.1 вҖ” acrescenta "a tГӯtulo de ressarcimento dos prejuГӯzos decorrentes do sinistro"
            htmlFinal = htmlFinal.replace(
                /(4\.1\.\s*O\s+colaborador\s+autoriza[\s\S]{0,400}?artigo\s+462\s+da\s*\n?\s*CLT)\s*\./gi,
                '$1 a t\u00edtulo de ressarcimento dos preju\u00edzos decorrentes do sinistro.'
            );
            // Fallback sem quebra de linha antes do ponto
            if (!htmlFinal.match(/4\.1\.[\s\S]{0,500}ressarcimento\s+dos\s+preju[Гӯi]zos\s+decorrentes\s+do\s+sinistro/i)) {
                htmlFinal = htmlFinal.replace(
                    /(4\.1\.\s*O\s+colaborador\s+autoriza[\s\S]{0,400}?artigo\s+462\s+da\s*CLT)\./gi,
                    '$1 a t\u00edtulo de ressarcimento dos preju\u00edzos decorrentes do sinistro.'
                );
            }
        }



        // ===== LOGO =====
        // Injeta logo da AmГ©rica Rental no topo вҖ” usa Base64 para garantir que apareГ§a no PDF gerado server-side
        const _logoB64ForBanner = getLogoBase64DataUri();
        const _logoSrc = _logoB64ForBanner || `${process.env.PUBLIC_URL || ''}/assets/logo-header.png`;
        const bannerHtml = `<div style="margin:0;padding:0;line-height:0;"><img src="${_logoSrc}" style="width:100%;display:block;margin:0;padding:0;"></div>`;
        const contentPaddingWrapper = `<div style="padding: 30px;">`;
        if (!htmlFinal.includes('america-rental-logo') && !htmlFinal.includes('<img') && !htmlFinal.includes('logo-header')) {
            // Apply banner above the padding wrapper
            htmlFinal = bannerHtml + contentPaddingWrapper + htmlFinal + `</div>`;
        } else {
            // Document already handles logo or we don't want to enforce it loosely
            htmlFinal = contentPaddingWrapper + htmlFinal + `</div>`;
        }

        // O body deve ir formatado com HTML completo se nГЈo tiver <html>
        if (!htmlFinal.toLowerCase().includes('<html')) {
            htmlFinal = `<html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif;margin:0;padding:0;font-size:13px;line-height:1.6;}strong{font-weight:700;}</style></head><body>` + htmlFinal + `</body></html>`;
        }



        // ===== ANEXOS DO SINISTRO (ordem: BO вҶ’ Fotos вҶ’ VГӯdeos вҶ’ OrГ§amentos) =====
        try {
            let anxsHtml = '';
            let added = false;
            const onedrive = require('./utils/onedrive');

            // Helper: baixa arquivo do OneDrive e retorna Buffer
            const downloadToBuffer = async (filePath) => {
                const dlUrl = await onedrive.getDownloadUrl(filePath);
                if (!dlUrl) return null;
                const res = await fetch(dlUrl);
                if (!res.ok) return null;
                const buf = Buffer.from(await res.arrayBuffer());
                // Limite de 4MB por imagem para evitar OOM no servidor
                if (buf.length > 4 * 1024 * 1024) {
                    console.warn('[gerar-doc] Imagem muito grande ignorada:', filePath, Math.round(buf.length/1024) + 'KB');
                    return null;
                }
                return buf;
            };
            const downloadToB64 = async (filePath) => {
                const buf = await downloadToBuffer(filePath);
                return buf ? buf.toString('base64') : null;
            };

            // Helper: PDF вҶ’ renderizaГ§ГЈo client-side via PDF.js (cada pГЎgina ocupa sua prГіpria ГЎrea)
            const pdfBufToImgHtml = async (buf, label) => {
                const b64 = buf.toString('base64');
                return `<div class="sin-pdf-render" data-pdf-b64="${b64}" style="page-break-before:always;width:100%;margin-bottom:0;"><p style="font-size:0.85rem;font-weight:700;color:#333;margin:6px 0;text-align:center;">${label}</p><div class="sin-pdf-pages" style="width:100%;min-height:200px;"><p style="text-align:center;color:#888;padding:2rem;font-size:0.8rem;">&#x1F4C4; Carregando PDF...</p></div></div>`;
            };

            // 1) BOLETIM DE OCORRГҠNCIA вҖ” pГЎginas 2, 3, 4 (cada pГЎgina do PDF fica sequencial)
            if (sin.boletim_path) {
                try {
                    const buf = await downloadToBuffer(sin.boletim_path);
                    if (buf) {
                        anxsHtml += await pdfBufToImgHtml(buf, 'BOLETIM DE OCORRГҠNCIA');
                        added = true;
                    }
                } catch (e) { console.error('[Anexo BO]', e.message); }
            }

            // 2) FOTOS вҖ” cada foto em sua prГіpria pГЎgina (max 1 pГЎgina por foto)
            let mids = []; try { mids = JSON.parse(sin.midias_paths || '[]'); } catch (e) { }
            const videoLinks = []; // coleta vГӯdeos para exibir depois de todas as fotos

            for (let m of mids) {
                if (!m) continue;
                const url = typeof m === 'string' ? m : m.url;
                const tipo = typeof m === 'object' ? (m.tipo || '') : '';
                if (!url) continue;
                const ext = (url.split('.').pop() || '').toLowerCase().split('?')[0];
                const isImage = tipo.startsWith('image/') || ['jpg', 'jpeg', 'png', 'webp', 'gif'].includes(ext);
                const isVideo = tipo.startsWith('video/') || ['mp4', 'mov', 'avi', 'mkv', 'webm'].includes(ext);

                if (isImage) {
                    try {
                        const imgRes = await fetch(url);
                        if (imgRes.ok) {
                            const b64 = Buffer.from(await imgRes.arrayBuffer()).toString('base64');
                            const mime = tipo || 'image/jpeg';
                            // PГЎgina exclusiva para cada foto
                            anxsHtml += `<div style="page-break-before:always;width:100%;display:flex;flex-direction:column;align-items:center;justify-content:flex-start;padding:1.5rem 2rem;">
                                <p style="font-size:0.85rem;font-weight:700;color:#333;margin:0 0 10px;text-align:center;">&#x1F4F7; Foto do Dano${m.nome ? ' вҖ” ' + m.nome : ''}</p>
                                <img src="data:${mime};base64,${b64}" style="max-width:100%;max-height:90vh;object-fit:contain;border:1px solid #ddd;border-radius:4px;"/>
                            </div>`;
                            added = true;
                        }
                    } catch (e) { console.error('[Anexo FOTO]', e.message); }
                } else if (isVideo) {
                    // Acumula vГӯdeos para exibir todos em uma Гәnica pГЎgina depois
                    videoLinks.push({ url, nome: m.nome || '' });
                    added = true;
                }
            }

            // 3) LINKS DE VГҚDEOS вҖ” todos em uma Гәnica pГЎgina apГіs as fotos
            if (videoLinks.length > 0) {
                let videoHtml = `<div style="page-break-before:always;padding:2rem 2.5rem;">
                    <h3 style="font-size:1rem;font-weight:700;color:#1e293b;border-bottom:2px solid #334155;padding-bottom:0.6rem;margin-bottom:1.5rem;text-align:center;">&#x1F3A5; V&iacute;deos do Dano</h3>`;
                videoLinks.forEach((v, i) => {
                    videoHtml += `<div style="margin-bottom:1rem;padding:0.75rem 1rem;border:1px solid #e2e8f0;border-radius:8px;background:#f8fafc;">
                        <p style="margin:0 0 4px;font-weight:700;font-size:0.9rem;color:#0f172a;">V&iacute;deo ${i + 1}${v.nome ? ' &mdash; ' + v.nome : ''}</p>
                        <a href="${v.url}" style="word-break:break-all;font-size:0.8rem;color:#2563eb;">${v.url}</a>
                    </div>`;
                });
                videoHtml += `</div>`;
                anxsHtml += videoHtml;
            }

            // 4) ORГҮAMENTOS вҖ” apГіs os vГӯdeos (cada um em sua pГЎgina)
            let orcs = []; try { orcs = JSON.parse(sin.orcamentos_paths || '[]'); } catch (e) { }
            for (let p of orcs) {
                if (!p || typeof p !== 'string') continue;
                const ext = (p.split('.').pop() || '').toLowerCase().split('?')[0];
                if (['jpg', 'jpeg', 'png', 'webp', 'gif'].includes(ext)) {
                    try {
                        const b64 = await downloadToB64(p);
                        if (b64) {
                            const mime = ext === 'png' ? 'image/png' : (ext === 'webp' ? 'image/webp' : 'image/jpeg');
                            anxsHtml += `<div style="page-break-before:always;width:100%;display:flex;flex-direction:column;align-items:center;padding:1.5rem 2rem;">
                                <p style="font-size:0.85rem;font-weight:700;color:#333;margin-bottom:10px;text-align:center;">Or&ccedil;amento</p>
                                <img src="data:${mime};base64,${b64}" style="max-width:100%;max-height:90vh;object-fit:contain;border:1px solid #ccc;"/>
                            </div>`;
                            added = true;
                        }
                    } catch (e) { console.error('[Anexo ORC imagem]', e.message); }
                } else if (ext === 'pdf') {
                    try {
                        const buf = await downloadToBuffer(p);
                        if (buf) {
                            anxsHtml += await pdfBufToImgHtml(buf, 'Or&ccedil;amento');
                            added = true;
                        }
                    } catch (e) { console.error('[Anexo ORC PDF]', e.message); }
                }
            }

            // Injeta todos os anexos no final do HTML (sem wrapper/cabeГ§alho extra)
            if (added && anxsHtml) {
                if (htmlFinal.includes('</body>')) {
                    htmlFinal = htmlFinal.replace('</body>', anxsHtml + '</body>');
                } else {
                    htmlFinal += anxsHtml;
                }
            }
        } catch (e) { console.error('[Anexar imagens sinistro]', e.message); }


        // Salvar versГЈo LEVE no banco (sem base64 вҖ” evita OOM na requisiГ§ГЈo de assinatura)
        // A versГЈo completa com imagens Г© retornada ao cliente apenas para exibiГ§ГЈo
        function _stripBase64(html) {
            return html
                .replace(/src="data:[^"]{20,}"/g, 'src="[IMG]"')
                .replace(/data-pdf-b64="[A-Za-z0-9+/=]{20,}"/g, 'data-pdf-b64=""');
        }
        const htmlLeve = _stripBase64(htmlFinal);
        const htmlBytes = Buffer.byteLength(htmlLeve, 'utf8');
        console.log('[gerar-doc] HTML completo:', Math.round(Buffer.byteLength(htmlFinal,'utf8')/1024) + 'KB | Leve:', Math.round(htmlBytes/1024) + 'KB');
        db.run('UPDATE sinistros SET documento_html = ? WHERE id = ?', [htmlLeve, sin.id]);
        res.json({ sucesso: true, html: htmlFinal }); // retorna versГЈo completa ao cliente


    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Helper: gera PDF a partir de HTML e salva no OneDrive do colaborador
// Helper: lГӘ o logo do disco e retorna data URI base64 para embutir em PDF
function getLogoBase64DataUri() {
    try {
        const logoPath = path.join(__dirname, '..', 'frontend', 'assets', 'logo-header.png');
        if (fs.existsSync(logoPath)) {
            const logoBuffer = fs.readFileSync(logoPath);
            return `data:image/png;base64,${logoBuffer.toString('base64')}`;
        }
    } catch (e) {
        console.warn('[PDF] NГЈo foi possГӯvel carregar logo-header.png:', e.message);
    }
    return null;
}

async function salvarPDFSinistroNoOneDrive(colaboradorId, sinistroId, htmlDoc, nomeArquivo) {
    try {
        const htmlPdf = require('html-pdf-node');
        const colab = await new Promise((resolve, reject) =>
            db.get('SELECT * FROM colaboradores WHERE id = ?', [colaboradorId], (err, row) => err ? reject(err) : resolve(row))
        );
        if (!colab) throw new Error('Colaborador nГЈo encontrado');

        const sin = await new Promise((resolve, reject) =>
            db.get('SELECT * FROM sinistros WHERE id = ?', [sinistroId], (err, row) => err ? reject(err) : resolve(row))
        );
        if (!sin) throw new Error('Sinistro nГЈo encontrado');

        const nomeFormatado = (colab.nome_completo || colab.nome || 'COLAB')
            .toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
            .replace(/\s+/g, '_').replace(/[^A-Z0-9_]/g, '');

        const pastaDataStr = (sin.data_hora || '').split(' ')[0].replace(/\//g, '-');
        const pastaRoot = process.env.ONEDRIVE_BASE_PATH || 'RH/1.Colaboradores/Sistema';
        const targetDir = pastaRoot + '/' + nomeFormatado + '/SINISTROS/' + (pastaDataStr || 'SEM_DATA');

        // === Substituir URL do logo por Base64 para garantir que apareГ§a no PDF ===
        let htmlParaPdf = htmlDoc;
        const logoB64 = getLogoBase64DataUri();
        if (logoB64) {
            // Substitui qualquer src que contenha logo-header.png pelo base64
            htmlParaPdf = htmlParaPdf
                .replace(/src="[^"]*logo-header\.png[^"]*"/gi, `src="${logoB64}"`)
                .replace(/src='[^']*logo-header\.png[^']*'/gi, `src='${logoB64}'`);
        }

        const pdfBuffer = await htmlPdf.generatePdf(
            { content: htmlParaPdf },
            {
                format: 'A4', margin: { top: '1cm', bottom: '1cm', left: '1cm', right: '1cm' },
                printBackground: true, args: ['--no-sandbox', '--disable-setuid-sandbox']
            }
        );


        if (typeof onedrive !== 'undefined') {
            await onedrive.ensurePath(pastaRoot + '/' + nomeFormatado);
            await onedrive.ensurePath(pastaRoot + '/' + nomeFormatado + '/SINISTROS');
            await onedrive.ensurePath(targetDir);
            await onedrive.uploadToOneDrive(targetDir, nomeArquivo, pdfBuffer);
        }

        // Atualiza path do documento assinado no banco (campo separado do BO)
        const pdfPath = targetDir + '/' + nomeArquivo;
        db.run('UPDATE sinistros SET documento_path = ? WHERE id = ?', [pdfPath, sinistroId]);

        console.log('[Sinistro] PDF salvo em:', pdfPath);
        return pdfPath;
    } catch (e) {
        console.error('[Sinistro] Erro ao salvar PDF no OneDrive:', e.message);
        throw e;
    }
}

app.put('/api/colaboradores/:id/sinistros/:sinistroId/dados-financeiros', authenticateToken, async (req, res) => {
    try {
        const { sinistroId } = req.params;
        const { tipo_sinistro, valor_total, parcelas, valor_parcela } = req.body;
        await new Promise((resolve, reject) =>
            db.run(`UPDATE sinistros SET tipo_sinistro=?, valor_total=?, parcelas=?, valor_parcela=?, processo_iniciado=1 WHERE id=?`,
                [tipo_sinistro, valor_total, parcelas, valor_parcela, sinistroId],
                err => err ? reject(err) : resolve())
        );
        res.json({ sucesso: true });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.post('/api/colaboradores/:id/sinistros/:sinistroId/assinar-testemunhas', authenticateToken, async (req, res) => {
    try {
        const { id, sinistroId } = req.params;
        const { t1_nome, t1_base64, t2_nome, t2_base64, html_atualizado, finalizar_sem_condutor, gps_lat, gps_lon, dispositivo } = req.body;

        const novoStatus = finalizar_sem_condutor ? 'assinado_testemunhas' : undefined;

        await new Promise((resolve, reject) =>
            db.run(`UPDATE sinistros SET assinatura_testemunha1_nome=?, assinatura_testemunha1_base64=?, 
                    assinatura_testemunha2_nome=?, assinatura_testemunha2_base64=?, documento_html=?
                    ${novoStatus ? ", status='assinado_testemunhas'" : ''}
                    WHERE id=?`,
                [t1_nome, t1_base64, t2_nome, t2_base64, html_atualizado, sinistroId],
                err => err ? reject(err) : resolve())
        );

        // --- Auditoria JurГӯdica ---
        try {
            const ip = req.headers['x-forwarded-for'] || req.socket.remoteAddress || req.ip || '';
            const payloadHash = JSON.stringify({ t1_nome, t1_base64, t2_nome, t2_base64, finalizar_sem_condutor });
            const hashDocumento = require('crypto').createHash('sha256').update(payloadHash).digest('hex');

            db.run(
                `INSERT INTO assinatura_auditoria (tipo_documento, documento_id, colaborador_nome, ip, dispositivo, gps_lat, gps_lon, hash_pdf, detalhes) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                ['Sinistro Testemunhas', sinistroId, `Testemunhas de ID ${id}`, ip, dispositivo || req.headers['user-agent'], gps_lat || '', gps_lon || '', hashDocumento, 'Assinatura em Tela']
            );
        } catch (errAudit) { console.error('[AUDITORIA] Erro:', errAudit); }

        // Responde imediatamente вҖ” PDF gerado de forma assГӯncrona para nГЈo causar OOM
        res.json({ sucesso: true });

        // GeraГ§ГЈo de PDF em background (fire-and-forget)
        if (html_atualizado) {
            setImmediate(async () => {
                try {
                    const sin2 = await new Promise((resolve, reject) =>
                        db.get('SELECT * FROM sinistros WHERE id = ?', [sinistroId], (err, row) => err ? reject(err) : resolve(row))
                    );
                    const colab2 = await new Promise((resolve, reject) =>
                        db.get('SELECT * FROM colaboradores WHERE id = ?', [id], (err, row) => err ? reject(err) : resolve(row))
                    );
                    const nomeFormatado2 = (colab2?.nome_completo || colab2?.nome || 'COLAB')
                        .toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
                        .replace(/\s+/g, '_').replace(/[^A-Z0-9_]/g, '');
                    const dataStr2 = (sin2?.data_hora || '').split(' ')[0].replace(/\//g, '-').replace(/-/g, '') || String(Date.now());
                    const nomeArquivo2 = `Sinistro_${dataStr2}_${nomeFormatado2}.pdf`;
                    await salvarPDFSinistroNoOneDrive(id, sinistroId, html_atualizado, nomeArquivo2);
                } catch(pdfErr) { console.error('[PDF bg] assinar-testemunhas:', pdfErr.message); }
            });
        }
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.post('/api/colaboradores/:id/sinistros/:sinistroId/assinar-condutor', authenticateToken, async (req, res) => {
    try {
        const { id, sinistroId } = req.params;
        const { assinatura_base64, documento_html, tipo_sinistro, parcelas, valor_parcela, valor_total, gps_lat, gps_lon, dispositivo } = req.body;

        await new Promise((resolve, reject) =>
            db.run(`UPDATE sinistros SET assinatura_condutor_base64=?, documento_html=?, assinaturas_finalizadas=1, status='assinado', data_assinatura_condutor=CURRENT_TIMESTAMP,
                tipo_sinistro=COALESCE(?, tipo_sinistro), parcelas=COALESCE(?, parcelas), valor_parcela=COALESCE(?, valor_parcela), valor_total=COALESCE(?, valor_total)
                WHERE id=?`,
                [assinatura_base64, documento_html, tipo_sinistro || null, parcelas || null, valor_parcela || null, valor_total || null, sinistroId],
                err => err ? reject(err) : resolve())
        );

        // --- Auditoria JurГӯdica ---
        try {
            const ip = req.headers['x-forwarded-for'] || req.socket.remoteAddress || req.ip || '';
            const payloadHash = JSON.stringify({ assinatura_base64, tipo_sinistro, parcelas, valor_parcela, valor_total });
            const hashDocumento = require('crypto').createHash('sha256').update(payloadHash).digest('hex');

            db.run(
                `INSERT INTO assinatura_auditoria (tipo_documento, documento_id, colaborador_nome, ip, dispositivo, gps_lat, gps_lon, hash_pdf, detalhes) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                ['Sinistro Condutor', sinistroId, `ID ${id}`, ip, dispositivo || req.headers['user-agent'], gps_lat || '', gps_lon || '', hashDocumento, 'Assinatura Condutor']
            );
        } catch (errAudit) { console.error('[AUDITORIA] Erro:', errAudit); }

        // Responde imediatamente вҖ” PDF gerado de forma assГӯncrona para nГЈo causar OOM
        res.json({ sucesso: true });

        // GeraГ§ГЈo de PDF em background (fire-and-forget)
        if (documento_html) {
            setImmediate(async () => {
                try {
                    const sin3 = await new Promise((resolve, reject) =>
                        db.get('SELECT * FROM sinistros WHERE id = ?', [sinistroId], (err, row) => err ? reject(err) : resolve(row))
                    );
                    const colab3 = await new Promise((resolve, reject) =>
                        db.get('SELECT * FROM colaboradores WHERE id = ?', [id], (err, row) => err ? reject(err) : resolve(row))
                    );
                    const nomeFormatado3 = (colab3?.nome_completo || colab3?.nome || 'COLAB')
                        .toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
                        .replace(/\s+/g, '_').replace(/[^A-Z0-9_]/g, '');
                    const dataStr3 = (sin3?.data_hora || '').split(' ')[0].replace(/\//g, '-').replace(/-/g, '') || String(Date.now());
                    const nomeArquivo3 = `Sinistro_${dataStr3}_${nomeFormatado3}.pdf`;
                    await salvarPDFSinistroNoOneDrive(id, sinistroId, documento_html, nomeArquivo3);
                } catch(pdfErr) { console.error('[PDF bg] assinar-condutor:', pdfErr.message); }
            });
        }
    } catch (e) { res.status(500).json({ error: e.message }); }
});

