// POST /api/logistica/resumo-rota - Salva um novo resumo
app.post('/api/logistica/resumo-rota', authenticateToken, (req, res) => {
    const { id, nome, dados } = req.body;
    const dadosStr = typeof dados === 'string' ? dados : JSON.stringify(dados);

    if (id) {
        db.run("UPDATE logistica_resumo_rota SET dados = ? WHERE id = ?", [dadosStr, id], function (err) {
            if (err) return res.status(500).json({ error: err.message });
            res.json({ success: true, id: id });
        });
    } else {
        db.run("INSERT INTO logistica_resumo_rota (nome, dados, usuario_id, usuario_nome) VALUES (?, ?, ?, ?)",
            [nome, dadosStr, req.user.id, req.user.nome || req.user.username], function (err) {
                if (err) return res.status(500).json({ error: err.message });
                res.json({ success: true, id: this.lastID });
            });
    }
});

// DELETE /api/logistica/resumo-rota/:id - Exclui um resumo permanentemente
app.delete('/api/logistica/resumo-rota/:id', authenticateToken, (req, res) => {
    const resumoId = req.params.id;
    if (!resumoId) return res.status(400).json({ error: 'ID nГЈo fornecido' });
    
    db.run("DELETE FROM logistica_resumo_rota WHERE id = ?", [resumoId], function(err) {
        if (err) return res.status(500).json({ error: err.message, success: false });
        if (this.changes === 0) return res.status(404).json({ error: 'Resumo nГЈo encontrado', success: false });
        res.json({ success: true });
    });
});

