// POST /api/logistica/multas вҖ” cria nova multa
const multaUploadMiddleware = require('multer')({ storage: require('multer').memoryStorage(), limits: { fileSize: 20 * 1024 * 1024 } });
app.post('/api/logistica/multas', authenticateToken, multaUploadMiddleware.single('documento'), (req, res) => {
    const { data_infracao, hora_infracao, numero_ait, motivo, valor_multa, pontuacao, placa, local_infracao, data_limite, motorista_id, motorista_nome, status, parcelas } = req.body;

    let documento_base64 = null;
    let documento_nome = null;

    if (req.file) {
        try {
            documento_base64 = req.file.buffer.toString('base64');
            // Corrige mojibake: multer recebe o filename como Latin-1 mas o browser envia UTF-8
            try {
                const nomeBruto = req.file.originalname || '';
                documento_nome = Buffer.from(nomeBruto, 'latin1').toString('utf8');
            } catch (_) {
                documento_nome = req.file.originalname;
            }
        } catch (fileErr) {
            console.error('[MULTA-UPLOAD] Erro ao converter PDF:', fileErr.message);
        }
    }

    // Se o AIT estГЎ na lista de multas antigas, forГ§a status 'Antiga'
    const finalStatus = isAitAntiga(numero_ait) ? 'Antiga' : (status || 'ConferГӘncia');
    // Captura usuГЎrio logado
    const createdById = req.user ? req.user.id : null;
    const createdByNome = req.user ? (req.user.nome || req.user.username || null) : null;

    db.run(
        `INSERT INTO multas_logistica (data_infracao, hora_infracao, numero_ait, motivo, valor_multa, pontuacao, placa, local_infracao, data_limite, status, documento_nome, documento_base64, motorista_id, motorista_nome, parcelas, created_by_id, created_by_nome)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        [data_infracao || null, hora_infracao || null, numero_ait || null, motivo || null, valor_multa || null, pontuacao || 0, placa || null, local_infracao || null, data_limite || null, finalStatus, documento_nome, documento_base64, motorista_id || null, motorista_nome || null, parcelas || 1, createdById, createdByNome],
        function (err) {
            if (err) return res.status(500).json({ error: err.message });
            res.json({ id: this.lastID, ok: true });
        }
    );
});


async function notificarRHAuto(motoristaId, status, parcelas, valorMultaStr, dataInfracao, numAit, multaExtra) {
    return new Promise((resolve, reject) => {
        if (!motoristaId) return reject(new Error('Motorista nГЈo informado. NГЈo Г© possГӯvel notificar o RH.'));
        db.get('SELECT * FROM colaboradores WHERE id = ?', [motoristaId], async (err, colab) => {
            if (err || !colab) return reject(new Error('Motorista nГЈo encontrado no banco de dados.'));

            const numericStr = (valorMultaStr || '0').toString().replace(/[^\d,-]/g, '').replace(',', '.');
            const valorOriginal = parseFloat(numericStr) || 0;
            const multiplicador = (status === 'Multa NIC') ? 3 : 1;
            const valorTotalNum = valorOriginal * multiplicador;
            const p = parseInt(parcelas) || 1;
            const valorParcelaNum = valorTotalNum / p;
            const fmt = v => 'R$ ' + v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
            const logoPath = require('path').join(__dirname, '..', 'frontend', 'assets', 'logo-header.png');
            const [y, m, d] = (dataInfracao || '').split('-');
            const dataInfracaoFmt = d ? `${d}/${m}/${y}` : 'NГЈo informada';

            const extra = multaExtra || {};
            const prazoFmt = extra.data_limite ? extra.data_limite.split('-').reverse().join('/') : 'вҖ”';

            const htmlContent = `
                    <h2 style="color: #2c3e50; border-bottom: 2px solid #ea580c; padding-bottom: 10px;">Desconto Financeiro - Multa de TrГўnsito</h2>
                    <p>OlГЎ RH, favor realizar o desconto financeiro referente Г  multa de trГўnsito abaixo:</p>
                    <div style="background: #f9f9f9; padding: 15px; border-radius: 5px; margin: 20px 0;">
                        <p><strong>Colaborador:</strong> ${colab.nome_completo || colab.nome}</p>
                        <p><strong>CPF:</strong> ${colab.cpf}</p>
                        <p><strong>Data da InfraГ§ГЈo:</strong> ${dataInfracaoFmt}</p>
                        <p><strong>NВә do AIT (Multa):</strong> ${numAit || 'S/N'}</p>
                        <p><strong>Tipo/Status:</strong> ${status} ${status === 'Multa NIC' ? '(Base x 3)' : ''}</p>
                    </div>
                    <div style="margin-top: 20px; padding: 15px; border: 2px solid #ea580c; border-radius: 8px; background: #fff7ed;">
                        <h3 style="margin-top: 0; color: #c2410c;">Resumo do Desconto</h3>
                        <p style="font-size: 1.1rem;"><strong>Valor Total a Descontar:</strong> ${fmt(valorTotalNum)}</p>
                        <p style="font-size: 1.1rem;"><strong>Forma de Pagamento:</strong> ${p}x de ${fmt(valorParcelaNum)}</p>
                    </div>
                    <p style="margin-top: 30px; font-size: 0.9rem; color: #7f8c8d; text-align: center;">E-mail gerado automaticamente pelo Sistema RH & LogГӯstica</p>
                </div>
            `;
            try {
                await sendMailHelper({
                    from: `"AmГ©rica Rental" <${SMTP_CONFIG.auth.user}>`,
                    to: 'rh@americarental.com.br',
                    subject: `Desconto de Multa - ${colab.nome_completo || colab.nome}`,
                    html: htmlContent,
                    attachments: [{ filename: 'logo-header.png', path: logoPath, cid: 'empresa-logo' }]
                });
                resolve();
            } catch (errSend) {
                reject(errSend);
            }
        });
    });
}

// PUT /api/logistica/multas/:id вҖ” atualiza campos da multa (motorista, status, obs, link)
app.put('/api/logistica/multas/:id', authenticateToken, (req, res) => {
    const { motorista_id, motorista_nome, status, observacao, link_formulario, data_infracao, hora_infracao, numero_ait, motivo, valor_multa, pontuacao, parcelas, placa, local_infracao, data_limite } = req.body;

    db.get('SELECT * FROM multas_logistica WHERE id = ?', [req.params.id], (err, oldData) => {
        if (err || !oldData) return res.status(404).json({ error: 'Multa nГЈo encontrada' });

        if (oldData.status === 'Indicado' || oldData.status === 'Multa NIC') {
            return res.status(403).json({ error: 'Esta multa jГЎ foi enviada ao RH e nГЈo pode ser editada.' });
        }

        db.run(
            `UPDATE multas_logistica SET
                motorista_id = ?,
                motorista_nome = ?,
                status = ?,
                observacao = ?,
                link_formulario = ?,
                data_infracao = ?,
                hora_infracao = ?,
                numero_ait = ?,
                motivo = ?,
                valor_multa = ?,
                pontuacao = ?,
                parcelas = ?,
                placa = ?,
                local_infracao = ?,
                data_limite = ?,
                atualizado_em = CURRENT_TIMESTAMP
             WHERE id = ?`,
            [
                motorista_id !== undefined ? (motorista_id === "" ? null : motorista_id) : oldData.motorista_id,
                motorista_nome !== undefined ? (motorista_nome === "" ? null : motorista_nome) : oldData.motorista_nome,
                status !== undefined ? status : oldData.status,
                observacao !== undefined ? observacao : oldData.observacao,
                link_formulario !== undefined ? link_formulario : oldData.link_formulario,
                data_infracao !== undefined ? data_infracao : oldData.data_infracao,
                hora_infracao !== undefined ? hora_infracao : oldData.hora_infracao,
                numero_ait !== undefined ? numero_ait : oldData.numero_ait,
                motivo !== undefined ? motivo : oldData.motivo,
                valor_multa !== undefined ? valor_multa : oldData.valor_multa,
                pontuacao !== undefined ? pontuacao : oldData.pontuacao,
                parcelas !== undefined ? parcelas : oldData.parcelas,
                placa !== undefined ? placa : oldData.placa,
                local_infracao !== undefined ? local_infracao : oldData.local_infracao,
                data_limite !== undefined ? data_limite : oldData.data_limite,
                req.params.id
            ],
            function (errUpdate) {
                if (errUpdate) return res.status(500).json({ error: errUpdate.message });
                if (this.changes === 0) return res.status(404).json({ error: 'Multa nГЈo atualizada' });

                if (status && (status === 'Indicado' || status === 'Multa NIC')) {
                    const finalMotorista = motorista_id || oldData.motorista_id;
                    const finalValor = valor_multa || oldData.valor_multa;
                    const finalData = data_infracao || oldData.data_infracao;
                    const finalAit = numero_ait || oldData.numero_ait;
                    const finalParcelas = parcelas || oldData.parcelas || 1;
                    const multaExtra = {
                        placa: placa || oldData.placa,
                        hora_infracao: hora_infracao || oldData.hora_infracao,
                        local_infracao: local_infracao || oldData.local_infracao,
                        motivo: motivo || oldData.motivo,
                        pontuacao: pontuacao || oldData.pontuacao,
                        data_limite: data_limite || oldData.data_limite,
                    };
                    notificarRHAuto(finalMotorista, status, finalParcelas, finalValor, finalData, finalAit, multaExtra)
                        .then((result) => { res.json({ ok: true, emailEnviado: true }); })
                        .catch(errEmail => { res.status(500).json({ error: 'Salvo, mas o e-mail nГЈo foi enviado: ' + errEmail.message }); });
                } else {
                    res.json({ ok: true });
                }
            }
        );
    });
});

