// GET /api/logistica/multas/:id/documento вҖ” serve o PDF da multa (armazenado como base64 no banco)
app.get('/api/logistica/multas/:id/documento', (req, res) => {
    const token = req.query.token || (req.headers['authorization'] || '').replace('Bearer ', '');
    if (!token) return res.status(401).json({ error: 'NГЈo autorizado' });
    try {
        const jwt = require('jsonwebtoken');
        jwt.verify(token, SECRET_KEY);
    } catch (e) {
        return res.status(401).json({ error: 'Token invГЎlido' });
    }

    db.get('SELECT documento_base64, documento_nome, documento_path FROM multas_logistica WHERE id = ?', [req.params.id], (err, row) => {
        if (err || !row) return res.status(404).json({ error: 'Multa nГЈo encontrada' });

        const nome = row.documento_nome || 'documento_multa.pdf';
        res.setHeader('Content-Disposition', `inline; filename="${encodeURIComponent(nome)}"`);
        res.setHeader('Content-Type', 'application/pdf');

        // Tenta servir do base64 salvo no banco
        if (row.documento_base64) {
            const buf = Buffer.from(row.documento_base64, 'base64');
            return res.end(buf);
        }

        // Fallback: tenta servir do disco (registros antigos)
        if (row.documento_path && fs.existsSync(row.documento_path)) {
            return res.sendFile(path.resolve(row.documento_path));
        }

        return res.status(404).json({ error: 'Arquivo nГЈo disponГӯvel. FaГ§a o upload novamente.' });
    });
});

// GET /api/logistica/multas/:id/termo-desconto вҖ” serve o PDF da declaraГ§ГЈo de desconto (armazenado como base64 no banco)
app.get('/api/logistica/multas/:id/termo-desconto', (req, res) => {
    const token = req.query.token || (req.headers['authorization'] || '').replace('Bearer ', '');
    if (!token) return res.status(401).json({ error: 'NГЈo autorizado' });
    try {
        const jwt = require('jsonwebtoken');
        jwt.verify(token, SECRET_KEY);
    } catch (e) {
        return res.status(401).json({ error: 'Token invГЎlido' });
    }

    db.get('SELECT termo_desconto_base64, termo_desconto_nome FROM multas_logistica WHERE id = ?', [req.params.id], (err, row) => {
        if (err || !row) return res.status(404).json({ error: 'Multa nГЈo encontrada' });

        if (!row.termo_desconto_base64) return res.status(404).json({ error: 'Termo de desconto nГЈo disponГӯvel.' });

        const nome = row.termo_desconto_nome || 'termo_desconto.pdf';
        res.setHeader('Content-Disposition', `inline; filename="${encodeURIComponent(nome)}"`);
        
        let contentType = 'application/pdf';
        if (nome.toLowerCase().endsWith('.png')) contentType = 'image/png';
        else if (nome.toLowerCase().endsWith('.jpg') || nome.toLowerCase().endsWith('.jpeg')) contentType = 'image/jpeg';
        
        res.setHeader('Content-Type', contentType);

        const buf = Buffer.from(row.termo_desconto_base64, 'base64');
        return res.end(buf);
    });
});

