// POST: Salva o estado atual da tabela de recibos (histГіrico editГЎvel)
app.post('/api/recibos/salvar', authenticateToken, (req, res) => {
    const { mes, ano, itens } = req.body;
    if (!mes || !ano || !itens || !Array.isArray(itens)) return res.status(400).json({ error: 'ParГўmetros invГЎlidos' });

    db.serialize(() => {
        db.run('BEGIN TRANSACTION');
        
        // Failsafe migrations for columns added over time
        db.run("ALTER TABLE recibos_historico ADD COLUMN apuracao_diaria TEXT", () => {});
        db.run("ALTER TABLE recibos_historico ADD COLUMN folgas INTEGER DEFAULT 0", () => {});
        db.run("ALTER TABLE recibos_historico ADD COLUMN folgas_vt INTEGER DEFAULT 0", () => {});
        db.run("ALTER TABLE recibos_historico ADD COLUMN faltas_vt INTEGER DEFAULT 0", () => {});
        db.run("ALTER TABLE recibos_historico ADD COLUMN folgas_vr INTEGER DEFAULT 0", () => {});
        db.run("ALTER TABLE recibos_historico ADD COLUMN valor_vt_editado REAL", () => {});
        db.run("ALTER TABLE recibos_historico ADD COLUMN valor_vr_editado REAL", () => {});
        db.run("ALTER TABLE recibos_historico ADD COLUMN faltas_vr INTEGER DEFAULT 0", function() {
            let pending = itens.length;
            if (pending === 0) {
                db.run('COMMIT');
                return res.json({ ok: true, message: 'Nenhum item para salvar' });
            }

            const stmt = db.prepare(`
            INSERT INTO recibos_historico (mes, ano, colaborador_id, dias_trabalhados, dias_vr, faltas, dias_extra, valor_vr, apuracao_diaria, folgas, folgas_vt, faltas_vt, folgas_vr, faltas_vr, valor_vt_editado, valor_vr_editado) 
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(colaborador_id, mes, ano) 
            DO UPDATE SET 
                dias_trabalhados=excluded.dias_trabalhados,
                dias_vr=excluded.dias_vr,
                faltas=excluded.faltas,
                dias_extra=excluded.dias_extra,
                valor_vr=excluded.valor_vr,
                folgas=excluded.folgas,
                folgas_vt=excluded.folgas_vt,
                faltas_vt=excluded.faltas_vt,
                folgas_vr=excluded.folgas_vr,
                faltas_vr=excluded.faltas_vr,
                valor_vt_editado=excluded.valor_vt_editado,
                valor_vr_editado=excluded.valor_vr_editado,
                apuracao_diaria=COALESCE(excluded.apuracao_diaria, recibos_historico.apuracao_diaria)
            `, function(errPrep) {
                if (errPrep) {
                    console.error('[SALVAR RECIBOS] Erro no prepare:', errPrep.message);
                    db.run('ROLLBACK');
                    if (!res.headersSent) return res.status(500).json({ error: errPrep.message });
                }
            });
            
            let runError = null;
            itens.forEach(i => {
                stmt.run([mes, ano, i.colaborador_id, i.dias_trabalhados, i.dias_vr, i.faltas, i.dias_extra, i.valor_vr, i.apuracao_diaria, i.folgas || 0, i.folgas_vt || 0, i.faltas_vt || 0, i.folgas_vr || 0, i.faltas_vr || 0, i.valor_vt_editado, i.valor_vr_editado], function(errRun) {
                    if (errRun && !runError) {
                        runError = errRun;
                        console.error('[SALVAR RECIBOS] Erro no stmt.run:', errRun.message);
                    }
                    pending--;
                    if (pending === 0) {
                        stmt.finalize();
                        if (runError) {
                            db.run('ROLLBACK');
                            if (!res.headersSent) res.status(500).json({ error: runError.message });
                        } else {
                            db.run('COMMIT', () => {
                                if (!res.headersSent) res.json({ ok: true, message: 'HistГіrico de recibos salvo com sucesso' });
                            });
                        }
                    }
                });
            });
        });
    });
});

// POST: Anexar recibo gerado individualmente aos Docs. em Massa (prontuГЎrio digital + Assinafy)
app.post('/api/recibos/anexar-massa', authenticateToken, async (req, res) => {
    const { htmlContent, colaborador_id, mes, ano } = req.body;
    if (!htmlContent || !colaborador_id || !mes || !ano) return res.status(400).json({ error: 'ParГўmetros invГЎlidos' });

    try {
        const htmlPdf = require('html-pdf-node');
        const bufferPDF = await htmlPdf.generatePdf(
            { content: htmlContent },
            {
                format: 'A4',
                margin: { top: '0', bottom: '0', left: '0', right: '0' },
                printBackground: true,
                args: ['--no-sandbox', '--disable-setuid-sandbox']
            }
        );

        const novoProcesso = require('./novo_processo_assinafy');
        const tipoDocumento = 'Pagamentos';
        
        const colab = await new Promise((resolve, reject) =>
            db.get('SELECT * FROM colaboradores WHERE id = ?', [colaborador_id], (e, r) => e ? reject(e) : resolve(r))
        );
        if (!colab) throw new Error(`Colaborador ID ${colaborador_id} nГЈo encontrado`);

        const safeNome = (colab.nome_completo || 'Colaborador').normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-zA-Z0-9 ]/g, '').trim().replace(/\s+/g, '_');
        const nomeArquivo = `Pagamentos_${safeNome}_${mes}${ano}.pdf`;

        const { docId, filePath } = await pagamentosMassa.salvarDocumentoNoBanco({
            colaboradorId: colaborador_id,
            nomeColab: colab.nome_completo,
            bufferPDF: bufferPDF,
            nomeArquivo,
            tipoDocumento,
            ano,
            mes,
            basePath: BASE_UPLOAD_PATH,
        });

        // Tentar enviar para o Assinafy se possГӯvel
        let urlAssinatura = null;
        if (colab.email) {
            try {
                const resultado = await novoProcesso.enviarDocumentoParaAssinafy(docId, colaborador_id);
                urlAssinatura = resultado.urlAssinatura;
            } catch(e3) { console.warn('Erro ao enviar recibo pro Assinafy:', e3.message); }
        }

        try { await uploadDocToOneDrive(docId); } catch(e2) { }

        res.json({ ok: true, docId, urlAssinatura });
    } catch (e) {
        console.error('Erro ao anexar recibo (Pagamentos) em massa:', e.message);
        res.status(500).json({ error: e.message });
    }
});

// POST: Anexar recibos em lote otimizado (usa uma Гәnica instГўncia do navegador)
// в”Җв”Җв”Җ Upload de PDF gerado pelo browser (sem Chromium no servidor) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.post('/api/recibos/upload-pdf-colab',
    authenticateToken,
    multer({ storage: multer.memoryStorage(), limits: { fileSize: 20 * 1024 * 1024 } }).single('pdf'),
    async (req, res) => {
        try {
            const { colaborador_id, mes, ano, nomeArquivo } = req.body;
            if (!colaborador_id || !mes || !ano || !req.file) {
                return res.status(400).json({ error: 'ParГўmetros invГЎlidos' });
            }

            let bufferPDF = req.file.buffer;
            const nome = nomeArquivo || `Pagamentos_${colaborador_id}_${mes}${ano}.pdf`;

            // в”Җв”Җ Mesclar cartГЈo de ponto (igual ao fluxo anterior) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            try {
                const colab = await new Promise((resolve, reject) =>
                    db.get('SELECT * FROM colaboradores WHERE id = ?', [Number(colaborador_id)], (e, r) => e ? reject(e) : resolve(r))
                );
                const historico = await new Promise(res =>
                    db.get('SELECT apuracao_diaria FROM recibos_historico WHERE colaborador_id = ? AND mes = ? AND ano = ?',
                        [colaborador_id, mes, ano], (e, r) => res(r))
                );
                if (colab && historico && historico.apuracao_diaria) {
                    const apuracao = JSON.parse(historico.apuracao_diaria);
                    if (Array.isArray(apuracao) && apuracao.length > 0) {
                        const mesNome = ['Janeiro','Fevereiro','MarГ§o','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'][parseInt(mes)-1];
                        const { mergePdfPonto } = require('./cartao_ponto_generator');
                        bufferPDF = await mergePdfPonto(bufferPDF, colab, apuracao, String(mes).padStart(2, '0'), ano, mesNome);
                        console.log(`[UPLOAD-PDF] CartГЈo de ponto mesclado вҖ” colaborador ${colaborador_id}`);
                    }
                }
            } catch (errPonto) {
                console.error('[UPLOAD-PDF] Erro ao mesclar cartГЈo de ponto (continuando sem ele):', errPonto.message);
                // NГЈo interrompe вҖ” salva o recibo sem o cartГЈo de ponto
            }
            // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

            const { docId, filePath: savedPath } = await pagamentosMassa.salvarDocumentoNoBanco({
                colaboradorId: Number(colaborador_id),
                nomeColab: '',
                bufferPDF,
                nomeArquivo: nome,
                tipoDocumento: 'Pagamentos',
                ano,
                mes,
                basePath: BASE_UPLOAD_PATH,
            });

            // Salvar cГіpia _base.pdf para permitir reconstruГ§ГЈo ao processar holerites sem duplicaГ§ГЈo
            try {
                const path = require('path');
                const fs = require('fs');
                const basePath = savedPath.replace(/\.pdf$/i, '_base.pdf');
                fs.writeFileSync(basePath, bufferPDF);
            } catch(errBase) { console.warn('[UPLOAD-PDF] Erro ao salvar _base.pdf:', errBase.message); }

            uploadDocToOneDrive(docId).catch(e => console.warn('[UPLOAD-PDF] OneDrive bg:', e.message));
            console.log(`[UPLOAD-PDF] вң… Colaborador ${colaborador_id} вҖ” ${nome}`);
            res.json({ ok: true, docId });
        } catch (e) {
            console.error('[UPLOAD-PDF] Erro:', e.message);
            res.status(500).json({ error: e.message });
        }
    }
);

app.post('/api/recibos/anexar-massa-lote', authenticateToken, async (req, res) => {
    const { lote, mes, ano } = req.body;
    if (!lote || !Array.isArray(lote) || !mes || !ano) return res.status(400).json({ error: 'ParГўmetros invГЎlidos' });

    // Responde imediatamente para evitar timeout do proxy (502)
    // O processamento continua em background
    res.json({ ok: true, sucesso: 0, falha: 0, processando: true, total: lote.length });

    try {
        const htmlPdf = require('html-pdf-node');
        let sucesso = 0;
        let falha = 0;

        // 1. Buscar dados dos colaboradores
        const loteProcessar = [];
        for (let i = 0; i < lote.length; i++) {
            try {
                const colab = await new Promise((resolve, reject) =>
                    db.get('SELECT * FROM colaboradores WHERE id = ?', [lote[i].colaborador_id], (e, r) => e ? reject(e) : resolve(r))
                );
                if (!colab) throw new Error(`Colaborador ID ${lote[i].colaborador_id} nГЈo encontrado`);
                loteProcessar.push({ item: lote[i], colab });
            } catch (err) {
                console.error(`[RECIBOS-LOTE] Erro colaborador:`, err.message);
                falha++;
            }
        }

        // 2. Processar em lotes de 8 para nГЈo sobrecarregar o Chromium
        const TAMANHO_LOTE = 8;
        const options = {
            format: 'A4',
            margin: { top: '0', bottom: '0', left: '0', right: '0' },
            printBackground: true,
            args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage', '--disable-gpu', '--single-process']
        };

        for (let inicio = 0; inicio < loteProcessar.length; inicio += TAMANHO_LOTE) {
            const sublote = loteProcessar.slice(inicio, inicio + TAMANHO_LOTE);
            const filesToGenerate = sublote.map(lp => ({ content: lp.item.htmlContent }));

            let generatedPdfs = [];
            try {
                generatedPdfs = await htmlPdf.generatePdfs(filesToGenerate, options);
            } catch (errChromium) {
                console.error(`[RECIBOS-LOTE] Erro Chromium no lote ${inicio}-${inicio+TAMANHO_LOTE}:`, errChromium.message);
                // Tenta um por um como fallback
                for (let si = 0; si < sublote.length; si++) {
                    try {
                        const [pdf] = await htmlPdf.generatePdfs([filesToGenerate[si]], options);
                        generatedPdfs[si] = pdf;
                    } catch(e2) {
                        console.error(`[RECIBOS-LOTE] Falha individual idx ${inicio+si}:`, e2.message);
                        generatedPdfs[si] = null;
                    }
                }
            }

            // 3. Salvar no banco de dados e OneDrive
            for (let idx = 0; idx < sublote.length; idx++) {
                if (!generatedPdfs[idx]) { falha++; continue; }
                try {
                    const { item, colab } = sublote[idx];
                    let bufferPDF = generatedPdfs[idx].buffer;

                    const historico = await new Promise(res => db.get('SELECT apuracao_diaria FROM recibos_historico WHERE colaborador_id = ? AND mes = ? AND ano = ?', [item.colaborador_id, mes, ano], (e, r) => res(r)));
                    if (historico && historico.apuracao_diaria) {
                        try {
                            const apuracao = JSON.parse(historico.apuracao_diaria);
                            const mesNome = ['Janeiro','Fevereiro','MarГ§o','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'][parseInt(mes)-1];
                            const { mergePdfPonto } = require('./cartao_ponto_generator');
                            bufferPDF = await mergePdfPonto(bufferPDF, colab, apuracao, String(mes).padStart(2, '0'), ano, mesNome);
                        } catch(e) { console.error('[RECIBOS-LOTE] Erro merge ponto:', e.message); }
                    }

                    const safeNome = (colab.nome_completo || 'Colaborador').normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-zA-Z0-9 ]/g, '').trim().replace(/\s+/g, '_');
                    const nomeArquivo = `Pagamentos_${safeNome}_${mes}${ano}.pdf`;

                    const { docId } = await pagamentosMassa.salvarDocumentoNoBanco({
                        colaboradorId: item.colaborador_id,
                        nomeColab: colab.nome_completo,
                        bufferPDF: bufferPDF,
                        nomeArquivo,
                        tipoDocumento: 'Pagamentos',
                        ano,
                        mes,
                        basePath: BASE_UPLOAD_PATH,
                    });

                    uploadDocToOneDrive(docId).catch(e2 => console.warn('[RECIBOS-LOTE] Erro bg OneDrive:', e2.message));
                    sucesso++;
                    console.log(`[RECIBOS-LOTE] вң… ${sucesso}/${loteProcessar.length} вҖ” ${sublote[idx].colab.nome_completo}`);
                } catch (errSalvar) {
                    console.error(`[RECIBOS-LOTE] Erro ao salvar PDF:`, errSalvar.message);
                    falha++;
                }
            }

            // Pequena pausa entre lotes para nГЈo saturar memГіria
            if (inicio + TAMANHO_LOTE < loteProcessar.length) {
                await new Promise(r => setTimeout(r, 500));
            }
        }

        console.log(`[RECIBOS-LOTE] ConcluГӯdo: ${sucesso} ok, ${falha} falhas`);
    } catch (e) {
        console.error('[RECIBOS-LOTE] Erro geral:', e.message);
    }
});


