// GET: buscar dados completos de uma entrega de EPI (assinatura + EPIs)
app.get('/api/epi-entregas/:id', authenticateToken, (req, res) => {
    db.get(
        `SELECT ee.id, ee.ficha_id, ee.colaborador_id, ee.data_entrega,
                ee.epis_entregues, ee.assinatura_base64, ee.registrado_por,
                ef.grupo,
                c.nome_completo AS colaborador_nome
         FROM epi_entregas ee
         JOIN colaborador_epi_fichas ef ON ef.id = ee.ficha_id
         LEFT JOIN colaboradores c ON c.id = ee.colaborador_id
         WHERE ee.id = ?`,
        [req.params.id],
        (err, row) => {
            if (err) return res.status(500).json({ error: err.message });
            if (!row) return res.status(404).json({ error: 'Entrega nГЈo encontrada.' });
            const epis = JSON.parse(row.epis_entregues || '[]');
            // Agrupa itens repetidos
            const contagem = {};
            epis.forEach(nome => { contagem[nome] = (contagem[nome] || 0) + 1; });
            db.get(`SELECT selfie_base64 FROM epi_selfies WHERE colaborador_id = ? ORDER BY criado_em DESC LIMIT 1`, [row.colaborador_id], (err2, selfieRow) => {
                res.json({
                    id: row.id,
                    ficha_id: row.ficha_id,
                    colaborador_id: row.colaborador_id,
                    colaborador_nome: row.colaborador_nome,
                    data_entrega: row.data_entrega,
                    grupo: row.grupo,
                    registrado_por: row.registrado_por,
                    epis: Object.entries(contagem).map(([nome, qty]) => ({ nome, qty })),
                    assinatura_base64: row.assinatura_base64 || null,
                    selfie_base64: selfieRow ? selfieRow.selfie_base64 : null
                });
            });
        }
    );
});

// POST: registrar entrega assinada de EPIs
app.post('/api/epi-fichas/:id/entregas', authenticateToken, (req, res) => {
    const fichaId = req.params.id;
    const { colaborador_id, epis_entregues, assinatura_base64, data_entrega, epis_para_devolver, endereco_por_epi } = req.body;
    if (!epis_entregues || !assinatura_base64) return res.status(400).json({ error: 'Dados incompletos.' });
    const registrado_por = req.user ? (req.user.nome || req.user.username || '') : '';

    db.run(
        `INSERT INTO epi_entregas (ficha_id, colaborador_id, epis_entregues, assinatura_base64, data_entrega, registrado_por) VALUES (?,?,?,?,?,?)`,
        [fichaId, colaborador_id, JSON.stringify(epis_entregues), assinatura_base64, data_entrega || new Date().toLocaleDateString('pt-BR'), registrado_por],
        function (err) {
            if (err) return res.status(500).json({ error: err.message });
            const entregaId = this.lastID;

            // --- Auditoria JurГӯdica de Assinatura (tabela correta: assinaturas_auditoria) ---
            try {
                const ip = req.headers['x-forwarded-for'] || req.socket.remoteAddress || req.ip || '';
                const { dispositivo, gps_lat, gps_lon } = req.body;
                const payloadHash = JSON.stringify({ colaborador_id, epis_entregues, assinatura_base64, data_entrega });
                const hashDocumento = require('crypto').createHash('sha256').update(payloadHash).digest('hex');

                // Busca o nome real do colaborador antes de inserir
                db.get(`SELECT nome_completo FROM colaboradores WHERE id = ?`, [colaborador_id], (errC, colabRow) => {
                    const colabNome = colabRow ? colabRow.nome_completo : `ID ${colaborador_id}`;
                    const episLabel = Array.isArray(epis_entregues)
                        ? epis_entregues.slice(0, 3).join(', ') + (epis_entregues.length > 3 ? ` (+${epis_entregues.length - 3})` : '')
                        : String(epis_entregues);
                    const docLabel = `Entrega de EPI: ${episLabel}`;

                    db.run(
                        `INSERT INTO assinaturas_auditoria (documento_id, document_type, colaborador_id, colaborador_nome, gps_lat, gps_lon, dispositivo, ip_address, hash_assinatura) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                        [entregaId, docLabel, colaborador_id || null, colabNome, gps_lat || null, gps_lon || null, dispositivo || req.headers['user-agent'] || null, ip, hashDocumento],
                        (errA) => { if (errA) console.error('[AUDITORIA EPI] Erro ao inserir na auditoria:', errA.message); }
                    );
                });
            } catch (errAudit) {
                console.error('[AUDITORIA EPI] Erro ao salvar log de assinatura:', errAudit);
            }

            // Criar registros de emprГ©stimo se houver equipamentos para devolver
            if (Array.isArray(epis_para_devolver) && epis_para_devolver.length > 0) {
                const dataEntregaFmt = data_entrega || new Date().toLocaleDateString('pt-BR');
                epis_para_devolver.forEach(item => {
                    if (!item.nome || !item.data_devolucao_prevista) return;
                    db.run(
                        `INSERT INTO epi_emprestimos (colaborador_id, entrega_id, epi_nome, data_entrega, data_devolucao_prevista) VALUES (?,?,?,?,?)`,
                        [colaborador_id, entregaId, item.nome, dataEntregaFmt, item.data_devolucao_prevista],
                        (errEmp) => { if (errEmp) console.error('[EPI_EMPRESTIMOS] Erro ao registrar emprГ©stimo:', errEmp.message); }
                    );
                });
            }

            
            // InГӯcio do bloco de deduГ§ГЈo de estoque
            if (Array.isArray(epis_entregues) && epis_entregues.length > 0) {
                
                // Busca o sexo do colaborador
                db.get("SELECT sexo FROM colaboradores WHERE id = ?", [colaborador_id], (errC, rowC) => {
                    const colabSexo = (rowC && rowC.sexo) ? rowC.sexo.trim().toLowerCase() : '';
                    const isFeminino = colabSexo === 'feminino';
                    const isMasculino = colabSexo === 'masculino';

                    // AGRUPAR itens iguais para evitar condiГ§ГЈo de corrida:
                    const epiContagem = {};
                    epis_entregues.forEach(nome => {
                        if (!nome) return;
                        const key = nome.trim().toUpperCase();
                        epiContagem[key] = epiContagem[key] || { count: 0, original: nome };
                        epiContagem[key].count++;
                    });

                    // FunГ§ГЈo central para processar a baixa de um item com quantidade total e endereГ§o opcional
                function processarBaixaEstoque(item, count, enderecoId, enderecoNome) {
                    if (!item || item.quantidade_atual < count) {
                        console.warn(`[ESTOQUE] Item "${item ? item.nome : '?'}" com estoque insuficiente para baixa de ${count}.`);
                        count = item ? Math.max(0, item.quantidade_atual) : 0;
                        if (count === 0) return;
                    }
                    const newQtd = item.quantidade_atual - count;
                    // UPDATE atГҙmico no total
                    db.run("UPDATE estoque SET quantidade_atual = quantidade_atual - ? WHERE id = ? AND quantidade_atual >= ?", [count, item.id, count], (errUpd) => {
                        if (!errUpd) {
                            console.log(`[ESTOQUE] Baixa de ${count}x "${item.nome}" efetuada (endereГ§o: ${enderecoNome || 'Geral'}). Novo saldo: ${newQtd}.`);
                            // Se tem endereГ§o, debita do saldo por endereГ§o
                            if (enderecoId) {
                                db.run(
                                    'UPDATE estoque_saldo_por_endereco SET quantidade = MAX(0, quantidade - ?) WHERE estoque_id = ? AND endereco_id = ?',
                                    [count, item.id, enderecoId],
                                    (errSaldo) => { if (errSaldo) console.error('[ESTOQUE] Erro ao debitar saldo por endereГ§o:', errSaldo.message); }
                                );
                            } else {
                                // Sem endereГ§o especГӯfico: debita do 'Geral'
                                db.get("SELECT id FROM estoque_enderecos WHERE nome = 'Geral'", [], (errG, rowG) => {
                                    if (!errG && rowG) {
                                        db.run(
                                            'UPDATE estoque_saldo_por_endereco SET quantidade = MAX(0, quantidade - ?) WHERE estoque_id = ? AND endereco_id = ?',
                                            [count, item.id, rowG.id],
                                            () => {}
                                        );
                                    }
                                });
                            }
                            // Grava HistГіrico de SaГӯda
                            db.run(
                                'INSERT INTO estoque_historico (estoque_id, quantidade, tipo, usuario, motivo, endereco_id, endereco_nome) VALUES (?, ?, ?, ?, ?, ?, ?)',
                                [item.id, count, 'SaГӯda', registrado_por || 'Sistema', 'Baixa ProntuГЎrio Colaborador', enderecoId || null, enderecoNome || null],
                                () => {}
                            );
                        } else {
                            console.error(`[ESTOQUE] Erro ao baixar item ${item.id}:`, errUpd.message);
                        }

                        // Alerta de estoque mГӯnimo
                        if (!errUpd && newQtd < item.quantidade_minima && item.quantidade_atual >= item.quantidade_minima) {
                            const msg = `ESTOQUE BAIXO: O item "${item.nome}" (${item.departamento}) atingiu o estoque mГӯnimo. Quantidade Atual: ${newQtd}.`;
                            const dadosStr = JSON.stringify({ item_id: item.id, nome: item.nome, quantidade_atual: newQtd, quantidade_minima: item.quantidade_minima });

                            // Buscar tipo de notificaГ§ГЈo dos endereГ§os onde o item tem saldo
        db.all(
            `SELECT DISTINCT ee.tipo_notificacao FROM estoque_saldo_por_endereco s
             JOIN estoque_enderecos ee ON s.endereco_id = ee.id
             WHERE s.estoque_id = ? AND s.quantidade > 0 AND ee.tipo_notificacao != '' AND ee.tipo_notificacao IS NOT NULL`,
            [id], (errT, tiposRows) => {
                const tiposSet = new Set((tiposRows || []).map(r => r.tipo_notificacao));
                const tiposNotif = tiposSet.size > 0 ? Array.from(tiposSet) : ['compra']; // fallback: compra
                tiposNotif.forEach(tipoNotif => {
                    const dbTipo = tipoNotif === 'reposicao' ? 'estoque_reposicao' : 'estoque_minimo';
                    db.all(`SELECT usuario_id FROM config_notificacoes WHERE tipo = '${dbTipo}'`, [], (errCR, rowsCR) => {
                        if (!errCR && rowsCR && rowsCR.length > 0) {
                            rowsCR.forEach(c => {
                                db.run("INSERT INTO notificacoes_usuarios (usuario_id, tipo, mensagem, dados) VALUES (?, ?, ?, ?)", [c.usuario_id, dbTipo, msg, dadosStr]);
                            });
                        }
                    });
                });
            }
        );
        db.all("SELECT usuario_id FROM config_notificacoes WHERE tipo = 'estoque_minimo'", [], (errC, rowsC) => {
                                if (!errC && rowsC && rowsC.length > 0) {
                                    rowsC.forEach(c => {
                                        db.run("INSERT INTO notificacoes_usuarios (usuario_id, tipo, mensagem, dados) VALUES (?, ?, ?, ?)", [c.usuario_id, 'estoque_minimo', msg, dadosStr]);
                                    });
                                    const qIds = rowsC.map(r => r.usuario_id).join(',');
                                    db.all(`
                                        SELECT u.email as user_email, c.email_corporativo as colab_email
                                        FROM usuarios u
                                        LEFT JOIN colaboradores c ON u.nome = c.nome_completo
                                        WHERE u.id IN (${qIds})
                                    `, [], (errU, users) => {
                                        if (!errU && users && users.length > 0) {
                                            const emailsArray = users.map(u => u.colab_email || u.user_email).filter(e => e && e.trim() !== '');
                                            if (emailsArray.length > 0) {
                                                const emails = [...new Set(emailsArray)].join(',');
                                                const _logoPath8 = require('path').join(__dirname, '..', 'frontend', 'assets', 'logo-header.png');

                                                // IIFE async para permitir await ao baixar a foto do R2
                                                (async () => {
                                                    let fotoHtml = '';
                                                    let fotoAttachment = null;

                                                    // Tenta embutir a foto como CID inline para evitar bloqueio do Outlook
                                                    if (item.foto_url && item.foto_url.startsWith('http')) {
                                                        try {
                                                            const https = require('https');
                                                            const http = require('http');
                                                            const fotoBuffer = await new Promise((resolve, reject) => {
                                                                const mod = item.foto_url.startsWith('https') ? https : http;
                                                                mod.get(item.foto_url, (resp) => {
                                                                    const chunks = [];
                                                                    resp.on('data', c => chunks.push(c));
                                                                    resp.on('end', () => resolve(Buffer.concat(chunks)));
                                                                    resp.on('error', reject);
                                                                }).on('error', reject);
                                                            });
                                                            const contentType = item.foto_url.endsWith('.png') ? 'image/png' : (item.foto_url.endsWith('.webp') ? 'image/webp' : 'image/jpeg');
                                                            const fotoExt = contentType.split('/')[1].replace('jpeg','jpg');
                                                            fotoAttachment = { filename: 'produto.' + fotoExt, content: fotoBuffer, contentType, cid: 'produto-foto' };
                                                            fotoHtml = '<div style="text-align:center;margin:15px 0 20px;"><img src="cid:produto-foto" alt="' + item.nome + '" width="200" height="200" style="max-width:200px;max-height:200px;border-radius:8px;border:1px solid #e2e8f0;object-fit:contain;" /><p style="margin:6px 0 0;font-size:12px;color:#64748b;">Foto do produto</p></div>';
                                                        } catch(eFoto) {
                                                            console.warn('[ESTOQUE] NГЈo foi possГӯvel baixar foto do R2 para CID:', eFoto.message);
                                                            fotoHtml = '<div style="text-align:center;margin:15px 0 20px;"><img src="' + item.foto_url + '" alt="' + item.nome + '" width="200" height="200" style="max-width:200px;max-height:200px;border-radius:8px;border:1px solid #e2e8f0;object-fit:contain;" /><p style="margin:6px 0 0;font-size:12px;color:#64748b;">Foto do produto</p></div>';
                                                        }
                                                    } else if (item.foto_base64 && item.foto_base64.startsWith('data:image')) {
                                                        const _fm = item.foto_base64.match(/^data:([A-Za-z-+\/]+);base64,(.+)$/);
                                                        if (_fm) {
                                                            const _fext = (_fm[1].split('/')[1] || 'jpg').replace('jpeg','jpg');
                                                            fotoAttachment = { filename: 'produto.' + _fext, content: Buffer.from(_fm[2], 'base64'), cid: 'produto-foto' };
                                                            fotoHtml = '<div style="text-align:center;margin:15px 0 20px;"><img src="cid:produto-foto" alt="' + item.nome + '" width="200" height="200" style="max-width:200px;max-height:200px;border-radius:8px;border:1px solid #e2e8f0;object-fit:contain;" /><p style="margin:6px 0 0;font-size:12px;color:#64748b;">Foto do produto</p></div>';
                                                        }
                                                    }

                                                    const mailOptions = {
                                                        from: `"Estoque AmГ©rica Rental" <${SMTP_CONFIG.auth.user}>`,
                                                        to: emails,
                                                        subject: 'ALERTA DE ESTOQUE MГҚNIMO - America Rental',
                                                        html: `
                                                            <div style="font-family: Arial, sans-serif; color: #333; max-width: 600px; margin: auto; padding: 20px; border: 1px solid #ddd; border-radius: 8px;">
                                                                <div style="text-align: center; margin-bottom: 20px;">
                                                                    <img src="cid:empresa-logo" alt="America Rental" style="max-height: 80px;" />
                                                                </div>
                                                                <h2 style="color: #dc2626; text-align: center;">Aviso de Estoque MГӯnimo</h2>
                                                                <p>O seguinte item atingiu ou estГЎ abaixo da quantidade mГӯnima em estoque:</p>
                                                                ${fotoHtml}
                                                                <table style="width: 100%; border-collapse: collapse; margin-top: 15px; margin-bottom: 20px;">
                                                                    <tr><th style="text-align: left; padding: 8px; background: #f8fafc; border: 1px solid #e2e8f0;">Item</th><td style="padding: 8px; border: 1px solid #e2e8f0; font-weight: bold;">${item.nome}</td></tr>
                                                                    <tr><th style="text-align: left; padding: 8px; background: #f8fafc; border: 1px solid #e2e8f0;">Departamento</th><td style="padding: 8px; border: 1px solid #e2e8f0;">${item.departamento}</td></tr>
                                                                    <tr><th style="text-align: left; padding: 8px; background: #f8fafc; border: 1px solid #e2e8f0;">Quantidade Atual</th><td style="padding: 8px; border: 1px solid #e2e8f0; color: #dc2626; font-weight: bold;">${newQtd}</td></tr>
                                                                    <tr><th style="text-align: left; padding: 8px; background: #f8fafc; border: 1px solid #e2e8f0;">Quantidade MГӯnima</th><td style="padding: 8px; border: 1px solid #e2e8f0;">${item.quantidade_minima}</td></tr>
                                                                    <tr><th style="text-align: left; padding: 8px; background: #f8fafc; border: 1px solid #e2e8f0;">Quantidade MГЎxima</th><td style="padding: 8px; border: 1px solid #e2e8f0;">${item.quantidade_maxima || '-'}</td></tr>
                                                                    <tr><th style="text-align: left; padding: 8px; background: #f8fafc; border: 1px solid #e2e8f0;">A Adquirir</th><td style="padding: 8px; border: 1px solid #e2e8f0; color: #16a34a; font-weight: bold;">${item.quantidade_maxima ? Math.max(0, item.quantidade_maxima - newQtd) : '-'}</td></tr>
                                                                </table>
                                                                <p>Por favor, providencie a reposiГ§ГЈo o mais breve possГӯvel.</p>
                                                            </div>
                                                        `,
                                                        attachments: [
                                                            { filename: 'logo.png', path: _logoPath8, cid: 'empresa-logo' },
                                                            ...(fotoAttachment ? [fotoAttachment] : [])
                                                        ]
                                                    };
                                                    sendMailHelper(mailOptions).catch(e => console.error('[ESTOQUE] Erro ao enviar e-mail:', e));
                                                })().catch(e => console.error('[ESTOQUE] Erro async ao montar email:', e));
                                            }

                                        }
                                    });
                                }
                            });
                        }
                    });
                }

                // Carregar todo o estoque para a memГіria
                db.all("SELECT * FROM estoque", [], (errEstoque, todosItens) => {
                    if (errEstoque || !todosItens) return;

                    Object.values(epiContagem).forEach(({ count, original }) => {
                        const originalNome = original.trim();
                        const nomeNormalizado = originalNome.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase();
                        
                        console.log(`[ESTOQUE] Tentando baixar EPI entregue: "${nomeNormalizado}" (Sexo Colab: ${isFeminino?'F':(isMasculino?'M':'-')})`);

                        // --- 1. Match Exato Direto ---
                        let match = todosItens.find(i => (i.nome || '').trim().normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase() === nomeNormalizado);
                        
                        // --- 2. Busca por Score (PontuaГ§ГЈo) ---
                        if (!match) {
                            const STOP_WORDS = new Set(['DE','DO','DA','DOS','DAS','E','A','O','OS','AS','EM','NO','NA','NOS','NAS','UM','UMA','POR']);
                            
                            // Verifica se o modelo foi selecionado explicitamente no frontend (ex: "POLO - G - FEMININA")
                            let colabFeminino = isFeminino;
                            let colabMasculino = isMasculino;
                            
                            let isFemininoExplicit = nomeNormalizado.includes('FEMININA') || nomeNormalizado.includes('FEMININO');
                            let isMasculinoExplicit = nomeNormalizado.includes('MASCULINA') || nomeNormalizado.includes('MASCULINO');
                            
                            if (isFemininoExplicit || isMasculinoExplicit) {
                                colabFeminino = isFemininoExplicit;
                                colabMasculino = isMasculinoExplicit;
                            }
                            
                            // Remove as tags de modelo para nГЈo interferir na extraГ§ГЈo de tokens base e do tamanho final
                            const tokensEpi = nomeNormalizado.split(/[\s\-\.\/,;]+/).filter(t => t.length > 0 && !['FEMININA','FEMININO','MASCULINA','MASCULINO'].includes(t));
                            const lastToken = tokensEpi.length > 0 ? tokensEpi[tokensEpi.length - 1] : '';
                            const isSize = /^(P|M|G|GG|XG|EG|EXG|XGG|\d{2})$/.test(lastToken);
                            
                            let bestScore = -9999;
                            let bestItem = null;

                            todosItens.forEach(item => {
                                const itemNomeNorm = (item.nome || '').trim().normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase();
                                const tokensItem = itemNomeNorm.split(/[\s\-\.\/,;]+/).filter(t => t.length > 0);
                                
                                let score = 0;
                                
                                // Pontos por conter as palavras base do EPI (todas menos o tamanho)
                                const baseTokensEpi = isSize ? tokensEpi.slice(0, -1) : tokensEpi;
                                let validBaseTokens = baseTokensEpi.filter(t =>
                                    t.length >= 3 &&
                                    !STOP_WORDS.has(t) &&
                                    !/^\d+$/.test(t) &&
                                    !/^\d+\.\d+$/.test(t) &&
                                    t !== 'CA'
                                );
                                if (validBaseTokens.length === 0) validBaseTokens = baseTokensEpi.filter(t => t.length >= 2 && !STOP_WORDS.has(t));
                                
                                let matchedBaseCount = 0;
                                validBaseTokens.forEach(t => {
                                    if (tokensItem.includes(t)) matchedBaseCount++;
                                });
                                // Se bateu todas as palavras base, ganha muito ponto
                                if (matchedBaseCount > 0 && matchedBaseCount === validBaseTokens.length) score += 200;
                                else score += matchedBaseCount * 10;
                                
                                // Se for um item completamente diferente, o score de base vai ser baixo e nГЈo queremos
                                if (matchedBaseCount < validBaseTokens.length - 1) return; // ignora se faltar muita palavra

                                // InclusГЈo total da string
                                if (itemNomeNorm.includes(nomeNormalizado)) score += 50;

                                // Match de GГӘnero
                                const hasFeminina = itemNomeNorm.includes('FEMININ');
                                const hasMasculina = itemNomeNorm.includes('MASCULIN');
                                if (colabFeminino) {
                                    if (hasFeminina) score += 150;
                                    else if (hasMasculina) score -= 150;
                                } else if (colabMasculino) {
                                    if (hasMasculina) score += 150;
                                    else if (hasFeminina) score -= 150;
                                }

                                // Match de Tamanho
                                if (isSize) {
                                    const sizeInItem = tokensItem.includes(lastToken);
                                    if (sizeInItem) {
                                        score += 100; // Tamanho bateu!
                                    } else {
                                        // Tem algum outro tamanho no item?
                                        const otherSizes = tokensItem.filter(t => /^(P|M|G|GG|XG|EG|EXG|XGG|\d{2})$/.test(t) && t !== lastToken);
                                        if (otherSizes.length > 0) score -= 100; // Penaliza se for de outro tamanho
                                    }
                                }

                                if (score > bestScore) {
                                    bestScore = score;
                                    bestItem = item;
                                }
                            });

                            if (bestItem && bestScore >= 50) { // Limiar mГӯnimo de seguranГ§a
                                match = bestItem;
                            }
                        }

                        if (match) {
                            console.log(`[ESTOQUE] Match encontrado: "${match.nome}"`);
                            // Resolver endereГ§o selecionado para este EPI
                            const epiKeyNorm = (original || '').trim().toUpperCase();
                            let eEnderecoId = null;
                            let eEnderecoNome = null;
                            if (endereco_por_epi && typeof endereco_por_epi === 'object') {
                                // Tenta match exato, depois case-insensitive
                                const keys = Object.keys(endereco_por_epi);
                                const foundKey = keys.find(k => k.trim().toUpperCase() === epiKeyNorm) || keys.find(k => epiKeyNorm.includes(k.trim().toUpperCase()));
                                if (foundKey) {
                                    const endInfo = endereco_por_epi[foundKey];
                                    eEnderecoId = endInfo && endInfo.id ? endInfo.id : (typeof endInfo === 'number' ? endInfo : null);
                                    eEnderecoNome = endInfo && endInfo.nome ? endInfo.nome : null;
                                }
                            }
                            processarBaixaEstoque(match, count, eEnderecoId, eEnderecoNome);
                        } else {
                            console.warn(`[ESTOQUE] Item "${originalNome}" nГЈo encontrado no estoque apГіs tentativas.`);
                        }
                    });
                });
                }); // fim db.get sexo
            }
            // Fim do bloco de deduГ§ГЈo de estoque



            res.json({ id: this.lastID });
        }
    );
});

// POST: salvar PDF da ficha EPI no OneDrive
app.post('/api/epi-fichas/:id/save-onedrive', authenticateToken, async (req, res) => {
    const fichaId = req.params.id;
    const { pdf_base64, colaborador_id } = req.body;
    if (!pdf_base64 || !colaborador_id) return res.status(400).json({ error: 'Dados incompletos.' });
    if (!process.env.ONEDRIVE_CLIENT_ID) return res.json({ success: false, msg: 'OneDrive nao configurado.' });
    try {
        const colab = await new Promise((resolve, reject) =>
            db.get('SELECT * FROM colaboradores WHERE id=?', [colaborador_id], (e, r) => e ? reject(e) : resolve(r))
        );
        if (!colab) return res.status(404).json({ error: 'Colaborador nao encontrado.' });
        const safeNome = formatarNome(colab.nome_completo || 'Colaborador');
        const base64Data = pdf_base64.includes('base64,') ? pdf_base64.split('base64,')[1] : pdf_base64;
        const pdfBuffer = Buffer.from(base64Data, 'base64');
        const onedriveBase = `${process.env.ONEDRIVE_BASE_PATH || 'RH/1.Colaboradores/Sistema'}/${safeNome}`;
        // Pasta EPI: FichaEPI_N_Nome.pdf (sem sobrepor, nГәmero sequencial)
        const epiFolder = `${onedriveBase}/EPI`;
        await onedrive.ensurePath(epiFolder);
        // EPI: um Гәnico arquivo por ficha (sobrescreve a cada entrega)
        const epiFileName = `FichaEPI_${fichaId}_${safeNome}.pdf`;
        await onedrive.uploadToOneDrive(epiFolder, epiFileName, pdfBuffer);
        res.json({ success: true, arquivo_epi: epiFileName });
    } catch (err) {
        console.error('[EPI save-onedrive]', err);
        res.status(500).json({ error: err.message });
    }
});

// GET: todas as entregas de EPI de um colaborador (todas as fichas)
app.get('/api/colaboradores/:id/epi-entregas', authenticateToken, (req, res) => {
    db.all(
        `SELECT ee.id, ee.ficha_id, ee.data_entrega, ee.epis_entregues, ee.registrado_por, ef.grupo
         FROM epi_entregas ee
         JOIN colaborador_epi_fichas ef ON ef.id = ee.ficha_id
         WHERE ee.colaborador_id = ?
         ORDER BY ee.data_entrega DESC, ee.id DESC`,
        [req.params.id],
        (err, rows) => {
            if (err) return res.status(500).json({ error: err.message });
            const result = [];
            (rows || []).forEach(r => {
                const epis = JSON.parse(r.epis_entregues || '[]');
                if (epis.length === 0) {
                    result.push({ id: r.id, ficha_id: r.ficha_id, data_entrega: r.data_entrega, epi_nome: '\u2014', qty: 1, grupo: r.grupo, registrado_por: r.registrado_por || '' });
                } else {
                    // Agrupa nomes repetidos e conta a quantidade
                    const contagem = {};
                    epis.forEach(nome => { contagem[nome] = (contagem[nome] || 0) + 1; });
                    Object.entries(contagem).forEach(([nome, qty]) => {
                        result.push({ id: r.id, ficha_id: r.ficha_id, data_entrega: r.data_entrega, epi_nome: nome, qty, grupo: r.grupo, registrado_por: r.registrado_por || '' });
                    });
                }
            });
            res.json(result);
        }
    );
});

// DELETE: remover um EPI especГӯfico de uma entrega (ou toda a entrega se for o Гәnico)
app.delete('/api/epi-entregas/:id/epi', authenticateToken, (req, res) => {
    const { epi_nome, senha } = req.body;
    if (senha !== 'EXEPI2499!') return res.status(403).json({ error: 'Senha incorreta.' });
    if (!epi_nome) return res.status(400).json({ error: 'Nome do EPI nГЈo informado.' });

    db.get('SELECT * FROM epi_entregas WHERE id = ?', [req.params.id], (err, row) => {
        if (err) return res.status(500).json({ error: err.message });
        if (!row) return res.status(404).json({ error: 'Entrega nГЈo encontrada.' });

        const epis = JSON.parse(row.epis_entregues || '[]');
        const novoArray = epis.filter(e => e !== epi_nome);

        if (novoArray.length === 0) {
            // Гҡltimo EPI da entrega вҖ” exclui o registro inteiro
            db.run('DELETE FROM epi_entregas WHERE id = ?', [req.params.id], function (err2) {
                if (err2) return res.status(500).json({ error: err2.message });
                res.json({ success: true, entrega_excluida: true });
            });
        } else {
            // Ainda restam EPIs вҖ” apenas atualiza o array
            db.run('UPDATE epi_entregas SET epis_entregues = ? WHERE id = ?',
                [JSON.stringify(novoArray), req.params.id],
                function (err2) {
                    if (err2) return res.status(500).json({ error: err2.message });
                    res.json({ success: true, entrega_excluida: false });
                }
            );
        }
    });
});

