// POST: registrar devoluГ§ГЈo de equipamento + repor estoque
app.post('/api/epi-emprestimos/:id/devolver', authenticateToken, (req, res) => {
    const empId = req.params.id;
    const devolvido_por = req.user ? (req.user.nome || req.user.username || '') : '';
    const dataHoje = new Date().toLocaleDateString('pt-BR');

    db.get('SELECT * FROM epi_emprestimos WHERE id = ?', [empId], (err, emprestimo) => {
        if (err) return res.status(500).json({ error: err.message });
        if (!emprestimo) return res.status(404).json({ error: 'EmprГ©stimo nГЈo encontrado.' });
        if (emprestimo.data_devolvido) return res.status(400).json({ error: 'Equipamento jГЎ foi devolvido.' });

        db.run(
            `UPDATE epi_emprestimos SET data_devolvido = ?, devolvido_por = ? WHERE id = ?`,
            [dataHoje, devolvido_por, empId],
            function(errUpd) {
                if (errUpd) return res.status(500).json({ error: errUpd.message });

                // Repor no estoque: match por nome normalizado com score de tokens
                const nomeNorm = (emprestimo.epi_nome || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase();
                const STOP = new Set(['DE','DO','DA','DOS','DAS','E','A','O','OS','AS','EM','NO','NA']);
                const tokens = nomeNorm.split(/[\s\-\.\/,;]+/).filter(t =>
                    t.length >= 3 &&
                    !STOP.has(t) &&
                    !/^\d+$/.test(t) &&
                    !/^\d+\.\d+$/.test(t) &&
                    t !== 'CA' &&
                    !['FEMININA','FEMININO','MASCULINA','MASCULINO'].includes(t)
                );
                const tokensFallback = tokens.length > 0 ? tokens :
                    nomeNorm.split(/[\s\-\.\/,;]+/).filter(t => t.length > 1 && !STOP.has(t));

                db.all('SELECT * FROM estoque', [], (errEst, itens) => {
                    if (errEst || !itens) {
                        return res.json({ success: true, estoque_reposto: false });
                    }

                    let bestScore = 0;
                    let bestItem = null;
                    itens.forEach(item => {
                        const itemNorm = (item.nome || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase();
                        let score = 0;
                        tokensFallback.forEach(t => { if (itemNorm.includes(t)) score++; });
                        if (score > bestScore) { bestScore = score; bestItem = item; }
                    });

                    const requiredScore = Math.ceil(tokensFallback.length * 0.6);
                    if (bestItem && bestScore >= requiredScore) {
                        db.run(
                            'UPDATE estoque SET quantidade_atual = quantidade_atual + 1, atualizado_em = CURRENT_TIMESTAMP WHERE id = ?',
                            [bestItem.id],
                            (errR) => {
                                if (!errR) {
                                    db.run(
                                        'INSERT INTO estoque_historico (estoque_id, quantidade, tipo, usuario, motivo) VALUES (?,1,"Entrada",?,"DevoluГ§ГЈo de EPI emprestado")',
                                        [bestItem.id, devolvido_por]
                                    );
                                }
                                console.log(`[EPI_EMPRESTIMOS] Devolvido: "${emprestimo.epi_nome}" вҶ’ estoque "${bestItem.nome}" +1`);
                                res.json({ success: true, estoque_reposto: true, item_estoque: bestItem.nome });
                            }
                        );
                    } else {
                        console.warn(`[EPI_EMPRESTIMOS] DevoluГ§ГЈo sem match no estoque para: "${emprestimo.epi_nome}"`);
                        res.json({ success: true, estoque_reposto: false });
                    }
                });
            }
        );
    });
});

