// --- USUГҒRIOS ---
app.get('/api/usuarios', authenticateToken, (req, res) => {
    db.all(`SELECT u.id, u.username, u.nome, u.email, u.role, u.departamento, u.grupo_permissao_id, u.ativo,
                   g.nome as grupo_nome
            FROM usuarios u
            LEFT JOIN grupos_permissao g ON g.id = u.grupo_permissao_id
            ORDER BY u.nome`, [], (err, usuarios) => {
        if (err) return res.status(500).json({ error: err.message });
        
        db.all(`SELECT id, nome_completo, foto_base64, foto_path FROM colaboradores`, [], (errC, colabs) => {
            if (errC) return res.json(usuarios);
            
            const norm = (s) => s ? s.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim() : "";
            
            usuarios.forEach(u => {
                const uNome = norm(u.nome);
                let c = colabs.find(col => norm(col.nome_completo) === uNome);
                if (!c) {
                    c = colabs.find(col => {
                        const cNome = norm(col.nome_completo);
                        return cNome && uNome && (cNome.includes(uNome) || uNome.includes(cNome));
                    });
                }
                if (c) {
                    u.foto_colaborador = c.foto_base64 || (c.foto_path ? '/api/colaboradores/foto/' + c.id : null);
                }
            });
            
            res.json(usuarios);
        });
    });
});

app.post('/api/usuarios', authenticateToken, (req, res) => {
    const { username, password, nome, email, departamento, grupo_permissao_id, role, estoque_enderecos_permitidos } = req.body;
    if (!username || !password) return res.status(400).json({ error: 'Username e senha sГЈo obrigatГіrios' });
    const hash = bcrypt.hashSync(password, 10);
    const endPermitidos = estoque_enderecos_permitidos ? JSON.stringify(estoque_enderecos_permitidos) : null;
    db.run(
        'INSERT INTO usuarios (username, password_hash, nome, email, departamento, grupo_permissao_id, role, ativo, estoque_enderecos_permitidos) VALUES (?,?,?,?,?,?,?,1,?)',
        [username, hash, nome || username, email || null, departamento || 'RH', grupo_permissao_id || null, role || 'Operacional', endPermitidos],
        function (err) {
            if (err) {
                const msg = err.message.includes('UNIQUE') ? 'Este username jГЎ estГЎ cadastrado.' : err.message;
                return res.status(400).json({ error: msg });
            }
            res.status(201).json({ id: this.lastID, message: 'UsuГЎrio criado com sucesso' });
        }
    );
});

app.put('/api/usuarios/:id', authenticateToken, (req, res) => {
    const { nome, email, departamento, grupo_permissao_id, role, ativo, password, estoque_enderecos_permitidos } = req.body;
    const updates = [];
    const values = [];
    if (nome !== undefined) { updates.push('nome = ?'); values.push(nome); }
    if (email !== undefined) { updates.push('email = ?'); values.push(email); }
    if (departamento !== undefined) { updates.push('departamento = ?'); values.push(departamento); }
    if (grupo_permissao_id !== undefined) { updates.push('grupo_permissao_id = ?'); values.push(grupo_permissao_id); }
    if (role !== undefined) { updates.push('role = ?'); values.push(role); }
    if (ativo !== undefined) { updates.push('ativo = ?'); values.push(ativo); }
    if (estoque_enderecos_permitidos !== undefined) {
        updates.push('estoque_enderecos_permitidos = ?');
        values.push(estoque_enderecos_permitidos ? JSON.stringify(estoque_enderecos_permitidos) : null);
    }
    if (password) { updates.push('password_hash = ?'); values.push(bcrypt.hashSync(password, 10)); }
    if (updates.length === 0) return res.json({ message: 'Nenhuma alteraГ§ГЈo' });
    values.push(req.params.id);
    db.run(`UPDATE usuarios SET ${updates.join(', ')} WHERE id = ?`, values, function (err) {
        if (err) return res.status(400).json({ error: err.message });
        res.json({ message: 'UsuГЎrio atualizado com sucesso' });
    });
});


