// Migration: Excluir cargo genГ©rico 'ManutenГ§ГЈo' e adicionar cargos especГӯficos de manutenГ§ГЈo
db.serialize(() => {
    db.run("DELETE FROM cargos WHERE LOWER(TRIM(nome)) = 'manutencao' OR LOWER(TRIM(nome)) = 'manutenГ§ГЈo'");

    // Inserir ManutenГ§ГЈo apenas se nГЈo foi excluГӯdo
    db.run("INSERT INTO departamentos (nome) SELECT 'ManutenГ§ГЈo' WHERE NOT EXISTS (SELECT 1 FROM departamentos WHERE nome='ManutenГ§ГЈo') AND NOT EXISTS (SELECT 1 FROM departamentos_excluidos WHERE nome='ManutenГ§ГЈo')");

    const cargosManut = [
        'Aux. de ManutenГ§ГЈo',
        'Ass. de ManutenГ§ГЈo 1',
        'Ass. de ManutenГ§ГЈo 2',
        'TГ©c. de ManutenГ§ГЈo',
        'Sup. de ManutenГ§ГЈo'
    ];
    cargosManut.forEach(nome => {
        db.run("INSERT INTO cargos (nome, departamento) SELECT ?, 'ManutenГ§ГЈo' WHERE NOT EXISTS (SELECT 1 FROM cargos WHERE nome=?) AND NOT EXISTS (SELECT 1 FROM cargos_excluidos WHERE nome=?)", [nome, nome, nome]);
    });
});

