// POST /api/dissidio/aplicar вҖ” aplica reajuste em massa por cargo
app.post('/api/dissidio/aplicar', authenticateToken, async (req, res) => {
    const { cargo, novo_salario } = req.body;
    const loggedUser = req.user ? (req.user.username || req.user.nome || 'UNKNOWN') : 'SYSTEM';
    if (!cargo || !novo_salario || isNaN(parseFloat(novo_salario))) {
        return res.status(400).json({ error: 'cargo e novo_salario sГЈo obrigatГіrios.' });
    }
    const targetSalary = parseFloat(novo_salario);
    if (targetSalary <= 0) {
        return res.status(400).json({ error: 'SalГЎrio deve ser maior que zero.' });
    }
    try {
        let colabs = [];
        if (cargo === 'VALE_TRANSPORTE') {
            colabs = await new Promise((resolve, reject) =>
                db.all(`SELECT id, valor_transporte as salario FROM colaboradores WHERE LOWER(meio_transporte) LIKE '%vt%' OR LOWER(meio_transporte) LIKE '%vale transporte%'`, [], (err, rows) =>
                    err ? reject(err) : resolve(rows || []))
            );
        } else if (cargo === 'VALE_REFEICAO') {
            // VR Г© um valor global вҖ” lГӘ o valor antigo ANTES de atualizar
            const oldRow = await new Promise((resolve) =>
                db.get(`SELECT valor FROM configuracoes_sistema WHERE chave = 'valor_vr'`, [], (e, r) => resolve(r)));
            const oldVal = oldRow ? parseFloat(oldRow.valor) : 35.00;
            // Salva novo valor em configuracoes_sistema
            await new Promise((resolve, reject) =>
                db.run(`INSERT OR REPLACE INTO configuracoes_sistema (chave, valor) VALUES ('valor_vr', ?)`, [String(targetSalary)], (err) => err ? reject(err) : resolve())
            );
            const pct = oldVal > 0 ? ((targetSalary - oldVal) / oldVal) * 100 : 0;
            await new Promise((resolve, reject) =>
                db.run(`INSERT INTO dissidios (cargo, percentual, salario_antes_media, salario_depois_media, total_colaboradores) VALUES (?, ?, ?, ?, ?)`,
                    ['VALE_REFEICAO', pct, oldVal, targetSalary, 1], (err) => err ? reject(err) : resolve())
            );
            db.run(`INSERT INTO auditoria (usuario, programa, campo, conteudo_anterior, conteudo_atual, registro_id) VALUES (?, ?, ?, ?, ?, ?)`,
                [loggedUser, 'DissГӯdio', 'Reajuste: VALE_REFEICAO', `VR antes: R$ ${oldVal.toFixed(2)}`, `VR depois: R$ ${targetSalary.toFixed(2)}`, 0]);
            return res.json({ ok: true, atualizados: 1, cargo: 'VALE_REFEICAO', novo_salario: targetSalary, percentual: pct });
        } else {
            colabs = await new Promise((resolve, reject) =>
                db.all(`SELECT id, salario FROM colaboradores WHERE trim(cargo) = trim(?)`, [cargo], (err, rows) =>
                    err ? reject(err) : resolve(rows || []))
            );
        }
        if (colabs.length === 0) {
            return res.status(404).json({ error: 'Nenhum colaborador encontrado para este cargo.' });
        }
        const parseSalary = (val) => {
            if (!val) return 0;
            if (typeof val === 'number') return val;
            let s = String(val).replace(/R\$\s*/g, '').trim();
            if (s.includes(',') && s.includes('.')) {
                const lastComma = s.lastIndexOf(',');
                const lastDot = s.lastIndexOf('.');
                if (lastComma > lastDot) {
                    return parseFloat(s.replace(/\./g, '').replace(',', '.')) || 0;
                } else {
                    return parseFloat(s.replace(/,/g, '')) || 0;
                }
            }
            if (s.includes(',')) return parseFloat(s.replace(',', '.')) || 0;
            return parseFloat(s) || 0;
        };
        const formatBRL = (val) => {
            const num = Math.round(parseFloat(val) * 100);
            const cents = (num % 100).toString().padStart(2, '0');
            const reais = Math.floor(num / 100).toString();
            const reaisFormatted = reais.replace(/\B(?=(\d{3})+(?!\d))/g, '.');
            return `R$ ${reaisFormatted},${cents}`;
        };

        let totalAntes = 0;
        let atualizados = 0;
        const salNewStr = formatBRL(targetSalary);

        for (const colab of colabs) {
            const salOld = parseSalary(colab.salario);
            totalAntes += salOld;
            if (cargo === 'VALE_TRANSPORTE') {
                await new Promise((resolve, reject) =>
                    db.run(`UPDATE colaboradores SET valor_transporte = ? WHERE id = ?`, [targetSalary, colab.id], (err) => err ? reject(err) : resolve())
                );
            } else {
                await new Promise((resolve, reject) =>
                    db.run(`UPDATE colaboradores SET salario = ? WHERE id = ?`, [targetSalary, colab.id], (err) => err ? reject(err) : resolve())
                );
            }
            atualizados++;
        }

        const mediaAntes = totalAntes / atualizados;
        const mediaDepois = targetSalary;
        let pct = 0;
        if (mediaAntes > 0) {
            pct = ((mediaDepois - mediaAntes) / mediaAntes) * 100;
        }

        await new Promise((resolve, reject) =>
            db.run(`INSERT INTO dissidios (cargo, percentual, salario_antes_media, salario_depois_media, total_colaboradores) VALUES (?, ?, ?, ?, ?)`,
                [cargo, pct, mediaAntes, mediaDepois, atualizados], (err) => err ? reject(err) : resolve())
        );

        // Auditoria
        db.run(`INSERT INTO auditoria (usuario, programa, campo, conteudo_anterior, conteudo_atual, registro_id) VALUES (?, ?, ?, ?, ?, ?)`,
            [loggedUser, 'DissГӯdio', `Reajuste: ${cargo}`,
                `MГ©dia antes: ${formatBRL(mediaAntes)} (${atualizados} colab.)`,
                `Novo salГЎrio: ${salNewStr} | Reajuste: ${pct >= 0 ? '+' : ''}${pct.toFixed(2)}%`,
                0]);

        res.json({ ok: true, atualizados, cargo, novo_salario: targetSalary, percentual: pct });
    } catch (e) {
        console.error('[DissГӯdio] Erro ao aplicar:', e.message);
        res.status(500).json({ error: e.message });
    }
});


