// в”Җв”Җ ATIVAR COLABORADORES NA DATA DE ADMISSГғO в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Quando a data_admissao chega, muda status de 'Aguardando inГӯcio' / 'Processo iniciado' вҶ’ 'Ativo'
function ativarColaboradoresPorAdmissao() {
    const hoje = new Date();
    const hojeStr = hoje.toISOString().split('T')[0]; // YYYY-MM-DD
    console.log(`[CRON-ADMISSAO] Verificando colaboradores com admissao <= ${hojeStr}...`);

    db.all(
        `SELECT id, nome_completo, data_admissao, status FROM colaboradores
         WHERE status IN ('Aguardando inГӯcio', 'Processo iniciado')
           AND data_admissao IS NOT NULL
           AND data_admissao != ''
           AND data_admissao <= ?`,
        [hojeStr],
        (err, rows) => {
            if (err) { console.error('[CRON-ADMISSAO] Erro ao buscar:', err.message); return; }
            if (!rows || rows.length === 0) {
                console.log('[CRON-ADMISSAO] Nenhum colaborador para ativar.');
                return;
            }
            rows.forEach(colab => {
                db.run(
                    `UPDATE colaboradores SET status = 'Ativo' WHERE id = ? AND status IN ('Aguardando inГӯcio', 'Processo iniciado')`,
                    [colab.id],
                    function (updateErr) {
                        if (updateErr) {
                            console.error(`[CRON-ADMISSAO] Erro ao ativar colab ${colab.id}:`, updateErr.message);
                        } else if (this.changes > 0) {
                            console.log(`[CRON-ADMISSAO] вң… Colaborador ativado: ${colab.nome_completo} (admissao: ${colab.data_admissao}, era: ${colab.status})`);
                        }
                    }
                );
            });
        }
    );
}

