// GET - preventivo por veiculo usando catГЎlogo (plano ou padrГЈo)
app.get('/api/frota/manutencoes/preventivo/:veiculo_id', authenticateToken, (req, res) => {
    const vid = req.params.veiculo_id;
    db.get('SELECT km_atual, em_manutencao FROM frota_veiculos WHERE id=?', [vid], (err, v) => {
        // Se o veГӯculo nГЈo estiver cadastrado em frota_veiculos, ainda assim tenta buscar manutenГ§Гөes
        const kmAtual = v?.km_atual || 0;
        const emManutencao = v?.em_manutencao || 0;

        // Apenas serviГ§os registrados para este veГӯculo (preventiva, concluГӯda ou nГЈo)
        db.all(`
            SELECT
                m.id,
                m.descricao,
                m.km_na_manutencao,
                m.km_proxima_manutencao,
                m.data_conclusao,
                m.data_agendamento,
                m.status,
                m.observacoes,
                m.custo,
                m.fornecedor,
                m.servico_catalogo_id,
                COALESCE(s.periodicidade_padrao, 0) as periodicidade_padrao,
                COALESCE(s.tipo_controle, 'KM') as tipo_controle,
                COALESCE(s.unidade, 'km') as unidade,
                COALESCE(c.nome, 'Geral') as categoria_nome,
                COALESCE(c.icone, 'wrench') as categoria_icone,
                COALESCE(s.criticidade, 'Media') as criticidade_cat
            FROM frota_manutencoes m
            LEFT JOIN frota_servicos_catalogo s ON (
                s.id = m.servico_catalogo_id
                OR (m.servico_catalogo_id IS NULL AND s.nome = m.descricao)
            )
            LEFT JOIN frota_categorias_manutencao c ON c.id = s.categoria_id
            WHERE m.veiculo_id = ? AND m.tipo = 'preventiva'
            GROUP BY m.id
            ORDER BY m.km_na_manutencao DESC, m.created_at DESC
        `, [vid], (err2, rows) => {
            if (err2) { console.error('[PREV ERROR]', err2.message); return res.status(500).json({ error: err2.message }); }

            console.log(`[PREV] veiculo_id=${vid} вҶ’ ${(rows||[]).length} registros encontrados`);

            // Para cada serviГ§o distinto, guardar tanto o Гәltimo concluГӯdo (km, data) quanto o agendado
            const porDescricao = {};
            (rows || []).forEach(r => {
                const key = r.servico_catalogo_id ? `cat_${r.servico_catalogo_id}` : `desc_${r.descricao || r.id}`;
                if (!porDescricao[key]) porDescricao[key] = { concluida: null, agendada: null, em_andamento: null, base: null };

                // O registro com maior KM = Гәltima manutenГ§ГЈo concluГӯda
                if (r.status === 'concluida') {
                    if (!porDescricao[key].concluida || (r.km_na_manutencao || 0) > (porDescricao[key].concluida.km_na_manutencao || 0)) {
                        porDescricao[key].concluida = r;
                    }
                }
                // Agendada mais recente
                if (r.status === 'agendada') {
                    if (!porDescricao[key].agendada) porDescricao[key].agendada = r;
                }
                // Em andamento
                if (r.status === 'em_andamento') {
                    if (!porDescricao[key].em_andamento) porDescricao[key].em_andamento = r;
                }
                // Fallback: qualquer registro como base
                if (!porDescricao[key].base) porDescricao[key].base = r;
            });

            // Cleanup obsolete ghost records
            Object.keys(porDescricao).forEach(key => {
                const p = porDescricao[key];
                if (p.agendada && p.concluida && p.agendada.id < p.concluida.id) p.agendada = null;
                if (p.em_andamento && p.concluida && p.em_andamento.id < p.concluida.id) p.em_andamento = null;
            });

            const plano = Object.values(porDescricao).map(({ concluida, agendada, em_andamento, base }) => {
                const item = em_andamento || agendada || base || concluida;
                const kmUlt = concluida ? (concluida.km_na_manutencao || 0) : 0;
                const intervKm = item.periodicidade_padrao || 10000;
                const alerta = Math.floor(intervKm * 0.1);
                // PreferГӘncia de kmProx: agendada (se jГЎ foi editada) > concluida > calculado
                const kmProx = (agendada?.km_proxima_manutencao > 0)
                    ? agendada.km_proxima_manutencao
                    : (concluida
                        ? (concluida.km_proxima_manutencao || (kmUlt + intervKm))
                        : (item.km_proxima_manutencao || (kmUlt + intervKm)));
                const kmRest = kmProx - kmAtual;

                let statusItem = 'ok';
                let criticidade = 'Baixa';
                if (kmRest <= 0) { statusItem = 'vencida'; criticidade = 'Critica'; }
                else if (kmRest <= intervKm * 0.1) { statusItem = 'proxima'; criticidade = 'Critica'; }
                else if (kmRest <= intervKm * 0.2) { statusItem = 'ok'; criticidade = 'Media'; }

                const statusFinal = em_andamento ? 'em_andamento' : (agendada ? 'agendada' : 'programada');
                return {
                    ...item,
                    status: statusFinal,
                    km_ultima: kmUlt,
                    km_proxima: kmProx,
                    km_restante: kmRest,
                    intervalo_configurado: kmProx - kmUlt,
                    status_item: statusItem,
                    criticidade,
                    data_ultima_manutencao: concluida?.data_conclusao || null,
                    data_agendamento: agendada?.data_agendamento || em_andamento?.data_agendamento || null,
                    data_inicio: em_andamento?.data_inicio || agendada?.data_inicio || null,
                    observacoes_concluida: concluida?.observacoes || null,
                    observacoes_agendada: agendada?.observacoes_agendamento || em_andamento?.observacoes_agendamento || null,
                    observacoes: item.observacoes || null,
                    apenas_vistoria: concluida?.apenas_vistoria || 0
                };
            });

            const grupos = {};
            plano.forEach(item => {
                const cat = item.categoria_nome || 'Geral';
                if (!grupos[cat]) grupos[cat] = { icone: item.categoria_icone, itens: [] };
                grupos[cat].itens.push(item);
            });

            res.json({ km_atual: kmAtual, em_manutencao: emManutencao, grupos });
        });
    });
});



