// POST - registrar manutenГ§ГЈo
app.post('/api/frota/manutencoes', authenticateToken, (req, res) => {
    const { veiculo_id, tipo, descricao, status, km_na_manutencao, km_proxima_manutencao, data_agendamento, data_conclusao, custo, fornecedor, observacoes, apenas_vistoria, servico_catalogo_id, data_inicio, tipo_conclusao } = req.body;
    if (!veiculo_id || !descricao) return res.status(400).json({ error: 'veiculo_id e descricao sГЈo obrigatГіrios' });
    const usuario_nome = req.user?.username || 'sistema';

    db.run(
        `INSERT INTO frota_manutencoes (veiculo_id, tipo, descricao, status, km_na_manutencao, km_proxima_manutencao, data_agendamento, data_conclusao, custo, fornecedor, observacoes, usuario_nome, apenas_vistoria, servico_catalogo_id, data_inicio, tipo_conclusao)
         VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`,
        [veiculo_id, tipo||'preventiva', descricao, status||'programada', km_na_manutencao||null, km_proxima_manutencao||null, data_agendamento||null, data_conclusao||null, custo||null, fornecedor||null, observacoes||null, usuario_nome, apenas_vistoria ? 1 : 0, servico_catalogo_id||null, data_inicio||null, tipo_conclusao||null],
        function(err) {
            if (err) return res.status(500).json({ error: err.message });
            // Se status Г© 'em_andamento', marcar veГӯculo como em manutenГ§ГЈo
            if (status === 'em_andamento') {
                db.run('UPDATE frota_veiculos SET em_manutencao=1, updated_at=CURRENT_TIMESTAMP WHERE id=?', [veiculo_id]);
            }
            res.json({ id: this.lastID, message: 'ManutenГ§ГЈo registrada' });
        }
    );
});

// PUT - editar em massa (catГЎlogo e histГіrico)
app.put('/api/frota/manutencoes/em-massa', authenticateToken, (req, res) => {
    const { veiculo_id, itens } = req.body;
    if (!veiculo_id || !Array.isArray(itens)) return res.status(400).json({ error: 'veiculo_id e itens sГЈo obrigatГіrios' });
    const usuario_nome = req.user?.username || 'sistema';

    db.serialize(() => {
        db.run('BEGIN TRANSACTION');
        let errorOccurred = false;

        itens.forEach(item => {
            if (errorOccurred) return;
            // 1. Atualizar o catГЎlogo
            if (item.servico_id) {
                db.run(
                    `UPDATE frota_servicos_catalogo 
                     SET nome=?, criticidade=?, tipo_controle=?, periodicidade_padrao=? 
                     WHERE id=?`,
                    [item.nome, item.criticidade, item.tipo_controle, item.periodicidade_padrao, item.servico_id],
                    err => { if (err) { console.error('Erro atualizar catalogo', err); errorOccurred = true; } }
                );
            }
            
            // 2. Inserir histГіrico de manutenГ§ГЈo concluГӯda se km_ultima ou data_ultima foi informado
            if (item.km_ultima || item.data_ultima) {
                db.run(
                    `INSERT INTO frota_manutencoes (veiculo_id, tipo, descricao, status, km_na_manutencao, data_conclusao, usuario_nome, servico_catalogo_id, criticidade)
                     VALUES (?, 'preventiva', ?, 'concluida', ?, ?, ?, ?, ?)`,
                    [veiculo_id, item.nome, item.km_ultima || null, item.data_ultima || null, usuario_nome, item.servico_id || null, item.criticidade || 'Media'],
                    err => { if (err) { console.error('Erro inserir historico', err); errorOccurred = true; } }
                );
            }
        });

        db.run('COMMIT', err => {
            if (err || errorOccurred) {
                db.run('ROLLBACK');
                return res.status(500).json({ error: 'Erro ao salvar ediГ§Гөes em massa' });
            }
            res.json({ message: 'EdiГ§Гөes em massa salvas com sucesso' });
        });
    });
});

app.put('/api/frota/manutencoes/em-massa-intervalo-obs', authenticateToken, (req, res) => {
    const { veiculo_id, servicos_ids, intervalo, observacoes } = req.body;
    if (!veiculo_id || !Array.isArray(servicos_ids)) return res.status(400).json({ error: 'veiculo_id e servicos_ids sГЈo obrigatГіrios' });

    db.serialize(() => {
        db.run('BEGIN TRANSACTION');
        let errorOccurred = false;

        servicos_ids.forEach(servico_id => {
            if (errorOccurred) return;
            
            if (intervalo) {
                db.run(
                    `UPDATE frota_servicos_catalogo SET periodicidade_padrao=? WHERE id=?`,
                    [intervalo, servico_id],
                    err => { if (err) { console.error(err); errorOccurred = err.message; } }
                );
            }

            // 2. Atualizar observaГ§Гөes na Гәltima manutenГ§ГЈo concluГӯda deste veГӯculo e serviГ§o
            if (observacoes !== undefined && observacoes !== null && observacoes !== '') {
                db.get('SELECT nome FROM frota_servicos_catalogo WHERE id=?', [servico_id], (errSrv, srv) => {
                    if (errSrv) { console.error(errSrv); errorOccurred = errSrv.message; return; }
                    if (srv && srv.nome) {
                        db.get(
                            `SELECT id FROM frota_manutencoes WHERE veiculo_id=? AND descricao=? AND status='concluida' ORDER BY COALESCE(km_na_manutencao,0) DESC LIMIT 1`,
                            [veiculo_id, srv.nome],
                            (err, row) => {
                                if (err) { console.error(err); errorOccurred = err.message; return; }
                                if (row && row.id) {
                                    db.run(
                                        'UPDATE frota_manutencoes SET observacoes=? WHERE id=?',
                                        [observacoes, row.id],
                                        err2 => { if (err2) { console.error(err2); errorOccurred = err2.message; } }
                                    );
                                }
                            }
                        );
                    }
                });
            }
        });

        // Use setTimeout to allow db.get callbacks to finish (since sqlite3 doesn't support promises natively in this pattern easily without wrapper)
        // A better approach in serialize is just to wait a tick, or use a counter. We'll use a simple timeout for safety in this transaction.
        setTimeout(() => {
            db.run(errorOccurred ? 'ROLLBACK' : 'COMMIT', err => {
                if (err || errorOccurred) return res.status(500).json({ error: 'Erro ao salvar ediГ§Гөes: ' + (errorOccurred || err.message) });
                res.json({ message: 'EdiГ§Гөes salvas com sucesso' });
            });
        }, 1000);
    });
});

// PUT - atualizar manutenГ§ГЈo
app.put('/api/frota/manutencoes/:id', authenticateToken, (req, res) => {
    const { status, descricao, km_na_manutencao, km_proxima_manutencao, data_agendamento, data_conclusao,
            custo, fornecedor, observacoes, tipo, _apenas_intervalo_obs, intervalo_km, data_inicio, tipo_conclusao } = req.body;
    const mId = req.params.id;

    db.get('SELECT * FROM frota_manutencoes WHERE id=?', [mId], (err, row) => {
        if (err || !row) return res.status(404).json({ error: 'ManutenГ§ГЈo nГЈo encontrada' });

        // Modo ediГ§ГЈo rГЎpida: sГі atualiza observaГ§Гөes e km_proxima_manutencao (calculado pelo intervalo)
        if (_apenas_intervalo_obs) {
            // km_ultima Г© passado pelo frontend para calcular corretamente mesmo em registros agendados
            const kmBase = req.body.km_ultima != null ? parseInt(req.body.km_ultima) : (row.km_na_manutencao || 0);
            const novoKmProx = intervalo_km ? (kmBase + parseInt(intervalo_km)) : row.km_proxima_manutencao;
            const novaObs = observacoes !== undefined ? (observacoes || null) : row.observacoes;

            // Atualiza o prГіprio registro (agendado OU concluГӯdo)
            db.run(
                'UPDATE frota_manutencoes SET km_proxima_manutencao=?, observacoes=?, updated_at=CURRENT_TIMESTAMP WHERE id=?',
                [novoKmProx, novaObs, mId],
                (err2) => {
                    if (err2) return res.status(500).json({ error: err2.message });

                    // Se este registro Г© agendado, tambГ©m atualiza o Гәltimo concluГӯdo do mesmo veГӯculo/descriГ§ГЈo
                    // para que o plano preventivo exiba o novo intervalo imediatamente
                    if (row.status === 'agendada' && intervalo_km) {
                        db.run(
                            `UPDATE frota_manutencoes
                             SET km_proxima_manutencao=?, updated_at=CURRENT_TIMESTAMP
                             WHERE veiculo_id=? AND (descricao=? OR servico_catalogo_id=?)
                               AND status='concluida'
                               ORDER BY COALESCE(km_na_manutencao,0) DESC LIMIT 1`,
                            [novoKmProx, row.veiculo_id, row.descricao, row.servico_catalogo_id],
                            () => {} // ignora erro, nГЈo Г© crГӯtico
                        );
                    }

                    res.json({ message: 'ManutenГ§ГЈo atualizada' });
                }
            );
            return;
        }

        // Modo ediГ§ГЈo completa: preserva campos existentes com COALESCE
        // data_agendamento: string vazia = limpar (NULL), undefined = manter, valor = atualizar
        const dataAgValue = data_agendamento === '' ? null
            : data_agendamento !== undefined ? data_agendamento
            : undefined;
        const dataAgSql = dataAgValue === undefined ? 'data_agendamento' : '?';
        const dataAgParam = dataAgValue === undefined ? [] : [dataAgValue];

        db.run(
            `UPDATE frota_manutencoes SET
             tipo=COALESCE(?,tipo), descricao=COALESCE(?,descricao), status=COALESCE(?,status),
             km_na_manutencao=COALESCE(?,km_na_manutencao), km_proxima_manutencao=COALESCE(?,km_proxima_manutencao),
             data_agendamento=${dataAgSql}, data_conclusao=COALESCE(?,data_conclusao),
             custo=COALESCE(?,custo), fornecedor=COALESCE(?,fornecedor),
             observacoes = CASE 
                 WHEN ? IS NULL OR ? = '' THEN observacoes
                 WHEN observacoes IS NULL OR observacoes = '' THEN ?
                 ELSE observacoes || char(10) || char(10) || '--- AtualizaГ§ГЈo ---' || char(10) || ? 
             END,
             data_inicio=COALESCE(?,data_inicio), tipo_conclusao=COALESCE(?,tipo_conclusao),
             updated_at=CURRENT_TIMESTAMP WHERE id=?`,
            [tipo||null, descricao||null, status||null,
             km_na_manutencao !== undefined ? km_na_manutencao : null,
             km_proxima_manutencao !== undefined ? km_proxima_manutencao : null,
             ...dataAgParam,
             data_conclusao !== undefined ? data_conclusao : null,
             custo !== undefined ? custo : null,
             fornecedor||null, 
             observacoes||null, observacoes||null, observacoes||null, observacoes||null,
             data_inicio !== undefined ? data_inicio : null, tipo_conclusao !== undefined ? tipo_conclusao : null, mId],
            (err2) => {
                if (err2) return res.status(500).json({ error: err2.message });

                // Sincronizar status do veГӯculo
                if (status === 'em_andamento') {
                    db.run('UPDATE frota_veiculos SET em_manutencao=1, updated_at=CURRENT_TIMESTAMP WHERE id=?', [row.veiculo_id]);
                } else if (status === 'concluida' || status === 'cancelada') {
                    db.get("SELECT COUNT(*) as cnt FROM frota_manutencoes WHERE veiculo_id=? AND status='em_andamento' AND id!=?",
                        [row.veiculo_id, mId], (e3, r3) => {
                        if (!r3 || r3.cnt === 0) {
                            db.run('UPDATE frota_veiculos SET em_manutencao=0, updated_at=CURRENT_TIMESTAMP WHERE id=?', [row.veiculo_id]);
                        }
                    });
                    if (status === 'concluida' && km_na_manutencao) {
                        db.run('UPDATE frota_veiculos SET km_atual=?, updated_at=CURRENT_TIMESTAMP WHERE id=?', [km_na_manutencao, row.veiculo_id]);
                    }
                }
                res.json({ message: 'ManutenГ§ГЈo atualizada' });
            }
        );
    });
});

