                    if (cargo) detalhe += `<br><span style="color:#64748b;">Cargo: ${cargo}</span>`;
                    if (cpf) detalhe += `<br><span style="color:#64748b;">CPF: ${cpf}</span>`;
                    if (isMotorista && cnh) detalhe += `<br><span style="color:#64748b;">CNH: ${cnh}</span>`;
