// GET PГәblico: Busca dados do credenciamento e resolve os documentos
app.get('/api/publico/credenciamento/:token', (req, res) => {
    const token = req.params.token;
    db.get('SELECT * FROM credenciamentos WHERE token = ?', [token], (err, cred) => {
        if (err) return res.status(500).json({ error: err.message });
        if (!cred) return res.status(404).json({ error: 'Link invГЎlido ou nГЈo encontrado.' });

        const validUntil = new Date(cred.valid_until);
        if (new Date() > validUntil) {
            return res.status(403).json({ error: 'Este link de credenciamento jГЎ expirou (validade de 7 dias).' });
        }

        // Registrar primeiro acesso do cliente
        if (!cred.acessado_em) {
            db.run('UPDATE credenciamentos SET acessado_em = ? WHERE id = ?', [new Date().toISOString(), cred.id], () => {
                if (cred.solicitado_por_id) {
                    db.run("INSERT INTO comercial_notificacoes (usuario_id, mensagem, tipo, dados) VALUES (?, ?, 'credenciamento_acessado', ?)", [cred.solicitado_por_id, `O cliente ${cred.cliente_nome} acessou o link do credenciamento da OS ${cred.os || '-'}.`, JSON.stringify({ cliente_nome: cred.cliente_nome, remetente: 'Cliente' })]);
                }
                if (cred.enviado_por_id && cred.enviado_por_id !== cred.solicitado_por_id) {
                    db.run("INSERT INTO comercial_notificacoes (usuario_id, mensagem, tipo, dados) VALUES (?, ?, 'credenciamento_acessado', ?)", [cred.enviado_por_id, `O cliente ${cred.cliente_nome} acessou o link do credenciamento da OS ${cred.os || '-'}.`, JSON.stringify({ cliente_nome: cred.cliente_nome, remetente: 'Cliente' })]);
                }
            });
        }

        let colabs = [];
        try { colabs = JSON.parse(cred.colaboradores_ids || '[]'); } catch (e) { }
        let veics = [];
        try { veics = JSON.parse(cred.veiculos_ids || '[]'); } catch (e) { }

        // Buscar documentos dos colaboradores
        const colabIds = colabs.map(c => c.id).filter(id => id);
        const colabDocsPromise = new Promise((resolve) => {
            if (colabIds.length === 0) return resolve([]);
            const placeholders = colabIds.map(() => '?').join(',');
            db.all(`SELECT id, colaborador_id, document_type, file_name, file_path, signed_file_path FROM documentos WHERE colaborador_id IN (${placeholders})`, colabIds, (err, docs) => {
                resolve(docs || []);
            });
        });

        // Buscar foto_base64, cpf e cnh dos colaboradores
        const colabFotoPromise = new Promise((resolve) => {
            if (colabIds.length === 0) return resolve([]);
            const placeholders = colabIds.map(() => '?').join(',');
            db.all(`SELECT id, cpf, cnh, foto_base64, foto_path FROM colaboradores WHERE id IN (${placeholders})`, colabIds, (err, rows) => {
                resolve(rows || []);
            });
        });

        // Buscar fichas de EPI ativas (tabela separada)
        const epiPromise = new Promise((resolve) => {
            if (colabIds.length === 0) return resolve([]);
            const placeholders = colabIds.map(() => '?').join(',');
            db.all(`SELECT id, colaborador_id FROM colaborador_epi_fichas WHERE colaborador_id IN (${placeholders}) AND status='ativa' ORDER BY id DESC`, colabIds, (err, rows) => {
                resolve((rows || []).map(r => ({
                    id: r.id,
                    colaborador_id: r.colaborador_id,
                    document_type: 'Ficha de EPI',
                    file_name: `Ficha_EPI_colab${r.colaborador_id}.pdf`,
                    file_path: null,
                    signed_file_path: null,
                    _is_epi_ficha: true
                })));
            });
        });

        // Buscar CRLV dos veГӯculos
        const veicIds = veics.map(v => v.id).filter(id => id);
        const veicDocsPromise = new Promise((resolve) => {
            if (veicIds.length === 0) return resolve([]);
            const placeholders = veicIds.map(() => '?').join(',');
            db.all(`SELECT id, placa, crlv_filename, crlv_base64 FROM frota_veiculos WHERE id IN (${placeholders})`, veicIds, (err, frotas) => {
                resolve(frotas || []);
            });
        });

        // Also fetch licencas file info from DB
        let licencasRaw = [];
        try { licencasRaw = JSON.parse(cred.licencas_ids || '[]'); } catch (e) { }
        const licencaIds = licencasRaw.map(l => l.id).filter(Boolean);
        const licencasDbPromise = new Promise((resolve) => {
            if (licencaIds.length === 0) return resolve([]);
            const ph = licencaIds.map(() => '?').join(',');
            db.all(`SELECT id, file_name FROM licencas WHERE id IN (${ph})`, licencaIds, (err, rows) => resolve(rows || []));
        });

        Promise.all([colabDocsPromise, veicDocsPromise, licencasDbPromise, epiPromise, colabFotoPromise]).then(([docs, frotas, licencasDb, epiDocs, colabFotos]) => {
            // Merge EPI docs with regular docs (deduplicate by colaborador_id - keep only one EPI per collab)
            const docsComEPI = [...docs];
            epiDocs.forEach(ed => {
                // Only add if not already present in documentos table
                if (!docsComEPI.some(d => d.colaborador_id === ed.colaborador_id && (d.document_type || '').toLowerCase().includes('epi'))) {
                    docsComEPI.push(ed);
                }
            });

            // Mapear docs_exigidos (chaves) para nomes reais de documentos
            let docsExigidos = [];
            try { docsExigidos = JSON.parse(cred.docs_exigidos || '[]'); } catch (e) { }

            const docMapPublico = {
                'cnh': ['CNH'],
                'cpf': ['RG-CPF', 'CIN-CPF', 'CPF', 'rg cpf', 'cin cpf'],
                'aso': ['ASO', 'ASO Padrao', 'ASO PadrГЈo', 'Atestado de SaГәde Ocupacional'],
                'ficha_registro': ['Ficha de Registro', 'Ficha Cadastral', 'Ficha de registro'],
                'treinamento': ['Carteira de vacinacao', 'Carteira de vacinaГ§ГЈo', 'Carteira de Vacina', 'vacina'],
                'epi': ['Ficha de EPI Assinada', 'Ficha de EPI', 'ficha epi', 'epi'],
                'contrato_esocial': ['Contrato e-social', 'contrato esocial', 'e-social', 'esocial'],
                'nr1': ['NR1', 'NR 1', 'Ordem de Servico', 'Ordem de ServiГ§o', 'OS', 'ordem servico'],
                'foto_colaborador': ['Foto do Colaborador', 'foto colaborador', 'foto']
            };

            // Verificar se foto foi exigida
            const fotoExigida = docsExigidos.includes('foto_colaborador');

            // Montar conjunto de nomes aceitos (normalizados sem acento)
            const norm = s => (s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().trim();
            const tiposPermitidos = new Set();
            docsExigidos.forEach(chave => {
                (docMapPublico[chave] || []).forEach(nome => tiposPermitidos.add(norm(nome)));
            });

            // FunГ§ГЈo para saber se um documento Г© permitido
            const isApenasDados = docsExigidos.includes('apenas_dados');
            const isPermitido = (d) => {
                if (isApenasDados) return false; // Se for apenas dados, nГЈo envia nenhum documento
                if (tiposPermitidos.size === 0) return true; // se nГЈo hГЎ filtro, libera tudo
                const dn = norm(d.document_type);
                return Array.from(tiposPermitidos).some(acc => dn.includes(acc) || acc.includes(dn));
            };

            // Para cada chave do mapa, retorna qual chave bate num document_type
            const getChaveDoc = (d) => {
                const dn = norm(d.document_type);
                for (const [chave, nomes] of Object.entries(docMapPublico)) {
                    const normNomes = nomes.map(n => norm(n));
                    if (normNomes.some(acc => dn.includes(acc) || acc.includes(dn))) return chave;
                }
                return null;
            };

            res.json({
                cliente_nome: cred.cliente_nome,
                validade: cred.valid_until,
                colaboradores: colabs.map(c => {
                    const row = colabFotos.find(f => String(f.id) === String(c.id));
                    const foto_base64 = fotoExigida ? (row ? row.foto_base64 || null : null) : null;
                    return {
                        ...c,
                        cpf: row ? row.cpf || c.cpf : c.cpf,
                        cnh: row ? row.cnh : null,
                        foto_base64,
                        is_apenas_dados: isApenasDados,
                        documentos: (() => {
                            const filtrados = docsComEPI
                                .filter(d => d.colaborador_id === c.id && isPermitido(d))
                                .map(d => ({
                                    id: d.id,
                                    tipo: d.document_type,
                                    nome_arquivo: d.file_name,
                                    tem_assinado: !!d.signed_file_path,
                                    _chave: getChaveDoc(d),
                                    is_epi: !!d._is_epi_ficha
                                }));
                            // Deduplicar
                            const vistos = new Set();
                            return filtrados.filter(d => {
                                const key = d._chave || d.tipo;
                                if (vistos.has(key)) return false;
                                vistos.add(key);
                                return true;
                            }).map(({ _chave, ...rest }) => rest);
                        })()
                    };
                }),
                veiculos: veics.map(v => {
                    const f = frotas.find(fr => fr.id === v.id);
                    return {
                        ...v,
                        crlv_filename: f ? f.crlv_filename : null,
                        has_crlv: f && !!f.crlv_base64
                    };
                }),
                licencas: licencasRaw.map(l => {
                    const dbRow = licencasDb.find(r => String(r.id) === String(l.id));
                    return { ...l, file_name: dbRow ? dbRow.file_name : null };
                })
            });
        });
    });
});

// GET PГәblico: Baixar documento de colaborador do credenciamento
app.get('/api/publico/credenciamento/:token/doc/:docId', (req, res) => {
    db.get('SELECT * FROM credenciamentos WHERE token = ?', [req.params.token], (err, cred) => {
        if (!cred || new Date() > new Date(cred.valid_until)) return res.status(403).send('Link invГЎlido/expirado');

        db.get('SELECT * FROM documentos WHERE id = ?', [req.params.docId], (err, doc) => {
            if (!doc) return res.status(404).send('Documento nГЈo encontrado');

            // Validar se o doc pertence a um colaborador credenciado
            let colabs = [];
            try { colabs = JSON.parse(cred.colaboradores_ids || '[]'); } catch (e) { }
            if (!colabs.find(c => c.id === doc.colaborador_id)) return res.status(403).send('Acesso negado a este documento');

            const filePath = doc.signed_file_path || doc.file_path;
            const path_module = require('path');
            const fs_module = require('fs');
            const absolutePath = path_module.resolve(__dirname, '..', '..', filePath);

            if (fs_module.existsSync(absolutePath)) {
                res.download(absolutePath, doc.file_name);
            } else {
                res.status(404).send('Arquivo fГӯsico nГЈo encontrado no servidor');
            }
        });
    });
});

// GET PГәblico: Baixar CRLV de veГӯculo do credenciamento
app.get('/api/publico/credenciamento/:token/crlv/:veicId', (req, res) => {
    db.get('SELECT * FROM credenciamentos WHERE token = ?', [req.params.token], (err, cred) => {
        if (!cred || new Date() > new Date(cred.valid_until)) return res.status(403).send('Link invГЎlido/expirado');

        db.get('SELECT crlv_base64, crlv_filename FROM frota_veiculos WHERE id = ?', [req.params.veicId], (err, row) => {
            if (!row || !row.crlv_base64) return res.status(404).send('CRLV nГЈo encontrado');

            let veics = [];
            try { veics = JSON.parse(cred.veiculos_ids || '[]'); } catch (e) { }
            // Nota: JSON parsing converte nГәmeros para int/string. Vamos comparar como string.
            if (!veics.find(v => String(v.id) === String(req.params.veicId))) return res.status(403).send('Acesso negado a este veГӯculo');

            const base64Data = row.crlv_base64.replace(/^data:application\/pdf;base64,/, "");
            const buffer = Buffer.from(base64Data, 'base64');
            res.setHeader('Content-Length', buffer.length);
            res.setHeader('Content-Type', 'application/pdf');
            res.setHeader('Content-Disposition', `attachment; filename="${row.crlv_filename || 'CRLV.pdf'}"`);
            res.send(buffer);
        });
    });
});


// GET PГәblico: Baixar arquivo de licenГ§a do credenciamento
app.get('/api/publico/credenciamento/:token/licenca/:licId', (req, res) => {
    db.get('SELECT * FROM credenciamentos WHERE token = ?', [req.params.token], (err, cred) => {
        if (!cred || new Date() > new Date(cred.valid_until)) return res.status(403).send('Link invГЎlido/expirado');

        // Verificar que a licenГ§a pertence ao credenciamento
        let licencasIds = [];
        try { licencasIds = JSON.parse(cred.licencas_ids || '[]'); } catch (e) { }
        if (!licencasIds.find(l => String(l.id) === String(req.params.licId))) {
            return res.status(403).send('Acesso negado a esta licenГ§a');
        }

        db.get('SELECT * FROM licencas WHERE id = ?', [req.params.licId], (err2, row) => {
            if (err2 || !row) return res.status(404).send('LicenГ§a nГЈo encontrada');
            if (!row.file_path && !row.file_name) return res.status(404).send('Nenhum arquivo anexado a esta licenГ§a');

            let absPath = '';
            if (row.file_path) absPath = path.resolve(__dirname, '..', '..', row.file_path);
            if (!absPath || !fs.existsSync(absPath)) {
                const empresaDir = path.join(LICENCAS_UPLOAD_PATH, (row.empresa || 'GERAL').toUpperCase().replace(/[^A-Z0-9]/g, '_'));
                const finalPath = path.join(empresaDir, row.file_name);
                if (fs.existsSync(finalPath)) absPath = finalPath;
            }
            if (!absPath || !fs.existsSync(absPath)) return res.status(404).send('Arquivo fГӯsico nГЈo encontrado');

            res.setHeader('Content-Type', 'application/pdf');
            res.setHeader('Content-Disposition', 'attachment; filename="' + row.file_name + '"');
            res.sendFile(absPath);
        });
    });
});


// GET PГәblico: Dados da Ficha de EPI (o browser gera o PDF com jsPDF)
app.get('/api/publico/credenciamento/:token/epi/:epiId', (req, res) => {
    db.get('SELECT * FROM credenciamentos WHERE token = ?', [req.params.token], (err, cred) => {
        if (!cred || new Date() > new Date(cred.valid_until)) return res.status(403).json({ error: 'Link invГЎlido/expirado' });

        let colabs = [];
        try { colabs = JSON.parse(cred.colaboradores_ids || '[]'); } catch (e) { }

        db.get('SELECT * FROM colaborador_epi_fichas WHERE id = ?', [req.params.epiId], (err2, ficha) => {
            if (err2 || !ficha) return res.status(404).json({ error: 'Ficha de EPI nГЈo encontrada' });

            const colabInfo = colabs.find(c => String(c.id) === String(ficha.colaborador_id));
            if (!colabInfo) return res.status(403).json({ error: 'Acesso negado' });

            // Buscar dados completos do colaborador
            db.get('SELECT nome_completo, rg, cpf, cargo, departamento, data_admissao FROM colaboradores WHERE id = ?', [ficha.colaborador_id], (err3, colabRow) => {
                // Buscar template de EPI
                db.get('SELECT * FROM epi_templates WHERE id = ?', [ficha.template_id], (err4, template) => {
                    // Buscar entregas assinadas
                    db.all('SELECT * FROM epi_entregas WHERE ficha_id = ? ORDER BY data_entrega ASC', [ficha.id], (err5, entregas) => {
                        const epis = (() => { try { return JSON.parse(ficha.snapshot_epis || '[]'); } catch (e) { return []; } })();
                        const templateEpis = template ? (() => { try { return JSON.parse(template.epis_json || '[]'); } catch (e) { return []; } })() : epis;

                        res.json({
                            ficha: {
                                id: ficha.id,
                                grupo: ficha.grupo,
                                snapshot_termo: ficha.snapshot_termo,
                                snapshot_rodape: ficha.snapshot_rodape,
                                epis: epis.length ? epis : templateEpis
                            },
                            colaborador: colabRow ? {
                                nome: colabRow.nome_completo,
                                rg: colabRow.rg,
                                cpf: colabRow.cpf,
                                cargo: colabRow.cargo,
                                dept: colabRow.departamento,
                                admissao: colabRow.data_admissao
                            } : { nome: colabInfo.nome || 'Colaborador' },
                            entregas: (entregas || []).map(e => ({
                                data: e.data_entrega,
                                descricao: (() => { try { return JSON.parse(e.epis_entregues || '[]').join(', '); } catch (er) { return ''; } })(),
                                assinatura_base64: e.assinatura_base64
                            }))
                        });
                    });
                });
            });
        });
    });
});

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// CLIENTES ITINERANTES вҖ” Endpoint de LocalizaГ§ГЈo Google Maps
// Usa engenharia reversa (cookie-based) para buscar localizaГ§Гөes
// compartilhadas na conta Google do usuГЎrio.
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
app.post('/api/itinerantes/localizacoes', authenticateToken, express.json(), async (req, res) => {
    const { cookies } = req.body;
    if (!Array.isArray(cookies) || cookies.length === 0) {
        return res.status(400).json({ error: 'Cookies invГЎlidos ou ausentes.' });
    }

    try {
        const https = require('https');

        // Filtra apenas cookies do domГӯnio Google
        const cookieStr = cookies
            .filter(c => c.domain && c.domain.includes('google'))
            .map(c => `${c.name}=${c.value}`)
            .join('; ');

        if (!cookieStr) {
            return res.status(400).json({ error: 'Nenhum cookie do Google encontrado. Exporte em maps.google.com.' });
        }

        // Endpoint correto вҖ” usado internamente pelo Google Maps Web (reverse-engineered)
        // A URL com pb= populado retorna os dados de location sharing
        const rawData = await new Promise((resolve, reject) => {
            const urlStr = 'https://www.google.com/maps/rpc/locationsharing/read?authuser=0&hl=pt-BR&gl=BR&pb=!1m7!8m6!1m3!1i14!2i8413!3i5680!2i6!3x4095!2m9!1e0!2sm!3m5!1e0!2b1!5e8!7e41!11e4!3e0&_=1';
            const urlObj = new URL(urlStr);
            const req2 = https.request({
                hostname: urlObj.hostname,
                path: urlObj.pathname + urlObj.search,
                method: 'GET',
                headers: {
                    'Cookie': cookieStr,
                    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36',
                    'Accept': '*/*',
                    'Accept-Language': 'pt-BR,pt;q=0.9,en-US;q=0.8,en;q=0.7',
                    'Referer': 'https://www.google.com/maps/',
                    'X-Requested-With': 'XMLHttpRequest',
                    'sec-fetch-dest': 'empty',
                    'sec-fetch-mode': 'cors',
                    'sec-fetch-site': 'same-origin'
                }
            }, (resp) => {
                // 301/302 = redirecionamento para login = cookies expirados
                if (resp.statusCode === 301 || resp.statusCode === 302) {
                    return resolve({ body: '', status: resp.statusCode });
                }
                let body = '';
                resp.setEncoding('utf8');
                resp.on('data', chunk => body += chunk);
                resp.on('end', () => resolve({ body, status: resp.statusCode }));
            });
            req2.on('error', reject);
            req2.end();
        });

        console.log('[Itinerantes] HTTP status:', rawData.status);
        if (rawData.body) console.log('[Itinerantes] Preview:', rawData.body.substring(0, 200));

        if (rawData.status === 301 || rawData.status === 302 || rawData.status === 401 || rawData.status === 403) {
            return res.status(401).json({ error: 'SessГЈo expirada. Atualize os cookies da sua conta Google.' });
        }

        // O Google retorna prefixo anti-XSS: ")]}',\n" antes do JSON
        let jsonStr = (rawData.body || '').replace(/^\)\]\}'\n?/, '').trim();

        // Se vier HTML = nГЈo estГЎ autenticado
        if (!jsonStr || jsonStr.startsWith('<')) {
            console.error('[Itinerantes] Google retornou HTML вҖ” cookies invГЎlidos.');
            return res.status(401).json({ error: 'SessГЈo invГЎlida. Exporte os cookies novamente em guia anГҙnima logada em maps.google.com.' });
        }

        if (!jsonStr.startsWith('[')) {
            const firstBracket = jsonStr.indexOf('[');
            if (firstBracket >= 0) jsonStr = jsonStr.substring(firstBracket);
            else return res.status(502).json({ error: 'Resposta inesperada do Google.', debug: jsonStr.substring(0, 100) });
        }

        let parsed;
        try {
            parsed = JSON.parse(jsonStr);
        } catch (e) {
            console.error('[Itinerantes] Falha ao parsear resposta do Google:', jsonStr.substring(0, 300));
            return res.status(502).json({ error: 'Resposta invГЎlida do Google. Os cookies podem ter expirado.' });
        }

        // Estrutura do Google Location Sharing: parsed[0] Г© array de pessoas/devices
        const pessoas = Array.isArray(parsed[0]) ? parsed[0] : [];

        const tags = pessoas.map(p => {
            try {
                // p[0][0] = ID da pessoa
                // p[0][1] = Nome
                // p[0][6][1] = URL da foto de perfil
                // p[1][0] = Latitude * 1e-7
                // p[1][1] = Longitude * 1e-7
                // p[1][2] = PrecisГЈo em metros
                // p[1][6] = Timestamp da Гәltima atualizaГ§ГЈo (ms)
                // p[1][4] = EndereГ§o/localizaГ§ГЈo textual
                // p[1][3] = NГӯvel de bateria (0-4 aprox) вҖ” ou null
                const nome = p[0]?.[1] || p[0]?.[3] || 'Desconhecido';
                const photoUrl = p[0]?.[6]?.[1] || null;
                const lat = p[1]?.[0] ? p[1][0] / 1e7 : null;
                const lng = p[1]?.[1] ? p[1][1] / 1e7 : null;
                const timestamp = p[1]?.[6] ? parseInt(p[1][6]) : null;
                const endereco = p[1]?.[4] || null;
                const bateriaRaw = p[1]?.[3];
                const bateria = (bateriaRaw !== null && bateriaRaw !== undefined) ? Math.round(bateriaRaw * 25) : null;

                return { nome, photoUrl, lat, lng, timestamp, endereco, bateria };
            } catch (e) {
                return null;
            }
        }).filter(Boolean).filter(t => t.lat !== null && t.lng !== null);

        // Se nГЈo encontrou tags, devolve a estrutura bruta para diagnГіstico
        const debugInfo = tags.length === 0 ? {
            rawLength: Array.isArray(parsed) ? parsed.length : 'nГЈo Г© array',
            nivel0: Array.isArray(parsed[0]) ? `array com ${parsed[0].length} itens` : typeof parsed[0],
            nivel1: Array.isArray(parsed[1]) ? `array com ${parsed[1].length} itens` : typeof parsed[1],
            nivel2: Array.isArray(parsed[2]) ? `array com ${parsed[2].length} itens` : typeof parsed[2],
            nivel3: Array.isArray(parsed[3]) ? `array com ${parsed[3].length} itens` : typeof parsed[3],
            rawPreview: JSON.stringify(parsed).substring(0, 500)
        } : null;

        console.log('[Itinerantes] Tags encontradas:', tags.length, debugInfo ? '| Debug:' + JSON.stringify(debugInfo).substring(0, 200) : '');

        res.json({ tags, total: tags.length, atualizado: new Date().toISOString(), debug: debugInfo });

    } catch (err) {
        console.error('[Itinerantes] Erro:', err);
        res.status(500).json({ error: 'Erro interno ao buscar localizaГ§Гөes: ' + err.message });
    }
});

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
