// GET вҖ“ lista cards do mГӘs
app.get('/api/logistica/agenda', authenticateToken, (req, res) => {
    const { ano, mes, setor, inicio, fim } = req.query;
    let where = '1=1';
    const params = [];
    if (inicio && fim) {
        where += ' AND data >= ? AND data <= ?';
        params.push(inicio, fim);
    } else if (ano && mes) {
        const anoN = parseInt(ano), mesN = parseInt(mes);
        const dInicio = `${anoN}-${String(mesN).padStart(2, '0')}-01`;
        const dFim = `${anoN}-${String(mesN).padStart(2, '0')}-31`;
        where += ' AND data >= ? AND data <= ?';
        params.push(dInicio, dFim);
    }
    const reqContext = req.query.context || 'logistica';
    if (setor) { where += ' AND setor = ?'; params.push(setor); } else { where += ' AND setor IN ("logistica", "rh")'; }
    db.all(`SELECT * FROM logistica_agenda WHERE ${where} ORDER BY data, id`, params, (err, rawRows) => {
        if (err) return res.status(500).json({ error: err.message });
        db.all(`SELECT id, departamento FROM colaboradores`, [], (errDept, allColabs) => {
            const deptMap = {};
            (allColabs || []).forEach(c => deptMap[c.id] = c.departamento);
            const opSectors = ['Ajudante Geral', 'Ajudante PГЎtio', 'LideranГ§a', 'LogГӯstica', 'ManutenГ§ГЈo', 'Motorista'];
            let rows = [];
            const seenManual = new Set();
            (rawRows || []).forEach(card => {
                let isVisible = true;
                if (reqContext === 'rh' && card.setor === 'logistica') {
                    isVisible = false;
                    try {
                        const refs = JSON.parse(card.referente_ids || '[]');
                        if (refs.some(id => opSectors.includes(deptMap[id]))) isVisible = true;
                    } catch(e){}
                } else if (reqContext === 'logistica' && card.setor === 'rh') {
                    isVisible = false;
                    try {
                        const refs = JSON.parse(card.referente_ids || '[]');
                        if (refs.some(id => opSectors.includes(deptMap[id]))) isVisible = true;
                    } catch(e){}
                }
                if (isVisible) {
                    let isDuplicate = false;
                    try {
                        const refs = JSON.parse(card.referente_ids || '[]');
                        if (refs.length > 0) {
                            let allSeen = true;
                            refs.forEach(ref => {
                                const key = `${card.tipo}_${card.data}_${ref}`;
                                if (!seenManual.has(key)) { allSeen = false; seenManual.add(key); }
                            });
                            if (allSeen) isDuplicate = true;
                        }
                    } catch(e){}
                    if (!isDuplicate) rows.push(card);
                }
            });
            const deptFilter = reqContext === 'rh' ? '' : "AND departamento NOT IN ('ESCRITГ“RIO', 'RH', 'Comercial', 'Financeiro', 'Administrativo', 'Diretoria')";
            const deptFilterC = reqContext === 'rh' ? '' : "AND c.departamento NOT IN ('ESCRITГ“RIO', 'RH', 'Comercial', 'Financeiro', 'Administrativo', 'Diretoria')";
        db.all(`SELECT id, nome_completo, ferias_programadas_inicio, ferias_programadas_fim FROM colaboradores WHERE status IN ('Ativo', 'Afastado', 'FГ©rias') ${deptFilter} AND ferias_programadas_inicio IS NOT NULL AND ferias_programadas_fim IS NOT NULL AND ferias_programadas_inicio != ''`, [], (errColab, colabs) => {
            if (errColab) return res.json(rows || []);

            const feriasCards = [];
            (colabs || []).forEach(c => {
                let current = new Date(c.ferias_programadas_inicio + 'T12:00:00');
                const end = new Date(c.ferias_programadas_fim + 'T12:00:00');
                if (isNaN(current.getTime()) || isNaN(end.getTime())) return;

                while (current <= end) {
                    const dataStr = current.toISOString().split('T')[0];
                    feriasCards.push({
                        id: 'f_' + c.id + '_' + dataStr,
                        is_auto: true,
                        data: dataStr,
                        tipo: 'ferias',
                        titulo: 'FГ©rias: ' + c.nome_completo.split(' ')[0],
                        descricao: 'PerГӯodo de fГ©rias agendado para ' + c.nome_completo,
                        horario: '',
                        setor: 'logistica',
                        responsaveis: '[]',
                        referente_ids: '[]',
                        acoes: '[]'
                    });
                    current.setDate(current.getDate() + 1);
                }
            });

            db.all(`SELECT d.colaborador_id, d.atestado_inicio, d.atestado_fim, c.nome_completo 
                    FROM documentos d 
                    JOIN colaboradores c ON d.colaborador_id = c.id
                    WHERE d.tab_name = 'Atestados' 
                    AND d.atestado_tipo = 'dias'
                    AND d.atestado_inicio IS NOT NULL 
                    AND d.atestado_fim IS NOT NULL
                    AND c.status IN ('Ativo', 'Afastado', 'FГ©rias') ${deptFilterC}`, [], (errAtest, atestados) => {

                const afastadoCards = [];
                if (!errAtest) {
                    (atestados || []).forEach(a => {
                        let current = new Date(a.atestado_inicio + 'T12:00:00');
                        const end = new Date(a.atestado_fim + 'T12:00:00');
                        if (isNaN(current.getTime()) || isNaN(end.getTime())) return;

                        while (current <= end) {
                            const dataStr = current.toISOString().split('T')[0];
                            afastadoCards.push({
                                id: 'a_' + a.colaborador_id + '_' + dataStr,
                                is_auto: true,
                                data: dataStr,
                                tipo: 'afastado',
                                titulo: 'Afastado: ' + a.nome_completo.split(' ')[0],
                                descricao: 'Afastamento mГ©dico para ' + a.nome_completo,
                                horario: '',
                                setor: 'logistica',
                                responsaveis: '[]',
                                referente_ids: '[]',
                                acoes: '[]'
                            });
                            current.setDate(current.getDate() + 1);
                        }
                    });
                }

                db.all(`SELECT id, nome_completo, aso_exame_data FROM colaboradores WHERE status IN ('Ativo', 'Afastado', 'FГ©rias') ${deptFilter} AND aso_exame_data IS NOT NULL AND aso_exame_data != ''`, [], (errAso, asoColabs) => {
                    const asoCards = [];
                    if (!errAso) {
                        (asoColabs || []).forEach(c => {
                            // aso_exame_data is DD/MM/YYYY
                            const [d, m, y] = c.aso_exame_data.split('/');
                            if (d && m && y) {
                                const dataStr = `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
                                asoCards.push({
                                    id: 'aso_' + c.id + '_' + dataStr,
                                    is_auto: true,
                                    data: dataStr,
                                    tipo: 'aso',
                                    titulo: 'ASO: ' + c.nome_completo.split(' ')[0],
                                    descricao: 'Exame ASO agendado para ' + c.nome_completo,
                                    horario: '',
                                    setor: 'logistica',
                                    responsaveis: '[]',
                                    referente_ids: JSON.stringify([c.id]),
                                    acoes: '[]'
                                });
                            }
                        });
                    }

                    // Faltas de colaboradores operacionais
                    db.all(`SELECT f.colaborador_id, f.data_falta, f.turno, c.nome_completo
                            FROM faltas f
                            JOIN colaboradores c ON f.colaborador_id = c.id
                            WHERE c.status IN ('Ativo', 'Afastado', 'FГ©rias') ${deptFilterC}`, [], (errFaltas, faltasRows) => {
                        const faltaCards = [];
                        if (!errFaltas) {
                            (faltasRows || []).forEach(f => {
                                if (f.data_falta) {
                                    faltaCards.push({
                                        id: 'falta_' + f.colaborador_id + '_' + f.data_falta,
                                        is_auto: true,
                                        data: f.data_falta,
                                        tipo: 'falta',
                                        titulo: 'Falta: ' + f.nome_completo.split(' ')[0],
                                        descricao: 'Falta registrada para ' + f.nome_completo + (f.turno ? ' - ' + f.turno : ''),
                                        horario: '',
                                        setor: 'logistica',
                                        responsaveis: '[]',
                                        referente_ids: '[]',
                                        acoes: '[]'
                                    });
                                }
                            });
                        }
                        // Deduplicar: nГЈo mostrar auto-card de falta se jГЎ existe card manual na agenda para o mesmo colaborador e data
                        const faltaKeysManuais = new Set();
                        (rows || []).forEach(card => {
                            if (card.tipo === 'falta') {
                                try {
                                    const refs = JSON.parse(card.referente_ids || '[]');
                                    refs.forEach(cid => faltaKeysManuais.add(String(cid) + '_' + card.data));
                                } catch (e) { }
                            }
                        });
                        const faltaCardsDedup = faltaCards.filter(fc => {
                            // fc.id formato: 'falta_COLABID_DATE'
                            const parts = (fc.id || '').split('_');
                            if (parts.length >= 3) {
                                const key = parts[1] + '_' + parts[2];
                                return !faltaKeysManuais.has(key);
                            }
                            return true;
                        });
                        res.json([...(rows || []), ...feriasCards, ...afastadoCards, ...asoCards, ...faltaCardsDedup]);
                    });
                });
            });
        });
    });
});
        });

// GET вҖ“ Escala operacional: retorna colaboradores ativos do operacional com dados de escala e ausГӘncias no perГӯodo
app.get('/api/logistica/escala', authenticateToken, (req, res) => {
    const { inicio, fim } = req.query;
    if (!inicio || !fim) return res.status(400).json({ error: 'Informe inicio e fim.' });

    const DEPTS_EXCLUIDOS = ['ESCRITГ“RIO', 'RH', 'Comercial', 'Financeiro', 'Administrativo', 'Diretoria'];
    const excStr = DEPTS_EXCLUIDOS.map(() => '?').join(',');

    db.all(`SELECT id, nome_completo, cargo, departamento, foto_base64, foto_path, aso_exame_data,
                   escala_tipo, escala_folgas, escala_ciclo_inicio, horario_entrada, horario_saida, status
            FROM colaboradores WHERE status IN ('Ativo','Afastado','FГ©rias')
            AND departamento NOT IN (${excStr})
            AND (tipo_contrato IS NULL OR tipo_contrato != 'Intermitente')
            ORDER BY nome_completo`, DEPTS_EXCLUIDOS, (err, colabs) => {
        if (err) return res.status(500).json({ error: err.message });

        // Coletar ausГӘncias no perГӯodo (fГ©rias, atestados, faltas)
        const promises = [];

        // FГ©rias
        promises.push(new Promise(resolve => {
            const ids = (colabs || []).map(c => c.id);
            if (!ids.length) return resolve([]);
            const ph = ids.map(() => '?').join(',');
            db.all(`SELECT id, ferias_programadas_inicio, ferias_programadas_fim, ferias_fracionadas, ferias_fracionadas_tipo, ferias_fracionadas_inicio2, ferias_fracionadas_fim2 FROM colaboradores
                    WHERE id IN (${ph})`, ids, (e, rows) => {
                const ausFeriasSet = {};
                (rows || []).forEach(r => {
                    const addFerias = (inicio, fim) => {
                        if (!inicio || !fim) return;
                        let dStart = inicio;
                        if (dStart.includes('/')) { const p = dStart.split('/'); dStart = `${p[2]}-${p[1]}-${p[0]}`; }
                        let dEnd = fim;
                        if (dEnd.includes('/')) { const p = dEnd.split('/'); dEnd = `${p[2]}-${p[1]}-${p[0]}`; }
                        
                        let cur = new Date(dStart + 'T12:00:00');
                        const end = new Date(dEnd + 'T12:00:00');
                        if (isNaN(cur.getTime()) || isNaN(end.getTime())) return;
                        
                        while (cur <= end) {
                            const d = cur.toISOString().split('T')[0];
                            if (!ausFeriasSet[r.id]) ausFeriasSet[r.id] = {};
                            ausFeriasSet[r.id][d] = 'ferias';
                            cur.setDate(cur.getDate() + 1);
                        }
                    };

                    addFerias(r.ferias_programadas_inicio, r.ferias_programadas_fim);
                    if (r.ferias_fracionadas === 'Sim' && r.ferias_fracionadas_tipo === 'Tirada') {
                        addFerias(r.ferias_fracionadas_inicio2, r.ferias_fracionadas_fim2);
                    }
                });
                resolve(ausFeriasSet);
            });
        }));

        // Atestados
        promises.push(new Promise(resolve => {
            const ids = (colabs || []).map(c => c.id);
            if (!ids.length) return resolve([]);
            const ph = ids.map(() => '?').join(',');
            db.all(`SELECT colaborador_id, atestado_inicio, atestado_fim FROM documentos
                    WHERE colaborador_id IN (${ph}) 
                    AND (tab_name LIKE '%ATESTADO%' OR document_type LIKE '%Atestado%' OR tab_name = 'Atestados')
                    AND atestado_inicio IS NOT NULL AND atestado_fim IS NOT NULL`, ids, (e, rows) => {
                const ausAtestSet = {};
                (rows || []).forEach(r => {
                    if (!r.atestado_inicio || !r.atestado_fim) return;
                    let cur = new Date(r.atestado_inicio + 'T12:00:00');
                    const end = new Date(r.atestado_fim + 'T12:00:00');
                    while (cur <= end) {
                        const d = cur.toISOString().split('T')[0];
                        if (!ausAtestSet[r.colaborador_id]) ausAtestSet[r.colaborador_id] = {};
                        ausAtestSet[r.colaborador_id][d] = 'afastado';
                        cur.setDate(cur.getDate() + 1);
                    }
                });
                resolve(ausAtestSet);
            });
        }));

        // Faltas
        promises.push(new Promise(resolve => {
            const ids = (colabs || []).map(c => c.id);
            if (!ids.length) return resolve([]);
            const ph = ids.map(() => '?').join(',');
            db.all(`SELECT colaborador_id, data_falta FROM faltas
                    WHERE colaborador_id IN (${ph}) AND data_falta >= ? AND data_falta <= ?`,
                [...ids, inicio, fim], (e, rows) => {
                    const ausFaltasSet = {};
                    (rows || []).forEach(r => {
                        if (!ausFaltasSet[r.colaborador_id]) ausFaltasSet[r.colaborador_id] = {};
                        ausFaltasSet[r.colaborador_id][r.data_falta] = 'falta';
                    });
                    resolve(ausFaltasSet);
                });
        }));

        // Terapias e ausГӘncias registradas na agenda manual (logistica_agenda)
        promises.push(new Promise(resolve => {
            const ids = (colabs || []).map(c => c.id);
            if (!ids.length) return resolve({});
            db.all(`SELECT referente_ids, tipo, data FROM logistica_agenda
                    WHERE data >= ? AND data <= ? AND tipo IN ('terapia','falta','afastado','ferias')`,
                [inicio, fim], (e, rows) => {
                    const agSet = {}; // id -> { data -> tipo }
                    (rows || []).forEach(r => {
                        try {
                            const refs = JSON.parse(r.referente_ids || '[]');
                            refs.forEach(rid => {
                                const idNum = Number(rid);
                                if (!ids.includes(idNum)) return;
                                if (!agSet[idNum]) agSet[idNum] = {};
                                const prev = agSet[idNum][r.data];
                                // Prioridade: falta > afastado > ferias > terapia
                                const prio = { falta: 4, afastado: 3, ferias: 2, terapia: 1 };
                                if (!prev || (prio[r.tipo] || 0) > (prio[prev] || 0)) {
                                    agSet[idNum][r.data] = r.tipo;
                                }
                            });
                        } catch(ex) {}
                    });
                    resolve(agSet);
                });
        }));

        Promise.all(promises).then(([ferSet, atestSet, faltSet, agendaSet]) => {
            // Gerar lista de datas no range
            const datas = [];
            let cur = new Date(inicio + 'T12:00:00');
            const endDate = new Date(fim + 'T12:00:00');
            while (cur <= endDate) {
                datas.push(cur.toISOString().split('T')[0]);
                cur.setDate(cur.getDate() + 1);
            }

            // Para cada colaborador, calcular disponibilidade por dia
            const result = (colabs || []).map(c => {
                const asoData = {};
                if (c.aso_exame_data) {
                    const [d, m, y] = c.aso_exame_data.split('/');
                    if (d && m && y) asoData[`${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`] = 'aso';
                }
                const ausencias = { ...asoData, ...((faltSet || {})[c.id] || {}), ...((atestSet || {})[c.id] || {}), ...((ferSet || {})[c.id] || {}), ...((agendaSet || {})[c.id] || {}) };

                // Parse da escala
                const escalaStr = (c.escala_tipo || '').toLowerCase();
                const folgas = (c.escala_folgas || '').toLowerCase();

                // Mapeamento de nome do dia вҶ’ getDay() index (0=Dom)
                const DIA_MAP = {
                    'dom': 0, 'domingo': 0,
                    'seg': 1, 'segunda': 1,
                    'ter': 2, 'terГ§a': 2, 'terca': 2,
                    'qua': 3, 'quarta': 3,
                    'qui': 4, 'quinta': 4,
                    'sex': 5, 'sexta': 5,
                    'sГЎb': 6, 'sab': 6, 'sabado': 6, 'sГЎbado': 6
                };

                // Dias de folga explГӯcitos cadastrados (campo escala_folgas Г© JSON array ex: ["Qua"])
                let folgasExplicitas = [];
                try {
                    const parsed = JSON.parse(c.escala_folgas || '[]');
                    folgasExplicitas = Array.isArray(parsed)
                        ? parsed.map(f => String(f).trim().toLowerCase())
                        : [String(parsed).trim().toLowerCase()];
                } catch (e) {
                    folgasExplicitas = (c.escala_folgas || '').split(/[,;]+/).map(f => f.trim().toLowerCase()).filter(Boolean);
                }
                const folgasDow = folgasExplicitas.map(f => DIA_MAP[f]).filter(v => v !== undefined);

                // в”Җв”Җ LГ“GICA DOMINGO DE LEI в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                // Ciclo: domingo 0 = trabalha, 1 = trabalha, 2 = FOLGA, 3 = trabalha...
                const temCiclo = c.escala_ciclo_inicio && (escalaStr.includes('uma_folga') || escalaStr.includes('duas_folgas') || escalaStr.includes('folga'));
                const cicloBase = temCiclo ? new Date(c.escala_ciclo_inicio + 'T12:00:00') : null;

                // ГҚndice do 1Вә dia fixo de folga (para Tipo B: Г© o 1Вә dia que "cede" ao domingo de lei, virando trabalho)
                const ultimoFolgaDow = folgasDow.length >= 2 ? folgasDow[0] : null;

                const isDomingoDeLei = (dateStr) => {
                    if (!temCiclo || !cicloBase) return false;
                    const d = new Date(dateStr + 'T12:00:00');
                    if (d.getDay() !== 0) return false; // sГі testa domingos
                    // Contar quantos domingos desde o ciclo_inicio
                    const diffMs = d - cicloBase;
                    if (diffMs < 0) return false; // antes do ciclo
                    const diffDias = Math.round(diffMs / (1000 * 60 * 60 * 24));
                    const nDomingo = Math.round(diffDias / 7);
                    return nDomingo % 3 === 2; // 0=trab, 1=trab, 2=folga, 3=trab...
                };

                const getFolga = (dateStr) => {
                    const d = new Date(dateStr + 'T12:00:00');
                    const dow = d.getDay(); // 0=dom, 1=seg..6=sab

                    // в”Җв”Җ 12x36: ciclo alternado (dia trabalha / dia folga) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                    if (escalaStr.includes('12x36')) {
                        if (c.escala_ciclo_inicio) {
                            const ciclo12 = new Date(c.escala_ciclo_inicio + 'T12:00:00');
                            const diffMs = d - ciclo12;
                            if (diffMs < 0) return false; // antes do inГӯcio do ciclo: disponГӯvel
                            const diffDias = Math.round(diffMs / (1000 * 60 * 60 * 24));
                            return diffDias % 2 === 1; // par = trabalha, Гӯmpar = folga (36h)
                        }
                        return false; // sem data de referГӘncia: sempre disponГӯvel
                    }

                    // в”Җв”Җ Verificar Domingo de Lei в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                    if (dow === 0 && isDomingoDeLei(dateStr)) {
                        return true; // domingo Г© folga
                    }

                    // в”Җв”Җ Para Tipo B (2 folgas): na semana do domingo de lei,
                    //    o Гәltimo dia fixo de folga vira trabalho (compensaГ§ГЈo)
                    if (ultimoFolgaDow !== null && dow === ultimoFolgaDow) {
                        // Calcular se o domingo desta semana Г© Domingo de Lei
                        const thisSunday = new Date(dateStr + 'T12:00:00');
                        thisSunday.setDate(thisSunday.getDate() - dow); // retrocede ao domingo da semana
                        const thisSundayStr = thisSunday.toISOString().split('T')[0];
                        if (isDomingoDeLei(thisSundayStr)) {
                            return false; // o 2Вә dia fixo TRABALHA nesta semana (domingo folga)
                        }
                    }

                    // в”Җв”Җ Folgas fixas do cadastro в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                    if (escalaStr.includes('escala_uma_folga') || escalaStr.includes('escala_duas_folgas')) {
                        if (folgasDow.length > 0) {
                            return folgasDow.includes(dow);
                        }
                    }

                    // в”Җв”Җ Fallback por tipo de escala в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                    if (escalaStr.includes('sab_alternado') || escalaStr.includes('sabado_alternado')) {
                        if (dow === 0) return true; // domingo Г© folga fixa
                        if (dow === 6 && c.escala_ciclo_inicio) {
                            // Contar quantos sГЎbados desde o sГЎbado de referГӘncia
                            const sabRef = new Date(c.escala_ciclo_inicio + 'T12:00:00');
                            const d = new Date(dateStr + 'T12:00:00');
                            const diffMs = d - sabRef;
                            if (diffMs < 0) return false; // antes da referГӘncia
                            const diffSemanas = Math.round(diffMs / (1000 * 60 * 60 * 24 * 7));
                            return diffSemanas % 2 === 1; // 0=trabalha, 1=folga, 2=trabalha...
                        }
                        return false; // dias de semana: nunca folga por esta regra
                    }
                    if (escalaStr.includes('seg_sexta') || escalaStr.includes('5x2') || escalaStr.includes('5 x 2')) {
                        return dow === 0 || dow === 6;
                    }
                    if (escalaStr.includes('6x1') || escalaStr.includes('6 x 1')) {
                        return dow === 0;
                    }
                    return dow === 0; // padrГЈo
                };

                const diasInfo = datas.map(data => {
                    const ausencia = ausencias[data] || null;
                    const folga = getFolga(data);
                    let status = 'disponivel';
                    if (folga) status = 'folga';
                    if (ausencia) status = ausencia;
                    return { data, status };
                });

                return {
                    id: c.id,
                    nome_completo: c.nome_completo,
                    cargo: c.cargo,
                    departamento: c.departamento,
                    foto_base64: c.foto_base64,
                    foto_path: c.foto_path,
                    horario_entrada: c.horario_entrada,
                    horario_saida: c.horario_saida,
                    escala_tipo: c.escala_tipo,
                    escala_ciclo_inicio: c.escala_ciclo_inicio || null,
                    dias: diasInfo
                };
            });

            res.json(result);
        }).catch(e => res.status(500).json({ error: e.message }));
    });
});

// -- GET /api/rh/escala -- Escala RH (Operacional + Administrativo)
app.get('/api/rh/escala', authenticateToken, (req, res) => {
    const { inicio, fim } = req.query;
    if (!inicio || !fim) return res.status(400).json({ error: 'Informe inicio e fim.' });
    const INCL = ['Administrativo', 'Comercial', 'Financeiro', 'Limpeza', 'LogГӯstica', 'ManutenГ§ГЈo', 'RH', 'SupervisГЈo', 'Ajudante Geral', 'Ajudante PГЎtio', 'LideranГ§a', 'Motorista'];
    const incStr = INCL.map(() => '?').join(',');
    db.all(`SELECT id, nome_completo, cargo, departamento, foto_base64, foto_path, aso_exame_data,
                   escala_tipo, escala_folgas, escala_ciclo_inicio, horario_entrada, horario_saida, status
            FROM colaboradores WHERE status IN ('Ativo','Afastado','FГ©rias')
            AND departamento IN (${incStr})
            AND (tipo_contrato IS NULL OR tipo_contrato != 'Intermitente')
            ORDER BY nome_completo ASC`, INCL, (err, colabs) => {
        if (err) return res.status(500).json({ error: err.message });
        const ids = (colabs || []).map(c => c.id);
        if (!ids.length) return res.json([]);
        const ph = ids.map(() => '?').join(',');

        const p1 = new Promise(resolve => {
            db.all(`SELECT id, ferias_programadas_inicio, ferias_programadas_fim, ferias_fracionadas, ferias_fracionadas_tipo, ferias_fracionadas_inicio2, ferias_fracionadas_fim2 FROM colaboradores
                    WHERE id IN (${ph})`, ids, (e, rows) => {
                const s = {};
                (rows||[]).forEach(r => {
                    const addFerias = (inicio, fim) => {
                        if (!inicio || !fim) return;
                        let dStart = inicio;
                        if (dStart.includes('/')) { const p = dStart.split('/'); dStart = `${p[2]}-${p[1]}-${p[0]}`; }
                        let dEnd = fim;
                        if (dEnd.includes('/')) { const p = dEnd.split('/'); dEnd = `${p[2]}-${p[1]}-${p[0]}`; }
                        
                        let cur = new Date(dStart + 'T12:00:00');
                        const end = new Date(dEnd + 'T12:00:00');
                        if (isNaN(cur.getTime()) || isNaN(end.getTime())) return;
                        
                        while (cur <= end) {
                            const d = cur.toISOString().split('T')[0];
                            if (!s[r.id]) s[r.id] = {};
                            s[r.id][d] = 'ferias';
                            cur.setDate(cur.getDate() + 1);
                        }
                    };

                    addFerias(r.ferias_programadas_inicio, r.ferias_programadas_fim);
                    if (r.ferias_fracionadas === 'Sim' && r.ferias_fracionadas_tipo === 'Tirada') {
                        addFerias(r.ferias_fracionadas_inicio2, r.ferias_fracionadas_fim2);
                    }
                });
                resolve(s);
            });
        });

        const p2 = new Promise(resolve => {
            db.all(`SELECT colaborador_id, atestado_inicio, atestado_fim FROM documentos
                    WHERE colaborador_id IN (${ph})
                    AND (tab_name LIKE '%ATESTADO%' OR document_type LIKE '%Atestado%' OR tab_name='Atestados')
                    AND atestado_inicio IS NOT NULL AND atestado_fim IS NOT NULL`, ids, (e, rows) => {
                const s = {};
                (rows||[]).forEach(r => {
                    let cur = new Date(r.atestado_inicio + 'T12:00:00');
                    const end = new Date(r.atestado_fim + 'T12:00:00');
                    while (cur <= end) { const d = cur.toISOString().split('T')[0]; if (!s[r.colaborador_id]) s[r.colaborador_id]={}; s[r.colaborador_id][d]='afastado'; cur.setDate(cur.getDate()+1); }
                });
                resolve(s);
            });
        });

        const p3 = new Promise(resolve => {
            db.all(`SELECT colaborador_id, data_falta FROM faltas
                    WHERE colaborador_id IN (${ph}) AND data_falta >= ? AND data_falta <= ?`,
                [...ids, inicio, fim], (e, rows) => {
                    const s = {};
                    (rows||[]).forEach(r => { if (!s[r.colaborador_id]) s[r.colaborador_id]={}; s[r.colaborador_id][r.data_falta]='falta'; });
                    resolve(s);
                });
        });

        // Terapias e ausГӘncias registradas manualmente na agenda logistica
        const p4 = new Promise(resolve => {
            db.all(`SELECT referente_ids, tipo, data FROM logistica_agenda
                    WHERE data >= ? AND data <= ? AND tipo IN ('terapia','falta','afastado','ferias')`,
                [inicio, fim], (e, rows) => {
                    const s = {}; // id -> { data -> tipo }
                    const prio = { falta: 4, afastado: 3, ferias: 2, terapia: 1 };
                    (rows || []).forEach(r => {
                        try {
                            const refs = JSON.parse(r.referente_ids || '[]');
                            refs.forEach(rid => {
                                const idNum = Number(rid);
                                if (!s[idNum]) s[idNum] = {};
                                const prev = s[idNum][r.data];
                                if (!prev || (prio[r.tipo] || 0) > (prio[prev] || 0)) {
                                    s[idNum][r.data] = r.tipo;
                                }
                            });
                        } catch(ex) {}
                    });
                    resolve(s);
                });
        });

        Promise.all([p1, p2, p3, p4]).then(([ferSet, atestSet, faltSet, agendaSet]) => {
            const datas = [];
            let cur = new Date(inicio + 'T12:00:00');
            const endD = new Date(fim + 'T12:00:00');
            while (cur <= endD) { datas.push(cur.toISOString().split('T')[0]); cur.setDate(cur.getDate()+1); }

            const DM = { 'dom':0,'domingo':0,'seg':1,'segunda':1,'ter':2,'terca':2,'qua':3,'quarta':3,'qui':4,'quinta':4,'sex':5,'sexta':5,'sab':6,'sabado':6 };

            const result = (colabs || []).map(c => {
                const asoD = {};
                if (c.aso_exame_data) { const [d,m,y] = c.aso_exame_data.split('/'); if(d&&m&&y) asoD[`${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`]='aso'; }
                const aus = { ...asoD, ...((faltSet||{})[c.id]||{}), ...((atestSet||{})[c.id]||{}), ...((ferSet||{})[c.id]||{}), ...((agendaSet||{})[c.id]||{}) };
                const escStr = (c.escala_tipo||'').toLowerCase();
                let fE = [];
                try { const p = JSON.parse(c.escala_folgas||'[]'); fE = Array.isArray(p) ? p.map(f=>String(f).trim().toLowerCase()) : [String(p).trim().toLowerCase()]; }
                catch(e) { fE = (c.escala_folgas||'').split(/[,;]+/).map(f=>f.trim().toLowerCase()).filter(Boolean); }
                const fDow = fE.map(f=>DM[f]).filter(v=>v!==undefined);
                const temC = c.escala_ciclo_inicio && (escStr.includes('uma_folga')||escStr.includes('duas_folgas')||escStr.includes('folga'));
                const cicB = temC ? new Date(c.escala_ciclo_inicio+'T12:00:00') : null;
                const ult = fDow.length >= 2 ? fDow[0] : null;
                const isDDL = (ds) => {
                    if (!temC||!cicB) return false;
                    const dd = new Date(ds+'T12:00:00'); if (dd.getDay()!==0) return false;
                    const diff = Math.round((dd-cicB)/86400000); if (diff<0) return false;
                    return Math.round(diff/7)%3===2;
                };
                const getF = (ds) => {
                    const dd = new Date(ds+'T12:00:00'); const dow = dd.getDay();
                    if (escStr.includes('12x36')) { if (c.escala_ciclo_inicio) { const c12=new Date(c.escala_ciclo_inicio+'T12:00:00'); const dif=Math.round((dd-c12)/86400000); if(dif<0)return false; return dif%2===1; } return false; }
                    if (dow===0 && isDDL(ds)) return true;
                    if (ult!==null && dow===ult) { const sun=new Date(ds+'T12:00:00'); sun.setDate(sun.getDate()-dow); if(isDDL(sun.toISOString().split('T')[0])) return false; }
                    if (escStr.includes('escala_uma_folga')||escStr.includes('escala_duas_folgas')) { if(fDow.length>0) return fDow.includes(dow); }
                    if (escStr.includes('seg_sexta')||escStr.includes('5x2')||escStr.includes('5 x 2')) return dow===0||dow===6;
                    if (escStr.includes('6x1')||escStr.includes('6 x 1')) return dow===0;
                    return dow===0;
                };
                const dias = datas.map(data => { const a=aus[data]||null; const f=getF(data); let st='disponivel'; if(f) st='folga'; if(a) st=a; return {data,status:st}; });
                return { id:c.id, nome_completo:c.nome_completo, cargo:c.cargo, departamento:c.departamento, foto_base64:c.foto_base64, foto_path:c.foto_path, horario_entrada:c.horario_entrada, horario_saida:c.horario_saida, escala_tipo:c.escala_tipo, escala_ciclo_inicio:c.escala_ciclo_inicio||null, dias };
            });
            res.json(result);
        }).catch(e => res.status(500).json({ error: e.message }));
    });
});

