// GET - Disponibilidade de colaboradores para o Resumo de Rota por data
// Query: ?data=YYYY-MM-DD&nomes=Nome1,Nome2,...
app.get('/api/logistica/disponibilidade-rota', authenticateToken, (req, res) => {
    const { data, nomes } = req.query;
    if (!data || !nomes) return res.status(400).json({ error: 'Informe data e nomes.' });

    const nomesArr = nomes.split(',').map(n => n.trim().toLowerCase()).filter(Boolean);
    if (!nomesArr.length) return res.json({});

    const DIA_MAP = {
        'dom': 0, 'domingo': 0, 'seg': 1, 'segunda': 1,
        'ter': 2, 'terГ§a': 2, 'terca': 2, 'qua': 3, 'quarta': 3,
        'qui': 4, 'quinta': 4, 'sex': 5, 'sexta': 5,
        'sГЎb': 6, 'sab': 6, 'sabado': 6, 'sГЎbado': 6
    };

    // FunГ§ГЈo de folga reutilizada do endpoint de escala
    function calcFolga(c, dateStr) {
        const escalaStr = (c.escala_tipo || '').toLowerCase();
        let folgasExplicitas = [];
        try {
            const parsed = JSON.parse(c.escala_folgas || '[]');
            folgasExplicitas = Array.isArray(parsed) ? parsed.map(f => String(f).trim().toLowerCase()) : [String(parsed).trim().toLowerCase()];
        } catch (e2) {
            folgasExplicitas = (c.escala_folgas || '').split(/[,;]+/).map(f => f.trim().toLowerCase()).filter(Boolean);
        }
        const folgasDow = folgasExplicitas.map(f => DIA_MAP[f]).filter(v => v !== undefined);
        const d = new Date(dateStr + 'T12:00:00');
        const dow = d.getDay();
        const temCiclo = c.escala_ciclo_inicio && (escalaStr.includes('uma_folga') || escalaStr.includes('duas_folgas') || escalaStr.includes('folga'));
        const cicloBase = temCiclo ? new Date(c.escala_ciclo_inicio + 'T12:00:00') : null;
        const ultimoFolgaDow = folgasDow.length >= 2 ? folgasDow[0] : null;

        const isDomingoDeLei = (ds) => {
            if (!temCiclo || !cicloBase) return false;
            const dd = new Date(ds + 'T12:00:00');
            if (dd.getDay() !== 0) return false;
            const diffMs = dd - cicloBase;
            if (diffMs < 0) return false;
            const diffDias = Math.round(diffMs / (1000 * 60 * 60 * 24));
            const nDomingo = Math.round(diffDias / 7);
            return nDomingo % 3 === 2;
        };

        if (escalaStr.includes('12x36')) {
            if (c.escala_ciclo_inicio) {
                const ciclo12 = new Date(c.escala_ciclo_inicio + 'T12:00:00');
                const diffMs = d - ciclo12;
                if (diffMs < 0) return false;
                const diffDias = Math.round(diffMs / (1000 * 60 * 60 * 24));
                return diffDias % 2 === 1;
            }
            return false;
        }
        if (dow === 0 && isDomingoDeLei(dateStr)) return true;
        if (ultimoFolgaDow !== null && dow === ultimoFolgaDow) {
            const thisSunday = new Date(dateStr + 'T12:00:00');
            thisSunday.setDate(thisSunday.getDate() - dow);
            if (isDomingoDeLei(thisSunday.toISOString().split('T')[0])) return false;
        }
        if (folgasDow.length > 0) return folgasDow.includes(dow);
        if (escalaStr.includes('seg_sexta') || escalaStr.includes('5x2') || escalaStr.includes('5 x 2')) return dow === 0 || dow === 6;
        if (escalaStr.includes('6x1') || escalaStr.includes('6 x 1')) return dow === 0;
        return dow === 0;
    }

    db.all(`SELECT id, nome_completo, status, escala_tipo, escala_folgas, escala_ciclo_inicio,
                   ferias_programadas_inicio, ferias_programadas_fim, aso_exame_data
            FROM colaboradores WHERE LOWER(TRIM(nome_completo)) IN (${nomesArr.map(() => '?').join(',')})`,
        nomesArr, (err, colabs) => {
            if (err) return res.status(500).json({ error: err.message });
            if (!colabs || !colabs.length) return res.json({});

            const ids = colabs.map(c => c.id);
            const ph = ids.map(() => '?').join(',');

            const pAtestado = new Promise(resolve => {
                db.all(`SELECT colaborador_id, atestado_inicio, atestado_fim FROM documentos
                    WHERE colaborador_id IN (${ph})
                    AND (tab_name LIKE '%ATESTADO%' OR document_type LIKE '%Atestado%' OR tab_name = 'Atestados')
                    AND atestado_inicio <= ? AND atestado_fim >= ?`, [...ids, data, data], (e, rows) => {
                    const set = {};
                    // Guarda o atestado_fim para mostrar no badge
                    (rows || []).forEach(r => { set[r.colaborador_id] = r.atestado_fim || null; });
                    resolve(set);
                });
            });

            const pFalta = new Promise(resolve => {
                db.all(`SELECT colaborador_id FROM faltas WHERE colaborador_id IN (${ph}) AND data_falta = ?`,
                    [...ids, data], (e, rows) => {
                        const set = {};
                        (rows || []).forEach(r => { set[r.colaborador_id] = true; });
                        resolve(set);
                    });
            });

            // Agenda: falta/ausencia/terapia marcada na agenda da logГӯstica para essa data referente ao colaborador
            const pAgenda = new Promise(resolve => {
                db.all(`SELECT referente_ids, tipo FROM logistica_agenda WHERE data = ? AND tipo IN ('falta','afastado','ferias','terapia')`, [data], (e, rows) => {
                    const agendaMap = new Map(); // id -> tipo
                    (rows || []).forEach(r => {
                        try {
                            const refs = JSON.parse(r.referente_ids || '[]');
                            refs.forEach(rid => {
                                const idNum = Number(rid);
                                // Prioridade: falta > afastado > ferias > terapia
                                const prev = agendaMap.get(idNum);
                                if (!prev || r.tipo === 'falta' || (r.tipo === 'afastado' && (prev === 'ferias' || prev === 'terapia')) || (r.tipo === 'ferias' && prev === 'terapia')) {
                                    agendaMap.set(idNum, r.tipo);
                                }
                            });
                        } catch (ex) { }
                    });
                    resolve(agendaMap);
                });
            });

            // Avisos: cards de aviso na agenda logГӯstica para essa data referentes a colaboradores
            const pAviso = new Promise(resolve => {
                db.all(`SELECT referente_ids, titulo FROM logistica_agenda WHERE data = ? AND tipo = 'aviso'`, [data], (e, rows) => {
                    const avisoMap = new Map(); // id -> [titulo, ...]
                    (rows || []).forEach(r => {
                        try {
                            const refs = JSON.parse(r.referente_ids || '[]');
                            refs.forEach(rid => {
                                const idNum = Number(rid);
                                if (!avisoMap.has(idNum)) avisoMap.set(idNum, []);
                                if (r.titulo) avisoMap.get(idNum).push(r.titulo);
                            });
                        } catch (ex) { }
                    });
                    resolve(avisoMap);
                });
            });

            Promise.all([pAtestado, pFalta, pAgenda, pAviso]).then(([atestSet, faltSet, agendaMap, avisoMap]) => {
                const result = {};
                colabs.forEach(c => {
                    const nomeKey = (c.nome_completo || '').toLowerCase().trim();
                    let status = 'disponivel';
                    let motivo = '';
                    let data_fim = null;

                    // Status do sistema (FГ©rias, Afastado no campo status)
                    const statusSistema = (c.status || '').toLowerCase();
                    const hojeDate = new Date(new Date().toLocaleString("en-US", {timeZone: "America/Sao_Paulo"}));
                    const hojeStr = hojeDate.getFullYear() + '-' + String(hojeDate.getMonth() + 1).padStart(2, '0') + '-' + String(hojeDate.getDate()).padStart(2, '0');

                    if (statusSistema === 'desligado') {
                        status = 'desligado';
                        motivo = 'Colaborador desligado';
                    } else if (statusSistema === 'fГ©rias' || statusSistema === 'ferias') {
                        if (c.ferias_programadas_fim && data > c.ferias_programadas_fim) {
                            // Data da rota Г© DEPOIS das fГ©rias, entГЈo estГЎ disponГӯvel
                        } else {
                            status = 'ferias';
                            motivo = 'Em FГ©rias (status cadastro)';
                        }
                    } else if (statusSistema === 'afastado') {
                        if (data <= hojeStr) {
                            status = 'afastado';
                            motivo = 'Afastado (status cadastro)';
                        }
                    }

                    // FГ©rias programadas por perГӯodo
                    if (c.ferias_programadas_inicio && c.ferias_programadas_fim) {
                        if (data >= c.ferias_programadas_inicio && data <= c.ferias_programadas_fim) {
                            status = 'ferias';
                            motivo = 'FГ©rias programadas';
                        }
                    }

                    // Atestado no perГӯodo (armazena a data fim para exibiГ§ГЈo)
                    if (atestSet[c.id] !== undefined && atestSet[c.id] !== null) {
                        const fimAtestado = atestSet[c.id];
                        const fimFmt = fimAtestado
                            ? new Date(fimAtestado + 'T12:00:00').toLocaleDateString('pt-BR')
                            : null;
                        status = 'afastado';
                        motivo = fimFmt ? `Afastado atГ© ${fimFmt}` : 'Afastado / Atestado';
                        data_fim = fimAtestado || null;
                    }

                    // Falta registrada na tabela de faltas
                    if (faltSet[c.id]) { status = 'falta'; motivo = 'Falta registrada no dia'; }

                    // Agenda logГӯstica вҖ” respeita o tipo do card (falta, afastado, ferias ou terapia)
                    if (agendaMap.has(c.id)) {
                        const tipoAgenda = agendaMap.get(c.id);
                        if (tipoAgenda === 'falta') { status = 'falta'; motivo = 'AusГӘncia lanГ§ada na Agenda'; }
                        else if (tipoAgenda === 'afastado') { status = 'afastado'; motivo = 'AusГӘncia lanГ§ada na Agenda'; }
                        else if (tipoAgenda === 'ferias' && status === 'disponivel') { status = 'ferias'; motivo = 'FГ©rias lanГ§adas na Agenda LogГӯstica'; }
                        else if (tipoAgenda === 'terapia' && status === 'disponivel') { status = 'terapia'; motivo = 'Terapia agendada para hoje'; }
                    }

                    // Folga da escala (sГі se ainda disponГӯvel)
                    if (status === 'disponivel') {
                        if (calcFolga(c, data)) { status = 'folga'; motivo = 'Dia de folga (escala)'; }
                    }

                    // ASO Agendado
                    if (c.aso_exame_data) {
                        const [d, m, y] = c.aso_exame_data.split('/');
                        if (d && m && y) {
                            const asoDateStr = `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
                            if (asoDateStr === data) {
                                // Add ASO info
                                status = 'aso'; 
                                motivo = 'ASO agendado para hoje';
                            }
                        }
                    }

                    // Avisos da Agenda LogГӯstica (nГЈo alteram status, apenas adicionam aviso)
                    const avisosColab = avisoMap.has(c.id) ? avisoMap.get(c.id) : [];

                    result[nomeKey] = { status, motivo, nome: c.nome_completo, data_fim, avisos: avisosColab };
                });
                res.json(result);
            });
        });
});

// POST вҖ“ criar card
app.post('/api/logistica/agenda', authenticateToken, express.json(), (req, res) => {
    const { titulo, descricao, data, horario, tipo, responsaveis, referente_ids, acoes, setor } = req.body;
    if (!data) return res.status(400).json({ error: 'Data obrigatГіria.' });
    const criado_por = req.user ? (req.user.username || '') : '';
    db.run(`INSERT INTO logistica_agenda (setor, titulo, descricao, data, horario, tipo, responsaveis, referente_ids, acoes, criado_por, criado_em, atualizado_em)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now','localtime'), datetime('now','localtime'))`,
        [setor || 'logistica', titulo || '', descricao || '', data, horario || '', tipo || 'aviso',
        JSON.stringify(responsaveis || []), JSON.stringify(referente_ids || []), JSON.stringify(acoes || []), criado_por],
        function (err) {
            if (err) return res.status(500).json({ error: err.message });
            const insertedId = this.lastID;
            db.get('SELECT * FROM logistica_agenda WHERE id = ?', [insertedId], (e2, row) => {
                if (row) dispararAcoesAgenda(row).catch(() => { });
            });
            db.run(`INSERT INTO auditoria (usuario, programa, campo, conteudo_anterior, conteudo_atual, registro_id) VALUES (?, ?, ?, ?, ?, ?)`,
                [criado_por, (setor === 'rh' ? 'Agenda RH' : 'Agenda LogГӯstica'), 'CriaГ§ГЈo de Card', null, `Card: ${titulo || ''} (${data})`, insertedId]);
            res.json({ id: insertedId, ok: true });
        }
    );
});

// PUT вҖ“ atualizar card
app.put('/api/logistica/agenda/:id', authenticateToken, express.json(), (req, res) => {
    db.get('SELECT * FROM logistica_agenda WHERE id = ?', [req.params.id], (err, oldRow) => {
        if (err || !oldRow) return res.status(404).json({ error: 'Card nГЈo encontrado' });
        
        const { titulo, descricao, data, horario, tipo, responsaveis, referente_ids, acoes, setor } = req.body;
        
        let anterior = [];
        let atual = [];
        if ((oldRow.titulo || '') !== (titulo || '')) { anterior.push(`TГӯtulo: ${oldRow.titulo || ''}`); atual.push(`TГӯtulo: ${titulo || ''}`); }
        if ((oldRow.descricao || '') !== (descricao || '')) { anterior.push(`DescriГ§ГЈo: ${oldRow.descricao || ''}`); atual.push(`DescriГ§ГЈo: ${descricao || ''}`); }
        if ((oldRow.data || '') !== (data || '')) { anterior.push(`Data: ${oldRow.data || ''}`); atual.push(`Data: ${data || ''}`); }
        if ((oldRow.horario || '') !== (horario || '')) { anterior.push(`HorГЎrio: ${oldRow.horario || ''}`); atual.push(`HorГЎrio: ${horario || ''}`); }
        if ((oldRow.tipo || '') !== (tipo || '')) { anterior.push(`Tipo: ${oldRow.tipo || ''}`); atual.push(`Tipo: ${tipo || ''}`); }
        
        try {
            const oldResp = JSON.parse(oldRow.responsaveis || '[]').join(',');
            const newResp = (responsaveis || []).join(',');
            if (oldResp !== newResp) { anterior.push(`Resp: [${oldResp}]`); atual.push(`Resp: [${newResp}]`); }
            
            const oldRef = JSON.parse(oldRow.referente_ids || '[]').join(',');
            const newRef = (referente_ids || []).join(',');
            if (oldRef !== newRef) { anterior.push(`Referente: [${oldRef}]`); atual.push(`Referente: [${newRef}]`); }
        } catch(e) {}

        let ca = anterior.length ? anterior.join(' | ') : null;
        let cu = atual.length ? atual.join(' | ') : `Editou o card: ${titulo || ''}`;

        db.run(`UPDATE logistica_agenda SET titulo=?, descricao=?, data=?, horario=?, tipo=?, responsaveis=?, referente_ids=?, acoes=?, setor=?,
                atualizado_em=datetime('now','localtime') WHERE id=?`,
            [titulo || '', descricao || '', data, horario || '', tipo || 'aviso',
            JSON.stringify(responsaveis || []), JSON.stringify(referente_ids || []), JSON.stringify(acoes || []),
            setor || 'logistica', req.params.id],
            function (err2) {
                if (err2) return res.status(500).json({ error: err2.message });
                db.run(`INSERT INTO auditoria (usuario, programa, campo, conteudo_anterior, conteudo_atual, registro_id) VALUES (?, ?, ?, ?, ?, ?)`,
                    [req.user ? req.user.username : '', (setor === 'rh' ? 'Agenda RH' : 'Agenda LogГӯstica'), 'EdiГ§ГЈo de Card', ca, cu, req.params.id]);
                res.json({ ok: true });
            }
        );
    });
});

