// Helper: disparar aГ§Гөes (e-mail) de um card da agenda
async function dispararAcoesAgenda(card) {
    let acoes = [];
    try { acoes = JSON.parse(card.acoes || '[]'); } catch (e) { }
    let referente_ids = [];
    try { referente_ids = JSON.parse(card.referente_ids || '[]'); } catch (e) { }

    // NotificaГ§ГЈo de Aviso de Falta (para o RH) - Regra Absoluta da Tela de NotificaГ§Гөes e InserГ§ГЈo no ProntuГЎrio
    if (card.tipo === 'falta' && referente_ids.length > 0) {
        // 1. Inserir a falta no prontuГЎrio do RH (apenas se ainda nГЈo existir para a mesma data)
        referente_ids.forEach(colab_id => {
            db.get('SELECT id FROM faltas WHERE colaborador_id = ? AND data_falta = ?', [colab_id, card.data], (errChk, existente) => {
                if (errChk || existente) return; // jГЎ existe, nГЈo duplicar
                const obsBase = card.descricao || 'Falta registrada via Agenda da LogГӯstica';
                const obsFinal = obsBase + (card.criado_por ? ' (Criado por: ' + card.criado_por + ')' : '');
                db.run('INSERT INTO faltas (colaborador_id, data_falta, turno, observacao, avisado_previamente) VALUES (?, ?, ?, ?, ?)',
                    [colab_id, card.data, 'Dia todo', obsFinal, 'NГЈo'],
                    function (errFalta) {
                        if (errFalta) console.error("Erro ao inserir falta via Agenda:", errFalta.message);
                    }
                );
            });
        });

        // 2. Disparar notificaГ§ГЈo para quem deve receber "aviso_faltas"
        db.all("SELECT usuario_id FROM config_notificacoes WHERE tipo = 'aviso_faltas'", [], (errConfig, rowsConfig) => {
            if (!errConfig && rowsConfig && rowsConfig.length > 0) {
                const placeholders = referente_ids.map(() => '?').join(',');
                db.all(`SELECT id, nome_completo FROM colaboradores WHERE id IN (${placeholders})`, referente_ids, (errColabs, colabs) => {
                    if (!errColabs && colabs && colabs.length > 0) {
                        const nomes = colabs.map(c => c.nome_completo.split(' ').slice(0, 2).join(' ')).join(', ');
                        const msg = `O(s) colaborador(es) ${nomes} teve/tiveram uma falta (Agenda) no dia ${card.data.split('-').reverse().join('/')}.`;
                        const dados = JSON.stringify({ origem: 'agenda', data_falta: card.data, id: card.id, nome_colab: nomes });
                        rowsConfig.forEach(cfg => {
                            db.run("INSERT INTO notificacoes_usuarios (usuario_id, tipo, mensagem, dados) VALUES (?, ?, ?, ?)",
                                [cfg.usuario_id, 'aviso_faltas', msg, dados]);
                        });
                        // E-mail para aviso_faltas da agenda
                        sendEmailParaNotificados('aviso_faltas', {
                            subject: `вҡ пёҸ Aviso de Falta (Agenda) вҖ“ ${nomes}`,
                            html: `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;border:1px solid #ddd;border-radius:8px;overflow:hidden;">
                                <div style="text-align:center;background:#fff;border-bottom:1px solid #eee;">
                                    <img src="cid:empresa-logo" alt="AmГ©rica Rental" style="width:100%;max-width:600px;height:auto;display:block;">
                                </div>
                                <div style="padding:24px;">
                                    <h2 style="color:#e67700;text-align:center;margin-top:0;">вҡ пёҸ Aviso de Falta (Agenda LogГӯstica)</h2>
                                    <p>Uma falta foi registrada via Agenda da LogГӯstica:</p>
                                    <div style="background:#fffbeb;padding:16px;border-radius:8px;margin:16px 0;border-left:4px solid #f59e0b;">
                                        <p style="margin:4px 0;"><strong>Colaborador(es):</strong> ${nomes}</p>
                                        <p style="margin:4px 0;"><strong>Data:</strong> ${card.data ? card.data.split('-').reverse().join('/') : 'вҖ”'}</p>
                                        ${card.descricao ? `<p style="margin:4px 0;"><strong>DescriГ§ГЈo:</strong> ${card.descricao}</p>` : ''}
                                        ${card.criado_por ? `<p style="margin:4px 0;"><strong>Registrado por:</strong> ${card.criado_por}</p>` : ''}
                                    </div>
                                    <p style="font-size:12px;color:#999;text-align:center;"><i>Esta notificaГ§ГЈo foi gerada automaticamente pelo Sistema AmГ©rica Rental.</i></p>
                                </div>
                            </div>`
                        });
                    }
                });
            }
        });
    }

    if (!acoes.includes('enviar_email')) return;

    let responsaveisIds = [];
    try { responsaveisIds = JSON.parse(card.responsaveis || '[]'); } catch (e) { }
    if (responsaveisIds.length === 0) return;

    const placeholders = responsaveisIds.map(() => '?').join(',');
    db.all(`SELECT nome_completo, email_corporativo FROM colaboradores WHERE id IN (${placeholders}) AND email_corporativo IS NOT NULL AND email_corporativo != ''`,
        responsaveisIds, async (err, colabs) => {
            if (err || !colabs || colabs.length === 0) return;

            const tipo_label = { aviso: 'Aviso Geral', falta: 'Aviso de Falta', reuniao: 'ReuniГЈo', tarefa: 'Tarefa', email: 'Envio de E-mail', outro: 'Outro' }[card.tipo] || card.tipo;
            const dataFmt = card.data ? card.data.split('-').reverse().join('/') : '';
            const logoPath = require('path').join(__dirname, '..', 'frontend', 'assets', 'logo-header.png');
            const transporter = nodemailer.createTransport(SMTP_CONFIG);

            for (const c of colabs) {
                const html = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;border:1px solid #eee;">
                    <div style="background:linear-gradient(135deg,#1e293b,#334155);padding:20px;text-align:center;">
                        <img src="cid:logo-agenda" style="max-height:60px;" alt="AmГ©rica Rental">
                    </div>
                    <div style="padding:24px;">
                        <h2 style="color:#2d9e5f;margin-top:0;">рҹ“… Agenda LogГӯstica вҖ” ${tipo_label}</h2>
                        <p>OlГЎ, <strong>${c.nome_completo}</strong>!</p>
                        <p>VocГӘ foi marcado como responsГЎvel em um item da agenda do dia <strong>${dataFmt}</strong>.</p>
                        <div style="background:#f0fdf4;border-left:4px solid #2d9e5f;border-radius:8px;padding:16px;margin:16px 0;">
                            <p style="margin:4px 0;"><strong>Tipo:</strong> ${tipo_label}</p>
                            ${card.titulo ? `<p style="margin:4px 0;"><strong>TГӯtulo:</strong> ${card.titulo}</p>` : ''}
                            ${card.descricao ? `<p style="margin:4px 0;"><strong>DescriГ§ГЈo:</strong> ${card.descricao}</p>` : ''}
                        </div>
                        <p style="margin-top:24px;color:#94a3b8;font-size:0.85em;">Atenciosamente,<br>Sistema AmГ©rica Rental</p>
                    </div>
                </div>`;
                try {
                    await sendMailHelper({
                        from: `"Agenda AmГ©rica Rental" <${SMTP_CONFIG.auth.user}>`,
                        to: c.email_corporativo,
                        subject: `[Agenda ${dataFmt}] ${card.titulo || tipo_label}`,
                        html,
                        attachments: [{ filename: 'logo.png', path: logoPath, cid: 'logo-agenda' }]
                    });
                    console.log(`[Agenda] E-mail enviado para ${c.email_corporativo}`);
                } catch (e2) {
                    console.error('[Agenda] Erro ao enviar e-mail:', e2.message);
                }
            }
        }
    );
}
