// Credenciais Monaco (username/password que vocГӘ definirГЎ e enviarГЎ Г  MГҙnaco)
const MONACO_USERNAME = process.env.MONACO_USERNAME || 'america_rental';
const MONACO_PASSWORD = process.env.MONACO_PASSWORD || 'Monaco@AmericaRental2025!';

// в”Җв”Җ POST /api/monaco/token в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.post('/api/monaco/token', (req, res) => {
    const { username, password } = req.body || {};
    if (username !== MONACO_USERNAME || password !== MONACO_PASSWORD) {
        return res.status(401).json({ codError: 401, message: 'Credenciais invГЎlidas' });
    }
    const token = jwt.sign({ source: 'monaco', username }, SECRET_KEY, { expiresIn: '30d' });
    res.json({ type: 'Bearer', access_token: token });
});

// Middleware de autenticaГ§ГЈo Monaco
function monacoAuth(req, res, next) {
    const authHeader = req.headers['authorization'] || '';
    const token = authHeader.replace(/^(Bearer|Basic|Token)\s+/i, '');
    if (!token) return res.status(401).json({ codError: 401, message: 'Token ausente' });
    try {
        const decoded = jwt.verify(token, SECRET_KEY);
        if (decoded.source !== 'monaco') throw new Error('Token invГЎlido para Monaco');
        next();
    } catch (e) {
        return res.status(401).json({ codError: 401, message: 'Token invГЎlido ou expirado' });
    }
}

// Sincroniza multa recebida da MГҙnaco para a tabela principal de logГӯstica
function syncToLogistica(uuid, tipoEvento, payload) {
    db.get('SELECT id, documento_base64, documento_path FROM multas_logistica WHERE numero_ait = ? OR monaco_uuid = ?', [payload.numero_ait, uuid], (err, row) => {
        if (err) {
            console.error('[MONACO SYNC] Erro ao buscar logistica:', err);
            return;
        }

        let docBase64 = null;
        let docNome = null;
        let termoBase64 = null;
        let termoNome = null;
        
        // Monaco envia o campo como 'Arquivos' (maiГәsculo) вҖ” suportamos ambos
        const arquivosArr = payload.Arquivos || payload.arquivos || [];
        
        // 1. Tentar buscar no campo direto termo_desconto
        if (payload.termo_desconto && typeof payload.termo_desconto === 'string' && payload.termo_desconto.length > 100) {
            termoBase64 = payload.termo_desconto;
            termoNome = 'termo_desconto.pdf';
        }

        if (arquivosArr.length > 0) {
            for (let arq of arquivosArr) {
                const nomeArq = arq.Nome || arq.nome || '';
                const nomeUpper = nomeArq.toUpperCase();
                // 2. Tentar buscar no array de arquivos (caso enviem como um anexo normal)
                if (nomeUpper.includes('DECLARAГҮГғO') || nomeUpper.includes('DECLARACAO') || nomeUpper.includes('TERMO') || nomeUpper.includes('DESCONTO')) {
                    termoBase64 = arq.base64;
                    termoNome = nomeArq || 'termo_desconto.pdf';
                } else if (!docBase64 && arq.base64) {
                    // Pega o primeiro arquivo que NГғO seja o termo como notificaГ§ГЈo padrГЈo
                    docBase64 = arq.base64;
                    docNome = nomeArq || 'anexo_monaco.pdf';
                }
            }
        }

        const dataLimite = payload.prazo_identificacao_condutor || payload.vencimento_multa || null;
        const localInfracao = payload.local || payload.local_infracao || payload.cidade || null;
        const statusMonaco = payload.status_notificacao || tipoEvento;
        let linkFormulario = payload.link_indicacao || payload.link_formulario || payload.url_formulario ||
                             payload.Link || payload.LinkIndicacao || payload.link || null;


        if (row) {
            // Atualizar multa existente
            let updateSql = `UPDATE multas_logistica SET
                monaco_uuid = ?, placa = ?, data_infracao = ?, hora_infracao = ?,
                motivo = ?, valor_multa = ?, pontuacao = ?, local_infracao = ?, data_limite = ?, status_monaco = ?,
                link_formulario = COALESCE(?, link_formulario)`;
            let params = [
                uuid, payload.placa, payload.data_da_infracao, payload.hora_da_infracao,
                payload.descricao, payload.valor_da_infracao, payload.pontos, localInfracao, dataLimite, statusMonaco,
                linkFormulario
            ];

            // SГі atualiza PDF se a multa nГЈo tiver um PDF anexado manualmente
            if (docBase64 && !row.documento_base64 && !row.documento_path) {
                updateSql += `, documento_base64 = ?, documento_nome = ?`;
                params.push(docBase64, docNome);
            }
            
            if (termoBase64) {
                updateSql += `, termo_desconto_base64 = ?, termo_desconto_nome = ?`;
                params.push(termoBase64, termoNome);
            }

            updateSql += ` WHERE id = ?`;
            params.push(row.id);

            db.run(updateSql, params, (errUpdate) => {
                if (errUpdate) console.error('[MONACO SYNC] Erro update:', errUpdate);
                else console.log(`[MONACO SYNC] Multa logistica ID=${row.id} atualizada.`);
            });
        } else {
            // Inserir nova multa
            db.run(`INSERT INTO multas_logistica (
                monaco_uuid, numero_ait, placa, data_infracao, hora_infracao,
                motivo, valor_multa, pontuacao, local_infracao, data_limite,
                status, created_by_nome, observacao, documento_base64, documento_nome, status_monaco, link_formulario, termo_desconto_base64, termo_desconto_nome
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'IntegraГ§ГЈo MГҙnaco', NULL, ?, ?, ?, ?, ?, ?)`, [
                uuid, payload.numero_ait, payload.placa, payload.data_da_infracao, payload.hora_da_infracao,
                payload.descricao, payload.valor_da_infracao, payload.pontos, localInfracao, dataLimite,
                isAitAntiga(payload.numero_ait) ? 'Antiga' : 'ConferГӘncia',
                docBase64, docNome, statusMonaco, linkFormulario, termoBase64, termoNome
            ], function (errInsert) {
                if (errInsert) console.error('[MONACO SYNC] Erro insert:', errInsert);
                else {
                    console.log(`[MONACO SYNC] Nova multa logistica inserida ID=${this.lastID}`);
                    // NГЈo notifica para multas antigas
                    if (!isAitAntiga(payload.numero_ait)) {
                        enviarNotificacaoNovaMultaMonaco(payload, this.lastID);
                    }
                }
            });
        }
    });
}

