// в”Җв”Җ MГ“DULO MTR SIGOR в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// Configuracoes SIGOR - valores padrao (sobrescritos pelo banco ao iniciar)
const SIGOR_HOM = {
  cpfCnpj: '38058722839',
  senha: 'gb5ti5',
  unidade: '19201',
  api: 'https://mtrr-hom.cetesb.sp.gov.br/apiws/rest'
};

const SIGOR_CFG = {
  cpfCnpj: '38058722839',
  senha: 'gb5ti5',
  unidade: '19201',
  apiHom: 'https://mtrr-hom.cetesb.sp.gov.br/apiws/rest',
  apiProd: 'https://mtrr.cetesb.sp.gov.br/apiws/rest',
  get api() { return this.apiProd; }
};

// Criar tabela de configuracoes
db.run(`CREATE TABLE IF NOT EXISTS config_sistema (
  chave TEXT PRIMARY KEY,
  valor TEXT,
  updated_at TEXT DEFAULT (datetime('now'))
)`);

// Carregar credenciais salvas do banco (ao iniciar)
function carregarCredenciaisSigorDoBanco() {
  db.all("SELECT chave, valor FROM config_sistema WHERE chave LIKE 'sigor_%'", [], (err, rows) => {
    if (err || !rows || rows.length === 0) return;
    const cfg = {};
    rows.forEach(r => { cfg[r.chave] = r.valor; });
    if (cfg['sigor_hom_cpf'])    SIGOR_HOM.cpfCnpj  = cfg['sigor_hom_cpf'];
    if (cfg['sigor_hom_senha'])  SIGOR_HOM.senha     = cfg['sigor_hom_senha'];
    if (cfg['sigor_hom_unidade'])SIGOR_HOM.unidade   = cfg['sigor_hom_unidade'];
    if (cfg['sigor_prod_cpf'])   SIGOR_CFG.cpfCnpj   = cfg['sigor_prod_cpf'];
    if (cfg['sigor_prod_senha']) SIGOR_CFG.senha      = cfg['sigor_prod_senha'];
    if (cfg['sigor_prod_unidade'])SIGOR_CFG.unidade   = cfg['sigor_prod_unidade'];
    // Invalida tokens em cache para forcar reautenticacao
    _sigorToken = null; _sigorTokenExp = 0;
    _sigorHomToken = null; _sigorHomTokenExp = 0;
    console.log('[SIGOR] Credenciais carregadas do banco');
  });
}
carregarCredenciaisSigorDoBanco();

// в”Җв”Җ GET /api/config/sigor - Retorna credenciais (senha mascarada) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.get('/api/config/sigor', authenticateToken, (req, res) => {
  const role = (req.user?.role || '').toLowerCase();
  if (!['admin', 'administrador', 'diretoria'].includes(role)) return res.status(403).json({ erro: 'Sem permissao' });
  res.json({
    hom: { cpfCnpj: SIGOR_HOM.cpfCnpj, senha: SIGOR_HOM.senha, unidade: SIGOR_HOM.unidade },
    prod: { cpfCnpj: SIGOR_CFG.cpfCnpj, senha: SIGOR_CFG.senha, unidade: SIGOR_CFG.unidade }
  });
});

// в”Җв”Җ PUT /api/config/sigor - Salva credenciais no banco в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.put('/api/config/sigor', authenticateToken, (req, res) => {
  const role = (req.user?.role || '').toLowerCase();
  if (!['admin', 'administrador', 'diretoria'].includes(role)) return res.status(403).json({ erro: 'Sem permissao' });
  const { hom, prod } = req.body;
  const agora = new Date().toISOString();
  const upsert = (chave, valor) => new Promise((resolve, reject) => {
    db.run(`INSERT INTO config_sistema (chave, valor, updated_at) VALUES (?,?,?)
            ON CONFLICT(chave) DO UPDATE SET valor=excluded.valor, updated_at=excluded.updated_at`,
      [chave, valor, agora], err => err ? reject(err) : resolve());
  });
  const ops = [];
  if (hom) {
    if (hom.cpfCnpj) ops.push(upsert('sigor_hom_cpf',    hom.cpfCnpj));
    if (hom.senha)   ops.push(upsert('sigor_hom_senha',   hom.senha));
    if (hom.unidade) ops.push(upsert('sigor_hom_unidade', hom.unidade));
  }
  if (prod) {
    if (prod.cpfCnpj) ops.push(upsert('sigor_prod_cpf',    prod.cpfCnpj));
    if (prod.senha)   ops.push(upsert('sigor_prod_senha',   prod.senha));
    if (prod.unidade) ops.push(upsert('sigor_prod_unidade', prod.unidade));
  }
  Promise.all(ops)
    .then(() => { carregarCredenciaisSigorDoBanco(); res.json({ ok: true }); })
    .catch(e => res.status(500).json({ erro: e.message }));
});

// в”Җв”Җ POST /api/config/sigor/testar - Testa autenticacao com os dados enviados в”Җв”Җ
app.post('/api/config/sigor/testar', authenticateToken, async (req, res) => {
  const role = (req.user?.role || '').toLowerCase();
  if (!['admin', 'administrador', 'diretoria'].includes(role)) return res.status(403).json({ ok: false, mensagem: 'Sem permissГЈo' });
  const env = req.query.env === 'prod' ? 'prod' : 'hom';
  const cfg = req.body || {}; // LГӘ da requisiГ§ГЈo, nГЈo do banco
  const url = env === 'prod' ? SIGOR_CFG.apiProd : SIGOR_HOM.api;
  try {
    const resp = await fetch(url + '/gettoken', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ cpfCnpj: cfg.cpfCnpj, senha: cfg.senha, unidade: cfg.unidade })
    });
    const data = await resp.json();
    if (data.erro || !data.objetoResposta) {
      return res.json({ ok: false, mensagem: data.mensagem || 'Credenciais invГЎlidas' });
    }
    // Invalida token em cache para usar as novas credenciais
    if (env === 'prod') { _sigorToken = null; _sigorTokenExp = 0; }
    else { _sigorHomToken = null; _sigorHomTokenExp = 0; }
    res.json({ ok: true, mensagem: 'Autenticado com sucesso' });
  } catch (e) {
    res.json({ ok: false, mensagem: e.message });
  }
});

// в”Җв”Җ GET /api/config/logistica - Retorna configuraГ§Гөes de logГӯstica в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.get('/api/config/logistica', authenticateToken, (req, res) => {
  db.all("SELECT chave, valor FROM config_sistema WHERE chave IN ('logistica_porcentagem_central', 'logistica_porcentagem_amarela', 'logistica_porcentagem_vermelha', 'logistica_porcentagem_outra', 'logistica_valor_km')", [], (err, rows) => {
    if (err) return res.status(500).json({ error: err.message });
    const cfg = {
      logistica_porcentagem_central: 0,
      logistica_porcentagem_amarela: 0,
      logistica_porcentagem_vermelha: 0,
      logistica_porcentagem_outra: 0,
      logistica_valor_km: 0
    };
    if (rows) {
      rows.forEach(r => {
        cfg[r.chave] = parseFloat(r.valor) || 0;
      });
    }
    res.json(cfg);
  });
});

// в”Җв”Җ PUT /api/config/logistica - Salva configuraГ§Гөes de logГӯstica no banco в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.put('/api/config/logistica', authenticateToken, (req, res) => {
  const d = req.body;
  const agora = new Date().toISOString();
  const keys = [
    'logistica_porcentagem_central',
    'logistica_porcentagem_amarela',
    'logistica_porcentagem_vermelha',
    'logistica_porcentagem_outra',
    'logistica_valor_km'
  ];
  const promises = keys.map(k => {
    const val = d[k] !== undefined ? String(d[k]) : '0';
    return new Promise((resolve, reject) => {
      db.run(`INSERT INTO config_sistema (chave, valor, updated_at) VALUES (?,?,?)
              ON CONFLICT(chave) DO UPDATE SET valor=excluded.valor, updated_at=excluded.updated_at`,
        [k, val, agora], err => err ? reject(err) : resolve());
    });
  });
  Promise.all(promises)
    .then(() => res.json({ success: true }))
    .catch(err => res.status(500).json({ error: err.message }));
});

// Dados fixos do Destinador padrao
const SIGOR_DESTINADOR = {
  cnpj: '05380441000260',
  unidade: 19154,
  nome: 'BRK AMBIENTAL - MAUA S.A.'
};


let _sigorToken = null;
let _sigorTokenExp = 0;
let _sigorHomToken = null;
let _sigorHomTokenExp = 0;

// Token de PRODUCAO (para gerar MTRs)
async function sigorGetToken() {
  if (_sigorToken && Date.now() < _sigorTokenExp) return _sigorToken;
  const resp = await fetch(SIGOR_CFG.api + '/gettoken', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ cpfCnpj: SIGOR_CFG.cpfCnpj, senha: SIGOR_CFG.senha, unidade: SIGOR_CFG.unidade })
  });
  const data = await resp.json();
  if (data.erro || !data.objetoResposta) throw new Error(data.mensagem || 'Falha na autenticacao SIGOR Producao');
  _sigorToken = data.objetoResposta;
  _sigorTokenExp = Date.now() + 3600000;
  return _sigorToken;
}

// Token de HOMOLOGACAO (para buscar tabelas de referencia - residuos, tratamentos, etc.)
async function sigorGetHomToken() {
  if (_sigorHomToken && Date.now() < _sigorHomTokenExp) return _sigorHomToken;
  const resp = await fetch(SIGOR_HOM.api + '/gettoken', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ cpfCnpj: SIGOR_HOM.cpfCnpj, senha: SIGOR_HOM.senha, unidade: SIGOR_HOM.unidade })
  });
  const data = await resp.json();
  if (data.erro || !data.objetoResposta) throw new Error(data.mensagem || 'Falha na autenticacao SIGOR Homologacao');
  _sigorHomToken = data.objetoResposta;
  _sigorHomTokenExp = Date.now() + 3600000;
  return _sigorHomToken;
}

// Requisicao generica para PRODUCAO
async function sigorReq(path, method = 'GET', body = null, retry = true) {
  const token = await sigorGetToken();
  const opts = { method, headers: { 'Authorization': token, 'Content-Type': 'application/json' } };
  if (body) opts.body = JSON.stringify(body);
  const resp = await fetch(SIGOR_CFG.api + path, opts);
  const text = await resp.text();
  if (!text || text.trim() === '') {
    // Token provavelmente expirado - forГ§ar renovaГ§ГЈo e tentar uma vez mais
    if (retry && resp.status === 401) {
      console.warn('[SIGOR] Token expirado (401 vazio), renovando...');
      _sigorToken = null; _sigorTokenExp = 0;
      return sigorReq(path, method, body, false);
    }
    throw new Error(`SIGOR retornou resposta vazia (HTTP ${resp.status}) em ${path}`);
  }
  return JSON.parse(text);
}

// Requisicao generica para HOMOLOGACAO (tabelas de referencia e testes)
async function sigorHomReq(path, method = 'GET', body = null) {
  const token = await sigorGetHomToken();
  const opts = { method, headers: { 'Authorization': token, 'Content-Type': 'application/json' } };
  if (body) opts.body = JSON.stringify(body);
  const resp = await fetch(SIGOR_HOM.api + path, opts);
  return resp.json();
}


