// в”Җв”Җ POST /api/mtr/sincronizar в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.post('/api/mtr/sincronizar', authenticateToken, async (req, res) => {
  db.all('SELECT * FROM mtr_local WHERE numero_mtr IS NOT NULL AND numero_mtr != "null"', [], async (err, rows) => {
    if (err) return res.status(500).json({ mensagem: err.message });
    if (!rows || rows.length === 0) return res.json({ mensagem: 'Nenhuma MTR encontrada para sincronizar' });

    let atualizados = 0;
    const erros = [];
    for (const row of rows) {
      if (!row.numero_mtr) continue;
      try {
        const data = await sigorReq('/retornaManifesto/' + row.numero_mtr);
        console.log(`[SINC] MTR ${row.numero_mtr} resposta:`, JSON.stringify(data).substring(0, 200));
        if (data && data.objetoResposta && data.objetoResposta.situacaoManifesto) {
           let sit = data.objetoResposta.situacaoManifesto.simDescricao;
           if (sit) {
               sit = sit.charAt(0).toUpperCase() + sit.slice(1).toLowerCase();
               // Manter o status exatamente como o SIGOR retorna
           }
           console.log(`[SINC] MTR ${row.numero_mtr}: status SIGOR='${sit}' local='${row.status}'`);
           if (sit && sit !== row.status) {
              await new Promise((resolve, reject) => {
                db.run('UPDATE mtr_local SET status = ? WHERE id = ?', [sit, row.id], (e) => e ? reject(e) : resolve());
              });
              atualizados++;
           }
        } else {
          console.warn(`[SINC] MTR ${row.numero_mtr}: objetoResposta ou situacaoManifesto ausente. data=`, JSON.stringify(data).substring(0, 300));
        }
      } catch (e) {
        console.error(`[SINC] Erro ao sincronizar MTR ${row.numero_mtr}:`, e.message);
        erros.push(`${row.numero_mtr}: ${e.message}`);
      }
    }
    const msg = `SincronizaГ§ГЈo concluГӯda. ${atualizados} MTR(s) atualizada(s) de ${rows.length} total.${erros.length ? ' Erros: ' + erros.join('; ') : ''}`;
    res.json({ mensagem: msg });
  });
});

// в”Җв”Җ POST /api/mtr/importar в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Importa uma MTR existente (gerada pelo cliente) sabendo o nГәmero
app.post('/api/mtr/importar', authenticateToken, async (req, res) => {
  const { numero_mtr } = req.body;
  if (!numero_mtr) return res.status(400).json({ mensagem: 'NГәmero do MTR obrigatГіrio' });

  try {
    // 1. Consulta o SIGOR para pegar os dados
    const data = await sigorReq('/retornaManifesto/' + numero_mtr);
    const obj = data?.objetoResposta;
    
    if (!obj || data.erro) {
       return res.status(400).json({ mensagem: data?.mensagem || 'MTR nГЈo encontrada no SIGOR ou erro na consulta.' });
    }

    // 2. Verifica se jГЎ existe localmente
    db.get('SELECT id FROM mtr_local WHERE numero_mtr = ?', [numero_mtr], (err, row) => {
      if (err) return res.status(500).json({ mensagem: err.message });
      if (row) return res.status(400).json({ mensagem: 'MTR jГЎ estГЎ cadastrada no sistema.' });

      // 3. Extrai dados bГЎsicos para o banco
      const status = obj.situacaoManifesto?.simDescricao || 'Ativo';
      const geradorNome = obj.parceiroGerador?.parDescricao || 'GERADOR EXTERNO';
      const geradorCnpj = obj.parceiroGerador?.parCnpj || '';
      
      const residuo = obj.listaManifestoResiduo?.[0] || {};
      const resNome = residuo.residuo?.resDescricao || 'MГәltiplos / NГЈo informado';
      const quantidade = residuo.marQuantidade || 0;
      const unidade = residuo.unidade?.uniSigla || 'TON';
      const observacao = obj.manObservacao || 'Importada do SIGOR';

      // 4. Salva no banco local
      db.run(
        `INSERT INTO mtr_local (numero_mtr, status, gerador_nome, gerador_cnpj, residuo_codigo,
          quantidade, unidade, observacao, payload_json)
         VALUES (?,?,?,?,?,?,?,?,?)`,
        [numero_mtr, status, geradorNome, geradorCnpj, resNome,
         quantidade, unidade, observacao, JSON.stringify(data)],
        function (errIns) {
          if (errIns) return res.status(500).json({ mensagem: errIns.message });
          res.json({ mensagem: 'MTR importada com sucesso!', id: this.lastID });
        }
      );
    });
  } catch (e) {
    console.error('[MTR IMPORT] Erro:', e.message);
    res.status(500).json({ mensagem: e.message });
  }
});

