// в”Җв”Җ POST /api/mtr/gerar в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.post('/api/mtr/gerar', authenticateToken, async (req, res) => {
  const { geradorNome, geradorCnpj, residuoCodigo, quantidade, unidade,
          acondicionamentoCodigo, estadoFisicoCodigo, tratamentoCodigo,
          observacao, complementarDeId,
          destinadorCnpj, destinadorUnidade, motorista, placa, dataExpedicao } = req.body;

  // Usar destinador do formulГЎrio ou fallback para o padrГЈo BRK
  const destCnpj = (destinadorCnpj || SIGOR_DESTINADOR.cnpj).replace(/\D/g, '');
  const destUnidade = parseInt(destinadorUnidade) || SIGOR_DESTINADOR.unidade;

  try {
    // Usar API de PRODUCAO agora que temos as credenciais corretas
    const endpoint = '/salvarManifestoLote';
    
    // De/Para de unidades bГЎsicas
    const mapaUnidade = { 'TON': 3, 'KG': 1, 'L': 21, 'M3': 2 };
    const uniCodigo = mapaUnidade[unidade] || parseInt(unidade) || 3;
    
    // America Rental CNPJ
    const transpCnpj = '03434448000101';
    const transpUnidade = 116064; 

    // Date in ms
    let dtExpedicao = Date.now();
    if (dataExpedicao) {
       dtExpedicao = new Date(dataExpedicao + 'T12:00:00Z').getTime();
    }

    const payload = [{
      seuCodigo: 'AR-' + Date.now().toString().slice(-8),
      nomeResponsavel: 'AmГ©rica Rental',
      nomeMotorista: motorista || 'MГҒRCIO JORGE VILAR DA SILVA',
      placaVeiculo: (placa || 'DPE5A75').replace(/[^a-zA-Z0-9]/g, ''),
      dataExpedicao: dtExpedicao,
      transportador: { cpfCnpj: transpCnpj, unidade: transpUnidade },
      destinador: { cpfCnpj: destCnpj, unidade: destUnidade },
      gerador: { cpfCnpj: (geradorCnpj || '').replace(/\D/g, ''), razaoSocial: geradorNome },
      observacoes: observacao || '',
      listaManifestoResiduos: [{
        resCodigoIbama: residuoCodigo,
        marQuantidade: parseFloat(quantidade),
        uniCodigo: uniCodigo,
        tiaCodigo: parseInt(acondicionamentoCodigo),
        tieCodigo: parseInt(estadoFisicoCodigo),
        traCodigo: parseInt(tratamentoCodigo),
        claCodigo: req.body.claCodigo ? parseInt(req.body.claCodigo) : 43
      }]
    }];

    console.log('[MTR] Enviando payload prod:', JSON.stringify(payload));
    // Mudamos de sigorHomReq para sigorReq (Producao)
    const data = await sigorReq('/salvarManifestoLote', 'POST', payload);
    console.log('[MTR] Resposta CETESB:', JSON.stringify(data).substring(0, 500));
    const obj = data.respostaApiwsManifestoDTO?.[0] || data.objetoResposta?.[0] || data.objetoResposta || data;
        let numeroMTR = obj?.numeroManifestoEstadual || obj?.manifestoNumeroEstadual || obj?.numeroManifesto || obj?.manifesto || obj?.numero || null;
    if (!numeroMTR) {
        const str = JSON.stringify(data);
        const match = str.match(/(?:numeroManifestoEstadual|manifesto|numero|manifestoNumeroEstadual|numeroManifesto)"?:\s*"?(\d+)"?/i) || str.match(/\b(\d{12,14})\b/);
        if (match) numeroMTR = match[1];
    }

    // Coletar todos os erros do objeto de resposta (transportador, destinador, residuos...)
    const errosDetalhados = [];
    if (obj?.transportador?.restResponseMensagem && !obj.transportador.restResponseValido)
      errosDetalhados.push('Transportador: ' + obj.transportador.restResponseMensagem);
    if (obj?.destinador?.restResponseMensagem && !obj.destinador.restResponseValido)
      errosDetalhados.push('Destinador: ' + obj.destinador.restResponseMensagem);
    if (obj?.restResponseMensagem && !obj.restResponseValido)
      errosDetalhados.push(obj.restResponseMensagem);
    if (data.mensagemErroNacional)
      errosDetalhados.push(data.mensagemErroNacional);

    const mensagemErro = errosDetalhados.length > 0
      ? errosDetalhados.join(' | ')
      : (data.mensagem || obj?.restResponseMensagem || 'Erro desconhecido da CETESB');

    // A API CETESB retorna HTTP 200 mesmo em erro de negГіcio
    const temErro = data.erro || data.erroNacional || !obj?.restResponseValido || !numeroMTR;

    if (temErro || !numeroMTR) {
      console.warn('[MTR] Erro CETESB:', mensagemErro);
      return res.status(400).json({ erro: true, mensagem: mensagemErro });
    }

    db.run(
      `INSERT INTO mtr_local (numero_mtr, status, gerador_nome, gerador_cnpj, residuo_codigo,
        quantidade, unidade, acondicionamento_codigo, estado_fisico_codigo, tratamento_codigo,
        observacao, payload_json, complementar_de_id)
       VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)`,
      [numeroMTR, 'Salvo', geradorNome, geradorCnpj, residuoCodigo,
       quantidade, unidade, acondicionamentoCodigo, estadoFisicoCodigo, tratamentoCodigo,
       observacao, JSON.stringify({ ...data, _destinadorNome: req.body.destinadorNome || 'BRK AMBIENTAL - MAUГҒ S.A.' }), complementarDeId || null],
      function (errIns) {
        if (errIns) console.error('[MTR] Erro insert:', errIns);
        res.json({ erro: false, mensagem: 'MTR gerada com sucesso', numeroMTR, id: this.lastID });
      }
    );
  } catch (e) {
    console.error('[MTR] Erro gerar:', e);
    res.status(500).json({ erro: true, mensagem: e.message });
  }
});

// в”Җв”Җ POST /api/mtr/:id/receber в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.post('/api/mtr/:id/receber', authenticateToken, async (req, res) => {
  const { pesoReal, dataRecebimento, observacao } = req.body;
  db.get('SELECT * FROM mtr_local WHERE id = ?', [req.params.id], async (err, row) => {
    if (err || !row) return res.status(404).json({ mensagem: 'MTR nГЈo encontrada' });
    try {
      const payload = [{
        numeroManifesto: row.numero_mtr,
        pesoRealRecebido: parseFloat(pesoReal),
        dataRecebimento,
        observacao: observacao || ''
      }];
      const data = await sigorReq('/receberManifestoLote', 'POST', payload);
      if (data.erro) return res.status(400).json({ mensagem: data.mensagem });
      db.run('UPDATE mtr_local SET status = ?, data_recebimento = ?, peso_real = ? WHERE id = ?',
        ['Recebido', dataRecebimento, pesoReal, req.params.id]);
      res.json({ mensagem: 'MTR recebida com sucesso' });
    } catch (e) {
      res.status(500).json({ mensagem: e.message });
    }
  });
});

// в”Җв”Җ POST /api/mtr/:id/cancelar в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
app.post('/api/mtr/:id/cancelar', authenticateToken, async (req, res) => {
  const { justificativa } = req.body;
  if (!justificativa) return res.status(400).json({ mensagem: 'Justificativa obrigatГіria' });
  db.get('SELECT * FROM mtr_local WHERE id = ?', [req.params.id], async (err, row) => {
    if (err || !row) return res.status(404).json({ mensagem: 'MTR nГЈo encontrada' });
    // Modo forГ§ado local: cancela sГі no banco sem chamar SIGOR
    if (req.query.forceLocal === '1') {
      db.run('UPDATE mtr_local SET status = ? WHERE id = ?', ['Cancelado', row.id], (e) => {
        if (e) return res.status(500).json({ mensagem: e.message });
        res.json({ mensagem: 'MTR cancelada localmente (pendente de cancelamento no SIGOR)' });
      });
      return;
    }
    try {
      // API 12 - Cancelar Manifesto (Manual SIGOR v1.15)
      // Endpoint: POST /cancelarManifesto
      // Payload: objeto simples (NГғO array) com manNumero (string) e justificativa
      const payload = {
        manNumero: String(row.numero_mtr),
        justificativa: justificativa
      };
      console.log('[MTR CANCEL] Payload correto (API 12):', JSON.stringify(payload));
      const data = await sigorReq('/cancelarManifesto', 'POST', payload);
      console.log('[MTR CANCEL] Resposta SIGOR:', JSON.stringify(data));

      // Sucesso: data.erro === false e data.mensagem contГ©m "sucesso"
      if (data.erro === false || (data.mensagem && data.mensagem.toLowerCase().includes('sucesso'))) {
        db.run('UPDATE mtr_local SET status = ? WHERE id = ?', ['Cancelado', row.id]);
        return res.json({ mensagem: 'MTR cancelada com sucesso' });
      }

      // Erro do SIGOR
      const msgFinal = data.mensagem || 'Erro ao cancelar no SIGOR';
      console.error('[MTR CANCEL] SIGOR rejeitou:', msgFinal);
      return res.status(400).json({ mensagem: msgFinal });
    } catch (e) {
      console.error('[MTR CANCEL] Excecao:', e.message);
      res.status(500).json({ mensagem: e.message });
    }

  });
});



