// в”Җв”Җ CRON JOB MTR (A CADA 1 HORA) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
setInterval(async () => {
    console.log('[CRON-MTR] Iniciando sincronizaГ§ГЈo automГЎtica de MTRs...');
    db.all('SELECT * FROM mtr_local WHERE status NOT IN ("Cancelado", "Recebido")', [], async (err, rows) => {
        if (err || !rows) return;
        let atualizados = 0;
        for (const row of rows) {
            if (!row.numero_mtr) continue;
            try {
                const data = await sigorReq('/retornaManifesto/' + row.numero_mtr);
                if (data && data.objetoResposta && data.objetoResposta.situacaoManifesto) {
                    let sit = data.objetoResposta.situacaoManifesto.simDescricao;
           if (sit) {
               sit = sit.charAt(0).toUpperCase() + sit.slice(1).toLowerCase();
               // Manter o status exatamente como o SIGOR retorna
           }
                    if (sit && sit !== row.status) {
                        db.run('UPDATE mtr_local SET status = ? WHERE id = ?', [sit, row.id]);
                        atualizados++;
                    }
                }
            } catch(e) {}
        }
        if (atualizados > 0) {
            console.log(`[CRON-MTR] SincronizaГ§ГЈo automГЎtica concluiu com ${atualizados} atualizaГ§Гөes.`);
        }
    });
}, 60 * 60 * 1000);

