app.post('/api/comercial/rateio-custo', authenticateToken, (req, res) => {
  const items = Array.isArray(req.body) ? req.body : [req.body];
  const agora = new Date(new Date().getTime() - 3*60*60*1000).toISOString().replace('T',' ').substring(0,19);

  db.serialize(() => {
    let errorOccurred = null;
    const stmt = db.prepare(`
      REPLACE INTO comercial_rateio_custo (
        periodo, centro_custo, tipo, horas_periodo, valor_total, valor_hora, created_at, updated_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `);

    for (const item of items) {
      stmt.run(
        [item.periodo, item.centro_custo, item.tipo, item.horas_periodo || 0, item.valor_total || 0, item.valor_hora || 0, agora, agora],
        (err) => {
          if (err) errorOccurred = err;
        }
      );
    }

    stmt.finalize((err) => {
      if (err || errorOccurred) {
        return res.status(500).json({ error: err ? err.message : errorOccurred.message });
      }
      res.json({ success: true });
    });
  });
});


app.post('/api/comercial/itens-custo/importar', authenticateToken, multer({ storage: multer.memoryStorage(), limits: { fileSize: 20 * 1024 * 1024 } }).single('arquivo'), async (req, res) => {
  const { tipo } = req.body;
  if (!req.file) {
    return res.status(400).json({ error: "Nenhum arquivo enviado." });
  }

  // Helper function to dynamically classify category, nature and unit based on description
  const sugerirClassificacao = (desc) => {
    const descLower = (desc || '').toLowerCase();
    
    // 1. Categoria
    let categoria = 'MDO';
    if (descLower.includes('Гіleo') || descLower.includes('oleo') || descLower.includes('material') || descLower.includes('peГ§a') || descLower.includes('peca') || descLower.includes('insumo') || descLower.includes('graxa') || descLower.includes('filtro') || descLower.includes('combustivel') || descLower.includes('combustГӯvel') || descLower.includes('produto') || descLower.includes('lubrificante') || descLower.includes('gasolina') || descLower.includes('diesel') || descLower.includes('etanol') || descLower.includes('conserto') || descLower.includes('reparo') || descLower.includes('manutencao') || descLower.includes('manutenГ§ГЈo') || descLower.includes('equipamento') || descLower.includes('ferramenta') || descLower.includes('mГЎquina') || descLower.includes('maquina')) {
      categoria = 'Insumo';
    } else if (descLower.includes('frete') || descLower.includes('entrega') || descLower.includes('transporte') || descLower.includes('carreto') || descLower.includes('logistica') || descLower.includes('logГӯstica') || descLower.includes('pedagio') || descLower.includes('pedГЎgio')) {
      categoria = 'Frete';
    } else if (descLower.includes('imposto') || descLower.includes('taxa') || descLower.includes('aliquota') || descLower.includes('alГӯquota') || descLower.includes('iss') || descLower.includes('icms') || descLower.includes('darf') || descLower.includes('tributo') || descLower.includes('contribuiГ§ГЈo') || descLower.includes('contribuicao')) {
      categoria = 'Imposto';
    }

    // 2. Natureza
    let natureza = 'Fixo';
    const termosVariaveis = [
      'combustivel', 'combustГӯvel', 'gasolina', 'diesel', 'etanol', 'lubrificante',
      'frete', 'entrega', 'carreto', 'pedagio', 'pedГЎgio', 'viagem', 'hospedagem',
      'alimentacao', 'alimentaГ§ГЈo', 'refeicao', 'refeiГ§ГЈo', 'km', 'quilometragem',
      'manutencao', 'manutenГ§ГЈo', 'reparo', 'conserto', 'peГ§a', 'peca', 'Гіleo', 'oleo',
      'graxa', 'filtro', 'material', 'insumo', 'consumo', 'avulso', 'extra'
    ];
    const eVariavel = termosVariaveis.some(t => descLower.includes(t));
    if (eVariavel) {
      natureza = 'VariГЎvel';
    }

    // 3. Unidade de Medida
    let unidade = 'UN';
    if (descLower.includes('design') || descLower.includes('consultoria') || descLower.includes('desenvolvimento') || descLower.includes('projeto') || descLower.includes('mГЈo de obra') || descLower.includes('mao de obra') || descLower.includes('serviГ§o') || descLower.includes('servico') || descLower.includes('tГ©cnico') || descLower.includes('tecnico') || descLower.includes('analista') || descLower.includes('programador') || descLower.includes('suporte') || descLower.includes('consultor') || descLower.includes('assessoria') || descLower.includes('treinamento') || descLower.includes('instrutor') || descLower.includes('palestra') || descLower.includes('aula') || descLower.includes('coordenaГ§ГЈo') || descLower.includes('coordenacao') || descLower.includes('gerente') || descLower.includes('gerenciamento') || descLower.includes('hora') || descLower.includes('horas') || descLower.includes('hr')) {
      unidade = 'H';
    } else if (descLower.includes('quilometragem') || descLower.includes('km') || descLower.includes('distГўncia') || descLower.includes('distancia') || descLower.includes('rodado') || descLower.includes('deslocamento')) {
      unidade = 'KM';
    } else if (descLower.includes('combustГӯvel') || descLower.includes('combustivel') || descLower.includes('diesel') || descLower.includes('gasolina') || descLower.includes('etanol') || descLower.includes('lubrificante') || descLower.includes('Гіleo') || descLower.includes('oleo') || descLower.includes('litro') || descLower.includes('litros') || descLower.includes('agua') || descLower.includes('ГЎgua')) {
      unidade = 'L';
    } else if (descLower.includes('kg') || descLower.includes('kilo') || descLower.includes('quilo') || descLower.includes('peso') || descLower.includes('grama') || descLower.includes('gramas')) {
      unidade = 'KG';
    }

    return { categoria, natureza, unidade };
  };

  try {
    let itens = [];

    if (tipo === 'Planilha MDO') {
      const xlsx = require('xlsx');
      const workbook = xlsx.read(req.file.buffer, { type: 'buffer' });
      const sheetName = workbook.SheetNames[0];
      const sheet = workbook.Sheets[sheetName];
      const data = xlsx.utils.sheet_to_json(sheet);

      if (!data || data.length === 0) {
        return res.status(400).json({ error: "A planilha estГЎ vazia ou corrompida." });
      }

      for (const row of data) {
        const keys = Object.keys(row);
        const descKey = keys.find(k => k.toLowerCase().includes('desc') || k.toLowerCase().includes('item') || k.toLowerCase().includes('nome') || k.toLowerCase().includes('serviГ§o') || k.toLowerCase().includes('servico'));
        const valKey = keys.find(k => k.toLowerCase().includes('val') || k.toLowerCase().includes('cust') || k.toLowerCase().includes('preГ§o') || k.toLowerCase().includes('preco'));

        if (descKey && valKey) {
          const desc = String(row[descKey] || '').trim();
          const val = parseFloat(String(row[valKey]).replace(/[^\d,.-]/g, '').replace(',', '.'));
          if (desc && !isNaN(val)) {
            const classif = sugerirClassificacao(desc);
            itens.push({
              descricao: desc,
              valor: val,
              natureza: classif.natureza,
              categoria: classif.categoria,
              unidade: classif.unidade
            });
          }
        }
      }

      if (itens.length === 0) {
        return res.status(400).json({ error: "Colunas nГЈo encontradas ou nenhum item vГЎlido. O arquivo de Planilha MDO deve possuir colunas contendo as palavras 'DescriГ§ГЈo' e 'Valor'." });
      }

    } else if (tipo === 'PDF Fatura') {
      const fs = require('fs');
      try {
        fs.writeFileSync('backend/last_uploaded_fatura.pdf', req.file.buffer);
      } catch (err) {
        console.error('[DEBUG-SAVE-PDF-ERROR]', err);
      }

      const { PDFParse } = require('pdf-parse');
      const parser = new PDFParse({ verbosity: 0, data: req.file.buffer });
      const pdfData = await parser.getText();
      const text = pdfData.text || '';

      if (!text || text.trim().length === 0) {
        return res.status(400).json({ error: "O PDF nГЈo possui texto legГӯvel por OCR." });
      }

      const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);
      console.log(`[COMERCIAL] Importando PDF: ${lines.length} linhas de texto extraГӯdas.`);
      // accepts dots or commas as decimal separators
      const lineValRegex = /(?:r\$\s*)?([\d.]+[.,]\d{2})\b/i;

      lines.forEach((line) => {
        const lineLower = line.toLowerCase();
        
        // Skip obvious document total/tax/header lines in line-by-line item extraction
        if (lineLower.includes('valor total') || lineLower.includes('total a pagar') || lineLower.includes('total geral') || lineLower.includes('total da fatura') || lineLower.includes('total liquido') || lineLower.includes('total lГӯquido') || lineLower.includes('cnpj') || lineLower.includes('inscricao') || lineLower.includes('inscriГ§ГЈo') || lineLower.includes('sub-total') || lineLower.includes('subtotal') || lineLower.includes('imposto')) {
          return;
        }

        const match = line.match(lineValRegex);
        if (match) {
          let rawVal = match[1];
          let cleanVal = rawVal;
          if (cleanVal.includes('.') && cleanVal.includes(',')) {
            cleanVal = cleanVal.replace(/\./g, '').replace(',', '.');
          } else if (cleanVal.includes(',')) {
            cleanVal = cleanVal.replace(',', '.');
          } else if (cleanVal.includes('.')) {
            const parts = cleanVal.split('.');
            if (parts.length === 2 && parts[1].length === 2) {
              // decimal separator
            } else {
              // thousands separator
              cleanVal = cleanVal.replace(/\./g, '');
            }
          }
          const parsedVal = parseFloat(cleanVal);
          
          if (!isNaN(parsedVal) && parsedVal > 0) {
            // Get everything before the matched value to keep the description clean and exclude Qty/Total after it
            let desc = line.split(match[0])[0].trim();
            // clean up common punctuation and space separators at start/end
            desc = desc.replace(/^[\s\-.:;=]+/g, '').replace(/[\s\-.:;=]+$/g, '').trim();
            
            // Skip total label lines
            const descClean = desc.replace(/:/g, '').trim().toLowerCase();
            if (descClean === 'total' || descClean === 'subtotal' || descClean === 'sub-total' || descClean.startsWith('total ') || descClean === 'total geral' || descClean === 'total a pagar') {
              return;
            }

            // Only keep if it looks like a real description (minimum 3 alphabetical letters)
            const letterCount = (desc.match(/[a-zA-Z\u00C0-\u00FF]/g) || []).length;
            if (letterCount >= 3 && desc.length < 150) {
              const classif = sugerirClassificacao(desc);
              itens.push({
                descricao: desc,
                valor: parsedVal,
                natureza: classif.natureza,
                categoria: classif.categoria,
                unidade: classif.unidade
              });
            }
          }
        }
      });

      // Fallback: If line-by-line items extraction yielded nothing, fall back to extracting overall details
      if (itens.length === 0) {
        let singleDesc = "";
        let singleVal = 0.00;

        // Extract value
        const valRegex = /(?:r\$\s*)?([\d.]+[.,]\d{2})\b/gi;
        let valCandidates = [];
        lines.forEach((line, idx) => {
          const lineLower = line.toLowerCase();
          let match;
          valRegex.lastIndex = 0;
          while ((match = valRegex.exec(line)) !== null) {
            let rawVal = match[1];
            if (rawVal.includes('.') && rawVal.includes(',')) {
              rawVal = rawVal.replace(/\./g, '').replace(',', '.');
            } else if (rawVal.includes(',')) {
              rawVal = rawVal.replace(',', '.');
            } else if (rawVal.includes('.')) {
              const parts = rawVal.split('.');
              if (parts.length === 2 && parts[1].length === 2) {
                // decimal
              } else {
                rawVal = rawVal.replace(/\./g, '');
              }
            }
            const parsed = parseFloat(rawVal);
            if (!isNaN(parsed) && parsed > 0) {
              let score = 0;
              if (line.includes('R$')) score += 50;
              if (lineLower.includes('total') || lineLower.includes('lГӯquido') || lineLower.includes('liquido') || lineLower.includes('pagar') || lineLower.includes('fatura') || lineLower.includes('soma') || lineLower.includes('vlr')) {
                score += 100;
              }
              valCandidates.push({ value: parsed, score });
            }
          }
        });
        if (valCandidates.length > 0) {
          valCandidates.sort((a, b) => b.score - a.score);
          singleVal = valCandidates[0].value;
        }

        // Extract description
        let descCandidates = [];
        lines.forEach((line, idx) => {
          const lineLower = line.toLowerCase();
          if (lineLower.includes('descriГ§ГЈo') || lineLower.includes('descricao') || lineLower.includes('serviГ§o') || lineLower.includes('servico') || lineLower.includes('referente a')) {
            const colonIdx = line.indexOf(':');
            if (colonIdx !== -1 && colonIdx < line.length - 1) {
              const afterColon = line.substring(colonIdx + 1).trim();
              if (afterColon.replace(/[_\-*#]/g, '').trim().length > 3) {
                descCandidates.push({ text: afterColon.replace(/[_\-*#]/g, '').trim(), score: 80 });
              }
            }
            if (idx < lines.length - 1) {
              const nextLine = lines[idx+1].trim().replace(/[_\-*#]/g, '').trim();
              if (nextLine.length > 5 && !nextLine.toLowerCase().includes('valor') && !nextLine.toLowerCase().includes('total') && !nextLine.toLowerCase().includes('preГ§o') && !nextLine.toLowerCase().includes('r$')) {
                descCandidates.push({ text: nextLine, score: 100 });
              }
            }
          }
        });

        if (descCandidates.length > 0) {
          descCandidates.sort((a, b) => b.score - a.score);
          singleDesc = descCandidates[0].text;
        }

        if (!singleDesc) {
          const keywords = ['internet', 'telefone', 'telefonia', 'energia', 'luz', 'ГЎgua', 'agua', 'aluguel', 'locaГ§ГЈo', 'locacao', 'frete', 'transporte', 'combustГӯvel', 'combustivel', 'mГЈo de obra', 'salГЎrio', 'manutenГ§ГЈo', 'seguro'];
          for (const line of lines) {
            const matchesKeyword = keywords.some(kw => line.toLowerCase().includes(kw));
            if (matchesKeyword && line.length > 5 && line.length < 120 && !line.includes('R$')) {
              singleDesc = line.trim();
              break;
            }
          }
        }

        if (!singleDesc) {
          const filteredLines = lines.filter(l => l.length > 10 && l.length < 100 && !l.includes('R$') && !l.includes('$') && !l.toLowerCase().includes('cnpj'));
          singleDesc = filteredLines.length > 0 ? filteredLines[0] : "Fatura Importada (PDF)";
        }

        const classif = sugerirClassificacao(singleDesc);
        itens.push({
          descricao: singleDesc,
          valor: singleVal,
          natureza: classif.natureza,
          categoria: classif.categoria,
          unidade: classif.unidade
        });
      }

    } else if (tipo === 'Nota XML') {
      const xmlText = req.file.buffer.toString('utf8');
      
      const prodRegex = /<prod>([\s\S]*?)<\/prod>/g;
      let match;
      while ((match = prodRegex.exec(xmlText)) !== null) {
        const prodBlock = match[1];
        const xProdMatch = prodBlock.match(/<xProd>([^<]+)<\/xProd>/);
        const vUnComMatch = prodBlock.match(/<vUnCom>([^<]+)<\/vUnCom>/) || prodBlock.match(/<vProd>([^<]+)<\/vProd>/);

        if (xProdMatch && vUnComMatch) {
          const desc = xProdMatch[1].trim();
          const val = parseFloat(vUnComMatch[1]);
          if (desc && !isNaN(val)) {
            const classif = sugerirClassificacao(desc);
            itens.push({
              descricao: desc,
              valor: val,
              natureza: classif.natureza,
              categoria: classif.categoria,
              unidade: classif.unidade
            });
          }
        }
      }

      if (itens.length === 0) {
        const vNFMatch = xmlText.match(/<vNF>([^<]+)<\/vNF>/);
        const xProdMatch = xmlText.match(/<xProd>([^<]+)<\/xProd>/);
        const vUnComMatch = xmlText.match(/<vUnCom>([^<]+)<\/vUnCom>/);
        
        let val = 0.00;
        if (vUnComMatch) {
          val = parseFloat(vUnComMatch[1]);
        } else if (vNFMatch) {
          val = parseFloat(vNFMatch[1]);
        }
        
        let desc = "Nota XML Importada";
        if (xProdMatch) {
          desc = xProdMatch[1].trim();
        }

        if (desc && !isNaN(val)) {
          const classif = sugerirClassificacao(desc);
          itens.push({
            descricao: desc,
            valor: val,
            natureza: classif.natureza,
            categoria: classif.categoria,
            unidade: classif.unidade
          });
        }
      }

      if (itens.length === 0) {
        return res.status(400).json({ error: "NГЈo foi possГӯvel extrair itens do XML da NFe." });
      }

    } else {
      return res.status(400).json({ error: "Modo de importaГ§ГЈo de arquivo invГЎlido." });
    }

    res.json({ success: true, itens });

  } catch (err) {
    console.error("[IMPORT-ERROR] Falha geral no parser:", err);
    res.status(500).json({ error: "Erro de processamento no servidor: " + err.message });
  }
});

